// 驾考科目一 2026新规题库 Part 4 (501-825题)
var Q = Q || [];
Q.push(
// ═══════════════════════════════════════════════════════════════
// 一、记分管理 (points) — 80题 (501-580)
// ═══════════════════════════════════════════════════════════════
{id:501,cat:"points",type:"choice",q:"驾驶人在一个记分周期内累积记分达到12分的，由公安机关交通管理部门扣留其机动车驾驶证，并应参加多少天的道路交通安全法律法规学习？",opts:["3天","5天","7天","10天"],ans:2,exp:"记满12分后，驾驶证被扣留，驾驶人须参加为期7天的道路交通安全法律法规和相关知识学习（满分教育），学习结束后参加科目一考试，合格后方可领回驾驶证。",tip:"口诀：12分满→扣证→学7天→考科目一。七天上路再教育。"},
{id:502,cat:"points",type:"choice",q:"饮酒后驾驶机动车（血液酒精含量≥20mg/100ml且＜80mg/100ml）的一次记多少分？",opts:["6分","9分","12分","吊销驾照"],ans:2,exp:"饮酒驾车一次记12分，暂扣驾驶证6个月，罚款1000-2000元。醉酒驾车（≥80mg/100ml）则构成危险驾驶罪，追究刑事责任并吊销驾照，5年内不得重新取得。",tip:"口诀：喝酒开车12分全扣+扣证6个月。20mg以上就违法，80mg以上就是犯罪。"},
{id:503,cat:"points",type:"judgment",q:"造成致人轻伤以上或者死亡的交通事故后逃逸，尚不构成犯罪的，一次记12分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"造成人员伤亡后逃逸（尚不构成犯罪）一次记12分。若构成交通肇事罪，将追究刑事责任并吊销驾驶证，终身不得重新取得。逃逸是加重情节，罪加一等。",tip:"口诀：伤了人还跑=12分+可能坐牢。出了事故先救人，逃逸罪加一等。"},
{id:504,cat:"points",type:"choice",q:"在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记多少分？",opts:["6分","9分","12分","吊销驾照"],ans:2,exp:"高速公路倒车、逆行、穿越中央分隔带掉头属于极度危险行为，一次记12分。错过出口应继续行驶至下一出口，多绕几公里好过满分清零。",tip:"口诀：高速倒车/逆行/掉头=12分全扣。错过出口继续走，分数和命都保住。"},
{id:505,cat:"points",type:"choice",q:"使用伪造、变造的机动车号牌、行驶证、驾驶证或使用其他机动车号牌的，一次记多少分？",opts:["6分","9分","12分","吊销驾照"],ans:2,exp:"使用伪造、变造牌证或使用其他车辆号牌的，一次记12分，由公安机关收缴伪造牌证，扣留机动车，处15日以下拘留和2000-5000元罚款。与遮挡真牌（9分）有本质区别。",tip:"口诀：假牌假证12分+拘留+罚款。造假=12分，遮真=9分。真假处罚大不同。"},
{id:506,cat:"points",type:"judgment",q:"代替实际机动车驾驶人接受交通违法行为处罚和记分牟取经济利益的（买分卖分），一次记12分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2022年新规明确打击买分卖分行为，代替实际驾驶人接受处罚和记分牟取经济利益的，一次记12分，违法所得予以没收，并处违法所得三倍以下罚款（最高不超过5万元），双方均处罚。",tip:"口诀：买分卖分=12分+没收违法所得+罚款。代扣分赚钱=自毁驾照+信用污点。"},
{id:507,cat:"points",type:"choice",q:"饮酒后驾驶营运机动车的一次记多少分？",opts:["6分","9分","12分","吊销驾照且5年内不得重新取得"],ans:3,exp:"饮酒后驾驶营运机动车=吊销驾照+5年内不得重新取得+罚款5000元+拘留15日。醉酒驾驶营运机动车=吊销驾照+终身不得重新取得营运驾照+追究刑事责任。营运车驾驶人酒驾处罚更重。",tip:"口诀：营运车+酒驾=吊销+5年禁考。职业司机喝酒开车=直接断送职业生涯。"},
{id:508,cat:"points",type:"choice",q:"驾驶机动车超过规定时速50%以上的，一次记多少分？",opts:["6分","9分","12分","吊销驾照"],ans:2,exp:"超速50%以上一次记12分（普通机动车在高速和普通公路均适用）。超速20%-50%的，在高速公路记6分，在普通公路记3分。50%是一道红线。",tip:"口诀：超速50%以上=12分全扣。50%是生死红线，一过满分就清零。"},
{id:509,cat:"points",type:"judgment",q:"驾驶与准驾车型不符的机动车的一次记12分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"2022年新规将准驾不符由12分降为9分。例如C1驾照驾驶摩托车属于准驾不符，记9分而非12分。这是2022年调整力度较大的变化之一，2026年考试高频考点。",tip:"口诀：准驾不符记9分（不是12分！2022年已降）。C1开摩托=9分，别记错了。"},
{id:510,cat:"points",type:"choice",q:"驾驶未悬挂机动车号牌或故意遮挡、污损机动车号牌的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:2,exp:"未悬挂号牌或故意遮挡、污损号牌一次记9分（2022年由12分降为9分）。注意区分：使用伪造号牌仍记12分——真牌遮了=9分，假牌伪造=12分。",tip:"口诀：真牌遮了记9分，假牌伪造12分。遮真≠造假，处罚力度差3分。"},
{id:511,cat:"points",type:"judgment",q:"驾驶机动车在高速公路或城市快速路上违法停车的一次记9分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速或城市快速路违法停车一次记9分（2022年由6分提升为9分）。应急车道是生命通道，非紧急情况严禁占用。紧急情况指车辆故障、人员突发疾病等。",tip:"口诀：高速快速路违停记9分（加重了！）。应急车道=救命道，不是休息区。"},
{id:512,cat:"points",type:"choice",q:"驾驶机动车在高速公路或城市快速路上违法占用应急车道行驶的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:2,exp:"占用应急车道行驶一次记9分（2026新规加重处罚由6分提升为9分）。应急车道仅供警车、消防车、救护车、工程救险车等执行紧急任务时通行及故障车辆临时停靠。",tip:"口诀：占应急车道=9分。生命通道不可占，占了9分就没了。"},
{id:513,cat:"points",type:"choice",q:"驾驶机动车在高速公路、城市快速路上行驶时，驾驶人未按规定系安全带的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:0,exp:"2022年新规：驾驶人未系安全带在高速公路和城市快速路上记1分（此前部分地区记2分）。普通道路上同样记1分。乘车人未系安全带处警告或5-50元罚款。",tip:"口诀：不系安全带=1分。高速普通路都一样，1分虽少但命重要。"},
{id:514,cat:"points",type:"judgment",q:"驾驶机动车遇前方停车排队或缓慢行驶时，借道超车或占用对面车道穿插等候的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"加塞插队一次记3分（不是6分）。2022年新规将此项由2分提高到3分。在拥堵时强行穿插不仅危险，还严重影响通行秩序。",tip:"口诀：加塞插队记3分（不是6分！）。堵车就排队，插进去也快不到哪去。"},
{id:515,cat:"points",type:"choice",q:"驾驶机动车不按交通信号灯指示通行的（闯红灯），一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"闯红灯一次记6分。2022年新规维持6分不变。闯红灯是导致交叉路口交通事故的主要原因之一，处罚力度仅次于严重违法（12分）和较严重违法（9分）。",tip:"口诀：闯红灯=6分。红灯停绿灯行，抢灯6分加危险。"},
{id:516,cat:"points",type:"choice",q:"驾驶机动车在高速公路上行驶超过规定时速20%以上未达到50%的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"高速超速20%-50%一次记6分；超速50%以上记12分；超速未达20%不记分（处警告或罚款）。普通公路超速20%-50%记3分。高速公路处罚更重。",tip:"口诀：高速超20%-50%=6分，50%以上=12分。普通路超20%-50%=3分。高速严一倍。"},
{id:517,cat:"points",type:"judgment",q:"驾驶机动车在普通道路上行驶超过规定时速20%以上未达到50%的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"普通路超速20%-50%一次记3分（不是6分）。高速路超速20%-50%才是记6分。两者的处罚标准不同。普通路超速50%以上同样记12分。",tip:"口诀：普通路超20%-50%=3分（不是6分！）。高速同样区间才是6分。高速比普通重一倍。"},
{id:518,cat:"points",type:"choice",q:"驾驶机动车在道路上行驶时，驾驶人未按规定系安全带的，一次记多少分？",opts:["1分","2分","3分","6分"],ans:0,exp:"驾驶人未系安全带一次记1分（含所有道路）。乘车人未系安全带处警告或罚款但不记分。安全带是保命带，无论前排后排都应全程系好。",tip:"口诀：不系安全带=1分。扣分事小，安全事大。全员全程系好安全带。"},
{id:519,cat:"points",type:"judgment",q:"驾驶摩托车时驾驶人未按规定戴安全头盔的，一次记1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"摩托车驾驶人未戴安全头盔一次记1分（2022年由2分降为1分）。乘坐摩托车不戴头盔的处警告或罚款。头盔是摩托车骑手的最后一道防线，可降低75%的头部重伤风险。",tip:"口诀：骑摩托不戴头盔=1分+罚款。头比发型重要，头盔=保命盔。"},
{id:520,cat:"points",type:"choice",q:"驾驶机动车在普通道路上拨打接听手持电话的一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"普通路开车打电话一次记3分（2022年由2分提高到3分）。在高速公路、城市快速路上开车打电话的一次记9分（2026新规加重）。双手握方向盘不是手机！",tip:"口诀：普通路打电话=3分，高速快速路打电话=9分。开车看手机=玩命。"},
{id:521,cat:"points",type:"choice",q:"驾驶机动车在高速公路、城市快速路上拨打接听手持电话的一次记多少分？",opts:["3分","6分","9分","12分"],ans:2,exp:"高速或快速路开车打电话一次记9分（2026新规加重处罚，由3分大幅提高到9分）。高速车速快，分心一秒盲开几十米，极其危险。",tip:"口诀：高速打电话=9分！快速路也一样。高速上一低头看手机=盲开几十米。"},
{id:522,cat:"points",type:"judgment",q:"驾驶机动车行经人行横道不按规定减速、停车、避让行人的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"不礼让行人一次记3分（2022年由3分维持不变）。行经人行横道应减速行驶，遇行人正在通过应停车让行。「礼让斑马线」既是法律规定也是文明素养。",tip:"口诀：斑马线不让人=3分。人过马路你让路，文明驾驶记心间。"},
{id:523,cat:"points",type:"choice",q:"驾驶机动车不按规定超车、让行或在普通道路上逆行的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"不按规定超车、让行或普通路逆行一次记3分。注意：高速逆行记12分、普通路逆行记3分，处罚差距极大。不按规定让行还包括转弯不让直行、支路不让干路等。",tip:"口诀：普通路逆行+违规超车让行=3分。高速逆行=12分。普逆3分，高逆12分。"},
{id:524,cat:"points",type:"judgment",q:"驾驶机动车在高速公路、城市快速路以外的道路上逆行的，一次记12分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"普通路逆行一次记3分（不是12分）。只有在高速公路、城市快速路上逆行才记12分。两者的危险性不同，处罚标准也不同。",tip:"口诀：普通路逆行=3分，高速逆行=12分。不要混淆！高速逆行是3分的4倍。"},
{id:525,cat:"points",type:"choice",q:"驾驶机动车在高速公路上行驶低于规定最低时速的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"高速低于最低限速（通常为60km/h）一次记3分。2022年新规新增了此项处罚。低速行驶影响通行效率并增加追尾风险——后车可能来不及反应慢车。",tip:"口诀：高速开太慢=3分。「龟速」占快车道也违法。最低60码，低于就扣分。"},
{id:526,cat:"points",type:"choice",q:"驾驶校车、中型以上载客载货汽车、危险物品运输车辆在高速公路、城市快速路以外的道路上行驶超过规定时速50%以上的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:2,exp:"上述特殊车辆在普通路超速50%以上一次记9分。在高速、快速路超速20%以上即记12分。特种车辆因风险更高，处罚标准更严格。",tip:"口诀：校车/客货车/危险品车普通路超50%=9分。特殊车更严，高速超20%就是12分。"},
{id:527,cat:"points",type:"judgment",q:"驾驶机动车载货长度、宽度、高度超过规定的，一次记1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"载货超长超宽超高一次记1分。超限货物不仅影响自身行驶稳定性，还可能刮擦其他车辆和道路设施。运载不可解体超限物品须经审批。",tip:"口诀：超长超宽超高=1分。货物超出车身就是安全隐患，别贪多。"},
{id:528,cat:"points",type:"choice",q:"驾驶擅自改变已登记的结构、构造或特征的载货汽车上道路行驶的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:0,exp:"非法改装载货汽车（如加高栏板、加长车身等）一次记1分。改变车辆结构影响安全性能（制动、稳定性），且属于不合法改装。",tip:"口诀：货车非法改装=1分。改车身结构之前先问问车管所同不同意。"},
{id:529,cat:"points",type:"choice",q:"驾驶未按规定定期进行安全技术检验（年检）的公路客运汽车、旅游客运汽车、危险物品运输车辆上道路行驶的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"上述三类重点车辆未年检一次记3分。其他机动车未年检记1分。年检是保障车辆安全性能的重要制度，重点车辆管理更严格。",tip:"口诀：客车/旅游车/危险品车未年检=3分；普通小车未年检=1分。重点车辆加倍。"},
{id:530,cat:"points",type:"judgment",q:"驾驶未按规定定期进行安全技术检验的普通小型客车上道路行驶的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"普通小型客车（私家车）未年检一次记1分（不是3分）。只有公路客运汽车、旅游客运汽车、危险物品运输车未年检才记3分。2022年新规将私家车未年检由3分降为1分。",tip:"口诀：私家车未年检=1分（2022年降的）。重点车才是3分。别把自己的车跟客车比。"},
{id:531,cat:"points",type:"choice",q:"驾驶机动车违反禁令标志、禁止标线指示的（如压实线变道），一次记多少分？",opts:["1分","2分","3分","6分"],ans:0,exp:"违反禁令标志、禁止标线一次记1分（2022年由3分降为1分）。包括压实线变道、闯禁行区域、违反禁止转弯标志等。但闯红灯仍独立记6分。",tip:"口诀：压线闯禁记1分（新规大降）。闯红灯仍是6分——闯红灯和压线处罚大不同。"},
{id:532,cat:"points",type:"judgment",q:"驾驶机动车不按规定使用灯光的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"不按规定使用灯光一次记1分（不是3分）。包括不按规定使用转向灯、远光灯、雾灯等。2022年新规将此项由1分维持不变。",tip:"口诀：乱用灯光=1分。该打灯不打、不该用远光偏用，都是1分。"},
{id:533,cat:"points",type:"choice",q:"驾驶机动车在道路上发生故障或事故后，不按规定使用灯光和设置警告标志的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"故障停车不设警告标志一次记3分（2022年由3分维持不变）。故障停车后应开启双闪（危险报警闪光灯），在来车方向规定距离设置警告标志——普通路50-100米，高速150米。",tip:"口诀：车坏了不设警示=3分。双闪+警示牌，两样缺一不可。"},
{id:534,cat:"points",type:"choice",q:"驾驶机动车不按规定会车，或在高速公路、城市快速路以外的道路上不按规定倒车、掉头的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:0,exp:"不按规定会车、倒车、掉头（普通路）一次记1分（2022年由1分维持不变）。包括窄路会车不让行、违规掉头、不按规定倒车等。高速公路上倒车掉头则是12分。",tip:"口诀：普通路违规会车倒车掉头=1分。高速同样行为=12分。差距12倍！"},
{id:535,cat:"points",type:"judgment",q:"2026年记分体系分为五个等级：12分、9分、6分、3分、1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2022年新规调整后，记分等级为五档：12分（最严重）、9分（新增档）、6分、3分、1分（取消2分档）。2分违法行为分别调整为1分或3分。2026年继续沿用此体系。",tip:"口诀：新记分五档：12-9-6-3-1。2分取消了！要么升3分，要么降1分。"},
{id:536,cat:"points",type:"choice",q:"2022年新规中，下列哪项违法行为由12分降为9分？",opts:["醉驾","使用伪造号牌","准驾不符","高速逆行"],ans:2,exp:"准驾不符（如C1开摩托车）由12分降为9分。此外，未悬挂/遮挡号牌也由12分降为9分。醉驾、伪造号牌、高速逆行维持12分不变。",tip:"口诀：准驾不符+遮号牌=12降到9（2022年）。醉驾/假牌/高速倒逆=12分雷打不动。"},
{id:537,cat:"points",type:"choice",q:"驾驶机动车在高速公路、城市快速路上行驶超过规定时速20%以上未达到50%的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"高速/快速路超速20%-50%一次记6分。高速超速未达20%不记分（警告或罚款）。注意与普通路超速同区间的3分相区别——高速处罚更严。",tip:"口诀：高速超20-50%=6分，普通超20-50%=3分。高速比普通严一倍。"},
{id:538,cat:"points",type:"judgment",q:"驾驶载货汽车载物超过最大允许总质量30%以上未达到50%的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"货车超载30%-50%一次记3分（不是6分）。超载未达30%记1分，超载50%以上记6分。货物超载严重影响制动性能和车辆稳定性。",tip:"口诀：货车超载三档：<30%=1分，30-50%=3分，>50%=6分。越超分越多。"},
{id:539,cat:"points",type:"choice",q:"驾驶载货汽车载物超过最大允许总质量50%以上的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"货车超载50%以上一次记6分。严重超载使制动距离大幅延长，转向稳定性下降，轮胎负荷过大易爆胎，是极其危险的违法行为。",tip:"口诀：货车超50%=6分。超载一半=刹车距离加倍，危险翻番。"},
{id:540,cat:"points",type:"judgment",q:"驾驶机动车在道路上行驶时，驾驶人未按规定使用安全带的，在高速公路和普通道路分别记1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"不系安全带在所有道路上统一记1分。2022年新规统一了高速公路和普通道路的处罚标准。安全不分道路等级，安全带是每一条路上的保命带。",tip:"口诀：不系安全带走哪都是1分。高速普通一个样，安全带不分场合。"},
{id:541,cat:"points",type:"choice",q:"驾驶机动车在高速公路上行驶，能见度低于规定标准时不按规定行驶的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"高速低能见度不按规定行驶一次记6分。包括：能见度<200米时未减速至60km/h、能见度<100米时未减速至40km/h、能见度<50米时未减速至20km/h并驶离高速等。",tip:"口诀：高速大雾不减速=6分。200-60，100-40，50-20-离。不遵守这个规则就扣6分。"},
{id:542,cat:"points",type:"judgment",q:"驾驶危险物品运输车辆在高速公路、城市快速路上行驶超过规定时速20%以上的，一次记12分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"危险品运输车在高速超速20%以上一次记12分——比普通机动车（超速50%以上记12分）更严格。危险品一旦发生事故后果极其严重，处罚标准因此更严。",tip:"口诀：危险品车高速超20%=12分。普通车要超50%才12分。危险品=严上加严。"},
{id:543,cat:"points",type:"choice",q:"驾驶危险物品运输车辆在高速公路、城市快速路以外的道路上行驶超过规定时速50%以上的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:2,exp:"危险品运输车在普通路超速50%以上一次记9分。在高速和快速路上，超速20%以上即记12分。危险品运输车限速标准低、处罚标准高，体现安全至上的管理理念。",tip:"口诀：危险品车普通路超50%=9分。危险品+超速=极高危险，所以记分也高。"},
{id:544,cat:"points",type:"judgment",q:"驾驶机动车运载超限的不可解体物品，未按指定时间、路线、速度行驶的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"运载超限物品未按审批要求行驶一次记6分。超限运输须取得通行证，严格按指定的时间、路线、速度行驶并悬挂明显标志。违反审批要求=6分。",tip:"口诀：超限运输不按审批走=6分。审批怎么规定就怎么走，私自变动=扣分。"},
{id:545,cat:"points",type:"choice",q:"机动车驾驶证被暂扣期间驾驶机动车的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"驾驶证被暂扣期间驾车一次记6分。属于「无有效驾驶证驾驶」的一种情形，除记分外还可处200-2000元罚款和15日以下拘留。",tip:"口诀：扣证期间开车=6分+可能拘留。证被扣了=暂时没资格开车。"},
{id:546,cat:"points",type:"choice",q:"驾驶机动车在道路上行驶时，连续驾驶中型以上载客汽车、危险物品运输车辆超过4小时未停车休息或停车休息时间少于20分钟的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:2,exp:"营运客车、危险品运输车疲劳驾驶一次记9分（2026新规加重，由6分提高至9分）。这些车辆一旦因疲劳驾驶发生事故，人员伤亡惨重。",tip:"口诀：客车/危险品车疲劳驾驶=9分。4小时必停20分钟，不停=9分。"},
{id:547,cat:"points",type:"judgment",q:"驾驶机动车在高速公路或城市快速路上，驾驶人未按规定使用安全带的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"不系安全带在所有道路上统一记1分（不是3分）。2022年新规将高速公路不系安全带由2分调整为1分，与普通道路统一标准。",tip:"口诀：不系安全带=1分，不分高速普通。1分虽小，命比1分重。"},
{id:548,cat:"points",type:"choice",q:"驾驶机动车载运爆炸物品、易燃易爆化学物品以及剧毒、放射性等危险物品，未按指定的时间、路线、速度行驶或未悬挂警示标志的，一次记多少分？",opts:["3分","6分","9分","12分"],ans:1,exp:"危险品运输未按规定行驶或未悬挂警示标志一次记6分。危险品运输有严格的路线和时间限制（通常避开人口密集区和高时段），违规即重罚。",tip:"口诀：危险品不按规定运=6分。危险品=高度管控，所有规定必须遵守。"},
{id:549,cat:"points",type:"judgment",q:"驾驶机动车在高速公路或城市快速路以外的道路上，不按规定使用灯光和设置警告标志的，一次记1分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"故障停车不按规定使用灯光和设置警告标志的，无论什么道路统一记3分（不是1分）。双闪和警示牌是故障停车的法定动作，缺一不可。",tip:"口诀：故障不设警示=3分（不分道路）。双闪+三角牌，全路统一3分。"},
{id:550,cat:"points",type:"choice",q:"驾驶机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件时，未按规定开启相应灯光的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"高速低能见度不按规定使用灯光一次记3分。应开启：雾灯、近光灯、示廓灯和前后位灯；能见度<100米时加开双闪。但绝对禁止使用远光灯（会被雾气反射形成白墙）。",tip:"口诀：高速大雾不开灯=3分。雾灯+近光+示廓+前后位灯，低到100米加双闪。"},
{id:551,cat:"points",type:"judgment",q:"未取得校车驾驶资格驾驶校车的，一次记12分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"未取得校车驾驶资格驾驶校车一次记9分（不是12分）。校车承载学生安全，驾驶人需取得专门的校车驾驶资格。无资格驾驶校车=严重违法但不至12分。",tip:"口诀：无校车资格开校车=9分。校车有门槛，没资格别碰。"},
{id:552,cat:"points",type:"choice",q:"以下哪种违法行为一次记9分？",opts:["闯红灯","不系安全带","高速或快速路违法停车","压实线变道"],ans:2,exp:"高速/快速路违法停车=9分。闯红灯=6分、不系安全带=1分、压实线变道=1分。9分档是2022年新增的中间档，介于6分和12分之间。",tip:"口诀：9分档=高速违停+遮号牌+准驾不符+疲劳驾驶（客车）。9分是个新档位，记住了。"},
{id:553,cat:"points",type:"choice",q:"驾驶机动车超过规定时速20%以上未达到50%的，在高速公路上记6分，在普通道路上记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"普通路超速20%-50%记3分，高速同样区间记6分。高速车速更快，事故后果更严重，因此处罚加倍。超速未达20%不记分。",tip:"口诀：同一超速区间——高速6分，普通3分。高速永远是普通的两倍处罚。"},
{id:554,cat:"points",type:"judgment",q:"驾驶机动车在道路上行驶时，驾驶人在一个记分周期内累积记分满12分的，公安机关扣留驾驶证，驾驶人可通过参加学法减分全部抵扣，无需参加满分学习。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"学法减分是在记分未满12分时使用的减免手段（最多减6分且每个周期内使用）。记满12分后必须参加7天满分学习并重考科目一，学法减分不能用于抵扣已满12分的状态。",tip:"口诀：学法减分≠免学。12分满了=必须学7天+重考。学法减分只用来「预防」满分，不能「治疗」满分。"},
{id:555,cat:"points",type:"choice",q:"驾驶机动车在道路上行驶时，以下哪种违法行为一次记1分？",opts:["醉酒驾车","闯红灯","不按规定使用灯光","高速路上倒车"],ans:2,exp:"不按规定使用灯光=1分。醉驾=12分/吊销、闯红灯=6分、高速倒车=12分。1分档是2022年新规保留的最轻档，包括不系安全带、不戴头盔、违规用灯等。",tip:"口诀：1分档=不系安全带+不戴头盔+乱用灯+违规会车倒车+违反禁令标志。1分起步，积少成多。"},
{id:556,cat:"points",type:"judgment",q:"驾驶摩托车在高速公路上行驶的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"摩托车在高速公路上行驶本身不违法（最高限速80km/h），法规并未规定「禁止摩托车上高速」。但部分地方性法规有禁止规定，需看具体路段标志。摩托车未戴头盔记1分。",tip:"口诀：摩托车上高速不完全违法——看地方规定和路段标志。国家法规未全国禁止。"},
{id:557,cat:"points",type:"choice",q:"驾驶人在实习期内驾驶机动车上高速公路行驶，无相应或更高准驾车型驾驶证三年以上驾驶人陪同的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:0,exp:"实习期单独上高速（无老司机陪同）一次记1分。不是不让上高速，是必须有持相应或更高准驾车型3年以上驾龄的驾驶人陪同。增驾实习期内驾驶原准驾车型不受此限。",tip:"口诀：实习期独自上高速=1分。找个老司机陪着就不扣分。3年驾龄=老司机门槛。"},
{id:558,cat:"points",type:"choice",q:"驾驶机动车运输危险化学品，未经批准进入危险化学品运输车辆限制通行区域的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:2,exp:"危险品车未经审批进入限制区域一次记6分。危险化学品运输有严格的通行区域管理，禁行区域通常包括城市中心区、水源保护区、人口密集区等。",tip:"口诀：危险品车闯禁区=6分。禁区不是你想进就能进，有审批才能走。"},
{id:559,cat:"points",type:"judgment",q:"记分周期为12个月，从机动车驾驶证初次领取之日起计算。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"记分周期=12个月=从初次领证日期起算（不是自然年1月1日至12月31日）。例如5月10日领证，每次记分周期为5月10日至次年5月9日。",tip:"口诀：记分周期=领证日开始算一年。不是元旦到年底！看你驾驶证上的初次领证日期。"},
{id:560,cat:"points",type:"choice",q:"一个记分周期内记分未达到12分且罚款已缴纳的，记分如何处理？",opts:["转入下一周期","予以清除","累计至24分后清除","需要申请才能清除"],ans:1,exp:"记分未满12分+罚款已交=记分清除（自动清零）。罚款未交=记分转入下一周期。所以交罚款是清零的前提——不是时间到了就自动清零。",tip:"口诀：分清零两条件：①分没满12 ②罚款交了。缺一不可，不交钱=分转下一年。"},
{id:561,cat:"points",type:"judgment",q:"学法减分一个记分周期内最多可以减免12分，每次网上学习30分钟并通过考试可减免1分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"学法减分最多减免6分（不是12分）。每次网上学习30分钟+20道题答对18题=减免1分。也可以通过参加交通安全公益活动减免，一周期累计最多6分。",tip:"口诀：学法减分上限6分（不是12分！）。网上学半小时+考试=减1分，最多减6次。"},
{id:562,cat:"points",type:"choice",q:"驾驶人在一个记分周期内两次以上达到12分或累积记分达到24分以上的，除参加科目一考试外还需参加什么？",opts:["科目二","科目三道路驾驶技能","科目三安全文明驾驶常识","以上全部"],ans:1,exp:"24分以上=科目一+科目三道路驾驶技能（路考）。记12分=只考科目一。记分越多，重考项目越多。24分意味着驾驶人存在严重违法习惯，需要通过路考重新评估驾驶能力。",tip:"口诀：12分=考科一；24分=考科一+科三路考。分越多，重考越多。"},
{id:563,cat:"points",type:"judgment",q:"AB类驾驶证（大型客车、牵引车等）在一个记分周期内记满12分的，除满分学习考试外驾驶证还将被降级。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"AB类驾驶证记满12分=降级（注销最高准驾车型）+满分学习+重考科目一。例如A1驾证记满12分，注销A1资格降为A2或B1等。这是对职业驾驶人的额外严厉措施。",tip:"口诀：AB证满12分=降级+学习+重考。职业司机的噩梦——满分=降级=饭碗不保。"},
{id:564,cat:"points",type:"choice",q:"以下哪种违法行为记6分？",opts:["醉驾","不戴头盔","闯红灯","高速倒车"],ans:2,exp:"闯红灯=6分。醉驾=12分/吊销、不戴头盔=1分、高速倒车=12分。6分档还包括：高速超速20%-50%、驾照被扣期间驾车、低能见度不按规定行驶等。",tip:"口诀：6分档=闯红灯+高速超20-50%+扣证期开车+低能见度违规。6分是中档，不上不下的关键档位。"},
{id:565,cat:"points",type:"judgment",q:"驾驶机动车造成致人轻微伤或财产损失的交通事故后逃逸，尚不构成犯罪的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"造成人员轻伤以上或死亡后逃逸=12分；造成轻微伤或财产损失后逃逸=6分。区分标准是后果的严重程度——有人轻伤以上或死亡=12分，仅轻微伤或财损=6分。",tip:"口诀：逃逸两档——伤人（轻伤以上/死亡）=12分，轻微伤/财物=6分。后果越重分越多。"},
{id:566,cat:"points",type:"choice",q:"驾驶校车、公路客运汽车、旅游客运汽车载人超过核定人数20%以上，或驾驶其他载客汽车载人超过核定人数100%以上的，一次记多少分？",opts:["6分","9分","12分","吊销驾照"],ans:2,exp:"营运客车超载20%以上=12分；普通载客汽车超载100%以上=12分。客车超载严重威胁乘客安全，制动性能大幅下降，一旦发生事故伤亡惨重。",tip:"口诀：客车超20%=12分；普通车超100%=12分。超载越多处罚越重，12分封顶。"},
{id:567,cat:"points",type:"choice",q:"驾驶载货汽车载物超过最大允许总质量未达到30%的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:0,exp:"货车超载<30%一次记1分；超载30%-50%记3分；超载50%以上记6分。三档递进式处罚，越超越重。",tip:"口诀：货车超载三步走：<30%=1分，30-50%=3分，>50%=6分。一档一档往上加。"},
{id:568,cat:"points",type:"judgment",q:"驾驶机动车在道路上行驶，连续驾驶超过4小时未停车休息或停车休息时间少于20分钟的，一次记3分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"普通机动车疲劳驾驶一次记3分；但中型以上载客汽车和危险品运输车疲劳驾驶一次记9分。处罚力度因车辆类型（风险大小）而异。",tip:"口诀：普通车疲劳驾驶=3分，客车/危险品车疲劳驾驶=9分。同样疲劳，大车三倍处罚。"},
{id:569,cat:"points",type:"choice",q:"驾驶机动车在道路上行驶，驾驶人在驾驶证超过有效期仍驾驶机动车的，一次记多少分？",opts:["不记分","1分","3分","6分"],ans:3,exp:"驾驶证超过有效期仍驾车=记6分。超过有效期不满1年的可正常换证（但期间驾车仍属违法）；超过1年不满3年的需重考科目一；超过3年的注销。",tip:"口诀：过期驾照开车=6分。过期1年内可换证但期间不能开，过期超1年要重考。"},
{id:570,cat:"points",type:"judgment",q:"机动车喷涂、粘贴标识或车身广告影响安全驾驶的，处警告或罚款但不记分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"车身喷涂粘贴影响安全驾驶的一次记1分（不是不记分）。包括遮挡视线的不当贴膜、大面积车身广告改变车身颜色而未备案等情形。",tip:"口诀：车身乱贴影响安全=1分。不是只罚款不记分，有1分记在你账上。"},
{id:571,cat:"points",type:"choice",q:"2026年新规中，对一个记分周期内多次记满12分的驾驶人，以下哪项措施是正确的？",opts:["只重考科目一即可","延长学习时间，增加考试科目，加强教育管理","自动吊销驾驶证","不采取额外措施"],ans:1,exp:"多次记满12分=延长满分教育时间+增加考试科目+加强教育管理。屡犯屡记满12分说明驾驶人安全意识严重不足，需要更强化教育和考试。",tip:"口诀：屡教不改就加课加考。一次12分学7天，多次12分学更长考更多。"},
{id:572,cat:"points",type:"judgment",q:"驾驶机动车在高速公路、城市快速路上倒车的一次记12分，在普通道路上违规倒车的一次记1分。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速/快速路倒车=12分（极度危险）；普通路违规倒车=1分（危险程度相对较低）。同一行为在不同道路的处罚相差12倍，体现高速公路的特殊安全要求。",tip:"口诀：高速倒车12分，普通倒车1分。十二倍差距，高速上千万别乱来。"},
{id:573,cat:"points",type:"choice",q:"驾驶人在驾驶证被依法扣留期间，采用隐瞒、欺骗手段补领驾驶证的，一次记多少分？",opts:["1分","3分","6分","12分"],ans:2,exp:"以欺骗手段补领驾驶证一次记6分。驾驶证被扣留后通过谎称丢失等方式补领新证，属于严重扰乱驾驶证管理秩序的行为。",tip:"口诀：扣证后骗补新证=6分。扣了就老老实实等着，别搞小聪明。"},
{id:574,cat:"points",type:"judgment",q:"2026年记分体系中，高速公路上打电话的记分标准与普通道路上打电话的记分标准相同。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速公路打电话=9分，普通路打电话=3分。两者处罚标准不同且差距很大——高速公路车速快，分心驾驶后果更严重，因此处罚是普通路的三倍。",tip:"口诀：高速电话9分，普通电话3分。同样是打电话，高速严三倍。"},
{id:575,cat:"points",type:"choice",q:"驾驶机动车在道路上行驶时，行经人行横道不按规定减速、停车、避让行人的，一次记多少分？",opts:["1分","3分","6分","9分"],ans:1,exp:"不礼让行人=3分。这是2022年新规维持不变的处罚标准。机动车行经人行横道应减速；行人正在通过时应停车让行。礼让行人是基本驾驶素养。",tip:"口诀：斑马线不让行人=3分。看见斑马线脚放刹车上，有人就停。"},
{id:576,cat:"points",type:"judgment",q:"驾驶校车、公路客运汽车、旅游客运汽车、7座以上载客汽车以外的其他载客汽车载人超过核定人数20%以上未达到50%的，一次记6分。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"普通载客汽车（非营运、7座以下）超载20%-50%一次记3分（不是6分）。超载50%-100%记6分。超载100%以上记12分。营运客车处罚更重。",tip:"口诀：普通小车超载20%-50%=3分。别跟客运大巴比，处罚标准不一样。"},
{id:577,cat:"points",type:"choice",q:"以下哪项违法行为一次记12分？",opts:["压实线变道","闯红灯","使用伪造驾驶证","不礼让行人"],ans:2,exp:"使用伪造驾驶证=12分。压实线变道=1分、闯红灯=6分、不礼让行人=3分。12分是最严重档，针对极度危险行为和严重违法。",tip:"口诀：12分=醉驾/假牌证/高速倒逆/肇事逃逸伤人/超速50%+/替人消分牟利。碰一条就满分。"},
{id:578,cat:"points",type:"judgment",q:"驾驶人在一个记分周期内累积记分未满12分，即使有罚款未缴纳，记分也会在周期结束后自动清除。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"罚款未缴纳=记分不清零而是转入下一周期。分清零必须同时满足两个条件：记分未满12分且罚款已全部缴纳。这是考试中容易出错的知识点。",tip:"口诀：分清零=没满12分+交了罚款。不交钱=分滚到下一年。交钱是清零前提！"},
{id:579,cat:"points",type:"choice",q:"下列哪项不是2022年新规新增或调整的记分项目？",opts:["高速低于最低限速记3分","买卖分记12分","准驾不符由12分降为9分","闯红灯由3分提高到6分"],ans:3,exp:"闯红灯早在2013年就已提高到6分，不是2022年新规才调整的。其他三项均为2022年新规的变化：新增低速行驶记分、打击买分卖分、准驾不符降为9分。",tip:"口诀：闯红灯=6分早就有了（2013年）。2022年新增=低速记分+买卖分+准驾不符降档。"},
{id:580,cat:"points",type:"judgment",q:"记分减免（学法减分）只能通过网上学习考试实现，不能通过参加交通安全公益活动实现。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"学法减分有两种途径：①网上学习考试（交管12123APP学习30分钟+20道题答对18题=减1分）；②参加交通安全公益活动（线下志愿服务等）。两种方式均可，一周期最多减免6分。",tip:"口诀：学法减分两条路——网上学习+线下公益。两条路都能走，总上限6分。"},
{id:581,cat:"laws",type:"choice",q:"机动车驾驶证的有效期分为哪几档？",opts:["4年、8年、12年","5年、10年、15年","6年、10年、长期","3年、6年、9年"],ans:2,exp:"初次申领驾驶证有效期为6年。6年内每个记分周期均未记满12分，换发10年有效期驾驶证；10年内每个记分周期均未记满12分，换发长期有效驾驶证。",tip:"口诀：6年→10年→长期。好好开车终身免换证。"},
{id:582,cat:"laws",type:"judgment",q:"申请小型汽车（C1）驾驶证的年龄条件为18周岁以上，无上限年龄限制（但70周岁以上需通过三力测试）。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"2022年新规取消了C1、C2驾驶证的70周岁年龄上限。70周岁以上申领需通过记忆力、判断力、反应力「三力测试」，且每年需提交身体条件证明。",tip:"口诀：C1/C2考证无年龄上限！70岁以上加考三力测试+每年体检。"},
{id:583,cat:"laws",type:"choice",q:"申请大型客车（A1）驾驶证的最低年龄是多少？",opts:["20周岁","22周岁","26周岁","28周岁"],ans:1,exp:"申请A1（大型客车）和A2（牵引车）驾驶证的最低年龄为22周岁。A3（城市公交车）和B2（大型货车）为20周岁。最高年龄限制统一为60周岁。",tip:"口诀：A1/A2=22岁起步，A3/B2=20岁起步。大客大货门槛高。"},
{id:584,cat:"laws",type:"choice",q:"机动车驾驶人身体条件证明的有效期是多久？",opts:["3个月","6个月","12个月","24个月"],ans:1,exp:"身体条件证明自出具之日起6个月内有效。申领驾驶证、换证、提交身体条件证明时，均应提交有效期内的身体条件证明。70周岁以上驾驶人每年提交一次。",tip:"口诀：体检证明有效期6个月。70岁以上每年交一次体检。"},
{id:585,cat:"laws",type:"judgment",q:"驾驶人在驾驶证超过有效期一年以上未换证的，驾驶证将被注销，需要重新考取全部科目。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"超期1年以上未满3年=驾驶证注销可恢复状态，只需重考科目一即可恢复。超期3年以上=注销，需重考全部科目。超期不满1年=可正常换证。",tip:"口诀：过期<1年=正常换；1-3年=考科一恢复；>3年=重新全考。三档递进。"},
{id:586,cat:"laws",type:"choice",q:"机动车驾驶人联系电话、联系地址等信息发生变化，应在多少日内向驾驶证核发地或核发地以外车辆管理所备案？",opts:["15日","30日","60日","90日"],ans:1,exp:"驾驶人信息变更（联系方式、地址等）应在30日内向车辆管理所备案。未按规定备案的，处警告或20-200元罚款。这关系到能否及时收到交通违法通知等重要信息。",tip:"口诀：联系方式变了30天内报备。搬家换号要及时通知车管所。"},
{id:587,cat:"laws",type:"choice",q:"机动车在道路上临时停车时，在设有禁停标志的路段，能否临时停车？",opts:["可以，只要不熄火","可以临时停车上下人","不得停车","夜间可以停车"],ans:2,exp:"设有禁停标志、标线的路段不得停车（包括临时停车）。临时停车仍属于「停车」范畴。禁停路段交警可以贴罚单。",tip:"口诀：禁停标志=一秒都不能停。临时停车也是停车，照罚不误。"},
{id:588,cat:"laws",type:"judgment",q:"机动车在道路上发生交通事故，仅造成轻微财产损失且基本事实清楚的，当事人应当先撤离现场再进行协商处理。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"轻微事故（无人伤亡、车能开、事实清楚）=先拍照固定证据→撤离现场到不妨碍交通的地方→再协商或报警。造成交通堵塞的处200元罚款。",tip:"口诀：小事故=拍照→撤离→协商。堵在路上双方都可能被罚。"},
{id:589,cat:"laws",type:"choice",q:"驾驶机动车运载超限不可解体物品，应该怎样做？",opts:["直接运输","经公安机关交通管理部门批准，按指定时间、路线、速度行驶并悬挂标志","夜间运输即可","只需挂警示标志即可"],ans:1,exp:"超限运输（超长、超宽、超高、超重）不可解体物品须取得「超限运输车辆通行证」，严格按审批的路线、时间、速度行驶，悬挂明显标志。未审批运输扣6分。",tip:"口诀：大件运输=先审批→按路线走→挂标志。超大件不是想运就能运的。"},
{id:590,cat:"laws",type:"judgment",q:"机动车所有人发现登记内容有错误的，应及时申请更正登记。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"登记内容（如车身颜色、发动机号等）有误或因车辆变更导致与实际情况不符的，机动车所有人应当向车辆管理所申请更正登记或变更登记。",tip:"口诀：登记信息不对=申请更正。车和证信息必须一致。"},
{id:591,cat:"laws",type:"choice",q:"已注册登记的机动车改变车身颜色的，机动车所有人应在改变后多长时间内向车辆管理所申请变更登记？",opts:["10日","15日","30日","60日"],ans:1,exp:"改变车身颜色（包括贴膜改色）、更换发动机、更换车身或车架的，应在变更后10日内向车辆管理所申请变更登记。擅自改变未登记的，上路行驶将面临处罚。",tip:"口诀：改色/换发动机车身=10天内去登记。改完赶紧去备案，别等被查到。"},
{id:592,cat:"laws",type:"choice",q:"驾驶机动车在道路上发生交通事故，以下哪种情况可以即行撤离现场？",opts:["有人受伤","车辆无法移动","仅轻微财产损失且事实清楚","双方争议较大"],ans:2,exp:"轻微财产损失事故+事实清楚+无争议=可先撤离再协商。有人身伤亡、车辆不能移动、双方有争议、涉及酒驾无证等情况=必须保护现场并立即报警。",tip:"口诀：小刮擦无争议=撤离后处理；有人伤/车不能动/争执=必须等警察。"},
{id:593,cat:"laws",type:"judgment",q:"机动车在高速公路上行驶时，不得载人超过核定人数。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"所有机动车在任何道路上均不得超载。高速公路超载尤其危险——高速行驶中超载车辆制动距离更长、爆胎风险更高、事故后果更严重。营运客车高速超载20%以上=12分。",tip:"口诀：超载不分路——哪条路都不行。高速超载=加倍危险+加倍处罚。"},
{id:594,cat:"laws",type:"choice",q:"交通警察在处理交通事故时，对于应当扣留的机动车，可以扣留多长时间？",opts:["不超过15日","不超过30日","不超过60日","根据需要确定，法律有规定的按规定"],ans:3,exp:"扣留车辆的时间根据检验鉴定等需要确定，没有统一的上限天数。但检验鉴定一般不超过30日，特殊情况可延长。扣留期满后应及时退还。",tip:"口诀：扣车时间看需要（鉴定、调查等），没有固定上限。检验一般30天内。"},
{id:595,cat:"laws",type:"judgment",q:"饮酒后驾驶机动车的判定标准是血液中酒精含量大于或等于20mg/100ml。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"饮酒驾车=血液酒精含量≥20mg/100ml且<80mg/100ml，记12分+暂扣驾驶证6个月+罚款1000-2000元。醉酒驾车=≥80mg/100ml，构成危险驾驶罪。",tip:"口诀：20mg=酒驾（违法），80mg=醉驾（犯罪）。20和80是两条生死线。"},
{id:596,cat:"laws",type:"choice",q:"醉酒驾驶机动车的，应受到什么处罚？",opts:["记12分，暂扣驾驶证","吊销驾驶证，依法追究刑事责任，5年内不得重新取得","罚款200元","记6分"],ans:1,exp:"醉酒驾车（≥80mg/100ml）=吊销驾驶证+追究刑事责任（危险驾驶罪）+5年内不得重新取得驾驶证。醉酒驾驶营运机动车=吊销+终身不得重新取得营运驾驶证+10年内不得重新取得驾驶证。",tip:"口诀：醉驾=吊销+坐牢（拘役）+5年禁考。喝了酒摸方向盘=代价巨大。"},
{id:597,cat:"laws",type:"choice",q:"以下关于交强险（机动车交通事故责任强制保险）的说法正确的是？",opts:["可以自愿购买","所有上道路行驶的机动车必须投保","仅新车上路需要","仅营运车辆需要"],ans:1,exp:"交强险=法定强制保险，所有上道路行驶的机动车必须投保。未投保交强险的车辆不得上路，违者扣留车辆+处保费两倍罚款。商业险自愿购买。",tip:"口诀：交强险=强制买（不买扣车+罚款）。商业险=自愿买。强制的必须买。"},
{id:598,cat:"laws",type:"judgment",q:"机动车发生交通事故造成人身伤亡或财产损失的，由保险公司在交强险责任限额范围内予以赔偿；不足部分由商业险补充或当事人自行承担。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"交强险先赔付→不足部分由商业三者险补充→仍不足的由侵权人（责任方）自行承担。交强险赔偿限额（2026年）：死亡伤残180000元、医疗费用18000元、财产损失2000元。",tip:"口诀：赔偿顺序=先交强→再商业→最后自掏腰包。交强险是底层保障。"},
{id:599,cat:"laws",type:"choice",q:"机动车驾驶人因服兵役、出国等原因无法在规定时间内办理驾驶证期满换证的，可以申请延期，延期最长不超过多久？",opts:["1年","2年","3年","5年"],ans:1,exp:"因服兵役、出国（境）等原因无法按时换证的，可向车辆管理所申请延期办理，延期期限最长不超过2年。延期期间不得驾驶机动车。",tip:"口诀：出国当兵可延期换证最长2年。但延期期间不能开车。"},
{id:600,cat:"laws",type:"choice",q:"机动车登记证书、号牌、行驶证丢失或损毁的，机动车所有人应当向哪个部门申请补领？",opts:["公安机关交通管理部门（车辆管理所）","保险公司","机动车销售商","交通运输局"],ans:0,exp:"牌证丢失应向登记地车辆管理所申请补领。补领期间应使用临时号牌。补领后原丢失牌证作废。不得私自制作或使用伪造牌证。",tip:"口诀：牌证丢了找车管所补。补领期间用临牌，原丢失牌证作废。"},
{id:601,cat:"laws",type:"judgment",q:"在道路上发生交通事故，未造成人身伤亡且当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无人伤+无争议=可自行撤离协商。这是法律鼓励的快速处理方式，避免因小事故造成大堵车。但应先拍照或标划位置再撤离。",tip:"口诀：无人伤+谈得拢=拍照走人。别因为小刮擦堵死一条路。"},
{id:602,cat:"laws",type:"choice",q:"驾驶机动车遇前方交叉路口交通阻塞时，应当怎么做？",opts:["鸣喇叭催促","依次停在路口以外等候","绕行非机动车道","强行进入路口"],ans:1,exp:"「闯绿灯」也违法——绿灯亮但路口拥堵、车辆无法一次性通过时，应在停止线外等候，待路口净空后再进入。强行进入导致路口锁死将加重拥堵。",tip:"口诀：绿灯+路口堵=停在停止线外等。进去了出不来=堵上加堵。"},
{id:603,cat:"laws",type:"choice",q:"机动车在高速公路上行驶，车速低于100km/h时，与前车的最小安全距离是多少？",opts:["不少于30米","不少于50米","不少于80米","不少于100米"],ans:1,exp:"车速<100km/h时安全距离≥50米；车速≥100km/h时≥100米。可利用车距确认标线辅助判断。安全距离=反应距离+制动距离。",tip:"口诀：低速50米，高速100米。少于100码=50米打底。"},
{id:604,cat:"laws",type:"judgment",q:"已持有C1驾驶证申请增驾C2的，应当考科目一、科目二、科目三道路驾驶技能和科目三安全文明驾驶常识全部科目。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"C1增驾C2（自动挡）=免考科目一和科目三安全文明驾驶（科目四），只需考科目二和科目三道路驾驶技能。因为C1驾驶人已具备道路交通安全法律法规知识。",tip:"口诀：C1增C2=免文科（科一+科四），只考实操（科二+科三路考）。"},
{id:605,cat:"laws",type:"choice",q:"持境外机动车驾驶证的人申请中国机动车驾驶证，符合规定的，应参加什么考试？",opts:["无需考试","只需考科目一","考科目一、科目二和科目三","考全部科目"],ans:2,exp:"持境外驾驶证申领中国驾驶证，应考科目一（理论）。申请A1、A2、B1、B2等大型车辆驾驶证的，还应加考科目二和科目三。临时入境的境外驾驶证经翻译公证后可短期使用。",tip:"口诀：境外换国内证=考科一（理论）。大车加考实操。翻译公证可短期使用。"},
{id:606,cat:"laws",type:"judgment",q:"机动车驾驶人不得将机动车交由未取得机动车驾驶证的人驾驶。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"将车交给无证人驾驶=罚款200-2000元+可并处吊销驾驶证。借车之前先看证——确认对方持有有效驾驶证且准驾车型相符。",tip:"口诀：借车先看证！给无证人开车=你的驾照可能被吊销。"},
{id:607,cat:"laws",type:"choice",q:"驾驶机动车行经下列哪种路段时不得超车？",opts:["高速公路","城市主干道","人行横道","环岛"],ans:2,exp:"人行横道不得超车——因为可能有行人正在通过或准备通过，超车行为极易发生「鬼探头」事故。此外，铁路道口、交叉路口、窄桥、弯道、陡坡、隧道等也禁止超车。",tip:"口诀：人行横道禁超车！道口/路口/桥/弯/坡/隧道全都禁超车。"},
{id:608,cat:"laws",type:"choice",q:"关于机动车号牌的使用，以下哪种做法是正确的？",opts:["使用可拆卸号牌架方便取下","保持号牌清晰完整，使用固封装置固定","用贴纸遮挡部分号牌数字","把号牌放在挡风玻璃内侧"],ans:1,exp:"号牌必须按规定悬挂并使用专用固封装置（防盗螺丝）固定，保持清晰、完整。不得使用可拆卸号牌架、不得遮挡污损、不得倒置。遮挡号牌记9分，伪造记12分。",tip:"口诀：号牌=固封螺丝固定+清晰完整。可拆卸牌架违法，遮牌9分造假12分。"},
{id:609,cat:"laws",type:"judgment",q:"驾驶机动车在高速公路上行驶，能见度低于200米时，最高车速不得超过60km/h。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"能见度<200米=限速60km/h+间距≥100米+开启雾灯、近光灯、示廓灯和前后位灯。这是高速低能见度行驶的第一档要求。",tip:"口诀：200-60-100。能见度200→限速60→间距100。三个数字联记。"},
{id:610,cat:"laws",type:"choice",q:"机动车驾驶人身体条件不适合驾驶机动车时，以下做法正确的是？",opts:["可以继续驾驶但需小心","不得驾驶机动车","只要服药就可以驾驶","只需向单位报告"],ans:1,exp:"身体条件不适合驾驶时不得驾驶机动车。患有妨碍安全驾驶的疾病（如癫痫、严重心脏病、眩晕症等）或服用影响驾驶能力的药物（含部分感冒药、抗过敏药）后，不得驾车。",tip:"口诀：身体不行/吃了影响开车的药=别开车。硬撑着开=对自己和别人不负责。"},
{id:611,cat:"laws",type:"choice",q:"以下哪种情形下，公安机关交通管理部门应当注销机动车驾驶证？",opts:["记满12分","驾驶人死亡或丧失民事行为能力","交通违法未处理","驾驶证丢失"],ans:1,exp:"注销情形包括：驾驶人死亡、丧失民事行为能力、身体条件不适合、主动申请注销、超过有效期1年以上未换证等。记满12分是扣留不是注销。",tip:"口诀：注销=驾照永久作废——死亡/失能/过期1年以上/主动放弃。12分满=扣留（还能考回来）。"},
{id:612,cat:"laws",type:"judgment",q:"机动车在没有限速标志标线的道路上，城市道路最高行驶速度为30km/h，公路为40km/h。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无标线道路的法定最高限速：城市道路≤30km/h，公路≤40km/h。同方向只有1条机动车道的道路，城市≤50km/h，公路≤70km/h。",tip:"口诀：无标线=城市30公路40。同向1车道=城市50公路70。"},
{id:613,cat:"laws",type:"choice",q:"机动车驾驶人累积记分达到规定分值，拒不参加公安机关交通管理部门通知的学习和考试的，公安机关可以采取什么措施？",opts:["继续催告","公告其驾驶证停止使用","直接吊销驾驶证","不予处理"],ans:1,exp:"记满12分后拒不参加学习考试的，公安机关公告其驾驶证停止使用。公告停止使用期间驾车的，按无证驾驶处理（记6分+可以拘留）。",tip:"口诀：不去学不去考=公告驾照停用。停用期间开车=无证驾驶=6分+可拘留。"},
{id:614,cat:"laws",type:"choice",q:"驾驶机动车在夜间通过急弯、坡路、拱桥、人行横道或没有交通信号灯控制的路口时，应如何使用灯光？",opts:["一直使用远光灯","交替使用远近光灯示意","关闭所有灯光","只使用近光灯"],ans:1,exp:"夜间通过上述危险或视线受限路段，应交替使用远近光灯（闪灯）示意，提醒其他交通参与者注意。这是强制性的灯光使用规定。",tip:"口诀：夜间过特殊路段=闪灯（远近交替）。弯/坡/桥/人行道/无灯路口统统闪灯。"},
{id:615,cat:"laws",type:"judgment",q:"驾驶机动车在道路上发生交通事故，造成人身伤亡的，驾驶人应立即抢救伤员并迅速报告执勤交通警察或公安机关交通管理部门。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"有人身伤亡的事故=立即停车→抢救伤员→保护现场→报警（122）。因抢救伤员需变动现场的，应标明位置。这是法定的事故处理程序。",tip:"口诀：人伤事故=停车→救人→保护现场→打122。救人第一，报警第二。"},
{id:616,cat:"laws",type:"choice",q:"私家车（非营运小型客车）的强制报废标准是什么？",opts:["行驶满10年","行驶满15年","行驶满60万公里","无强制报废年限，但需通过年检"],ans:2,exp:"2026年：私家车（小型非营运载客汽车）无使用年限限制，但行驶里程达60万公里时引导报废。关键是通过定期年检——只要年检合格就可继续使用。营运车辆有年限限制。",tip:"口诀：私家车=60万公里引导报废（无年限强制）。年检过关就能继续开。"},
{id:617,cat:"laws",type:"choice",q:"以下哪种车辆有强制报废年限？",opts:["私家小轿车","出租车（营运）","SUV","MPV"],ans:1,exp:"营运载客汽车有强制报废年限：小微型出租车8年、中型出租车10年、大型出租车12年。私家车（非营运小微型客车）无年限限制。公交车13年。",tip:"口诀：出租车有报废年限（8年），私家车无年限。营运车有使用年限，私家车60万公里引导。"},
{id:618,cat:"laws",type:"judgment",q:"驾驶机动车在雾天行驶时应当开启雾灯和危险报警闪光灯。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"雾天=雾灯+近光灯。能见度<100米时应加开危险报警闪光灯（双闪）。但绝对禁用远光灯——远光会被雾气中的水滴反射造成白茫茫一片，反而什么都看不见。",tip:"口诀：雾天=雾灯+近光，<100米再加双闪。远光是雾天杀手——白茫茫一片全瞎。"},
{id:619,cat:"laws",type:"choice",q:"关于机动车安全技术检验（年检），以下哪种说法正确？",opts:["新车10年内免检","6年内新车免上线检验，每2年申领一次检验标志","所有车每年必须上线检验","私家车永远不需要检验"],ans:1,exp:"9座及以下非营运小微型客车（面包车除外）：6年内免上线检验（每2年申领检验标志），第6年和第10年上线检验，10-15年每年检验1次，15年以上每半年检验1次。",tip:"口诀：新车6年免上线（每2年领标），第6年上线→10年再上→之后每年检→15年以上半年检。"},
{id:620,cat:"laws",type:"judgment",q:"申领C1驾驶证的身体条件中，身高要求为不低于155厘米。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"C1/C2驾驶证无身高要求。只有申请大型客车（A1）、牵引车（A2）、城市公交车（A3）、大型货车（B2）、无轨电车（N）等车型时才有身高要求（不低于155厘米）。C照没有身高限制。",tip:"口诀：C照无身高要求！只有大车（A/B）才要求155cm以上。小轿车谁来开都行。"},
{id:621,cat:"laws",type:"choice",q:"吊销机动车驾驶证未满多长时间的，不得申请机动车驾驶证？",opts:["1年","2年","3年","5年"],ans:1,exp:"吊销驾驶证后2年内不得重新申领。醉酒驾车吊销驾驶证后5年内不得重新申领。交通肇事逃逸构成犯罪的，终身不得重新取得驾驶证。不同情形，禁考年限不同。",tip:"口诀：一般吊销=2年禁考，醉驾=5年禁考，肇事逃逸犯罪=终身禁考。"},
{id:622,cat:"laws",type:"judgment",q:"道路交通安全法规定，机动车与非机动车驾驶人、行人之间发生交通事故，机动车一方没有过错的，不承担赔偿责任。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"机动车与非机动车/行人发生事故，适用无过错责任原则——即使机动车无过错，也需承担不超过10%的赔偿责任。但如果事故是非机动车/行人故意造成的（碰瓷），机动车不承担赔偿责任。",tip:"口诀：机动车vs行人=机动车总有部分责任（最多10%），除非对方碰瓷。铁包肉vs肉包铁。"},
{id:623,cat:"laws",type:"choice",q:"驾驶机动车在没有中心线的城市道路上，最高行驶速度不得超过多少？",opts:["20km/h","30km/h","40km/h","50km/h"],ans:1,exp:"无中心线=城市道路30km/h、公路40km/h。同向1条机动车道=城市50km/h、公路70km/h。中心线的有无是限速的关键区分因素。",tip:"口诀：无中线=城市30公路40。同向1车道=城市50公路70。中线决定速度。"},
{id:624,cat:"laws",type:"choice",q:"机动车在进入高速公路前的匝道上行驶时，最高速度不得超过多少？",opts:["30km/h","40km/h","50km/h","60km/h"],ans:1,exp:"高速公路匝道限速一般为40km/h。匝道转弯半径小、车道窄，速度过快极易失控冲出车道。驶入加速车道后才能提速至60km/h以上准备并入主线。",tip:"口诀：匝道=40码慢走。出了匝道到加速车道才能提速到60+。"},
{id:625,cat:"laws",type:"judgment",q:"机动车驾驶人可以同时持有C1和C2两种驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"C2是C1的包含子集——C1驾驶证准驾范围覆盖C2（自动挡小型汽车），因此持C1证即可驾驶手动挡和自动挡小型汽车，无需也不能同时持有C2证。",tip:"口诀：C1包含了C2（自动挡），拿了C1就不用C2。驾驶证每人只能有一本。"},
{id:626,cat:"laws",type:"choice",q:"以下哪项属于C1驾驶证的准驾车型？",opts:["大型客车","中型客车","小型、微型载客汽车及轻型载货汽车","摩托车"],ans:2,exp:"C1=小型汽车（含手动挡和自动挡，含小客车和小货车），车长<6米且乘坐人数≤9人（含驾驶人）的载客汽车，以及总质量<4.5吨的载货汽车。不包括摩托车（E/D）和大型车辆（A/B）。",tip:"口诀：C1=蓝牌小客+小货（<6米+≤9座+<4.5吨）。不包含摩托车——摩托要单独考。"},
{id:627,cat:"laws",type:"choice",q:"达到报废标准的机动车不得上道路行驶。报废的大型客车、货车及其他营运车辆应当怎么做？",opts:["卖给废品收购站","在公安机关交通管理部门监督下解体","自行拆解","转卖至外地"],ans:1,exp:"报废的营运车辆及大型客货车必须在公安机关交通管理部门的监督下解体（强制报废），防止报废车重新拼装流入市场。私家车交售给有资质的报废回收企业。",tip:"口诀：营运车/大车报废=交警监督下解体。防止报废车「死而复生」重新上路害人。"},
{id:628,cat:"laws",type:"judgment",q:"驾驶机动车造成交通事故后逃逸的，由公安机关吊销驾驶证并终身不得重新取得。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"造成交通事故后逃逸的，吊销驾驶证+终身不得重新取得=「终身禁驾」。这是对肇事逃逸最严厉的行政处罚。同时如构成交通肇事罪，还需承担刑事责任。",tip:"口诀：肇事逃逸=终身禁驾（不管后果轻重）。跑了就别想再开车了。"},
{id:629,cat:"laws",type:"choice",q:"机动车在交叉路口、铁路道口、急弯路、宽度不足4米的窄路、桥梁、陡坡、隧道以及距离上述地点多少米以内的路段，不得停车？",opts:["30米","50米","100米","150米"],ans:1,exp:"在上述危险路段及距离这些路段50米以内的区域禁止停车。另外，公交车站、急救站、消防站门前及距离30米以内的路段禁止停车（使用上述设施的除外）。",tip:"口诀：路口/道口/窄路/桥/坡/隧道50米内禁停；公交站/消防站30米内禁停。"},
{id:630,cat:"laws",type:"choice",q:"机动车在高速公路上行驶，小型载客汽车最高车速不得超过多少？",opts:["100km/h","110km/h","120km/h","130km/h"],ans:2,exp:"高速最高限速120km/h（小型载客汽车）。其他机动车（含大客车、货车）最高100km/h，摩托车最高80km/h。实际限速以道路标志为准。",tip:"口诀：小车高速120封顶。大车100、摩托车80。谁都不能超。"},
{id:631,cat:"laws",type:"judgment",q:"驾驶机动车在高速公路发生故障，需要救援时，应由驾驶人自行联系社会救援车辆拖拽。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"高速公路故障应由高速公路经营管理单位组织的专业救援车辆（清障车）拖拽至最近出口或服务区，不得自行拦截过往车辆拖拽。可拨打12122（高速公路报警救援电话）。",tip:"口诀：高速拖车=专业救援队（打12122）。不能自己找社会车辆，这是法律规定。"},
{id:632,cat:"laws",type:"choice",q:"驾驶机动车上路行驶，以下哪种情形不需要随身携带相应证件？",opts:["驾驶证","行驶证","身份证","检验合格标志和保险标志"],ans:2,exp:"上路行驶需随车携带：驾驶证、行驶证、检验合格标志和保险标志。2026年电子证照全国通用，可通过交管12123APP出示电子驾驶证和行驶证。身份证不需随身携带（无此法定要求）。",tip:"口诀：上路带三证——驾驶证+行驶证+检验保险标。身份证不带也可以。"},
{id:633,cat:"laws",type:"choice",q:"已注册登记的机动车达到国家规定的强制报废标准，机动车所有人应当向车辆管理所申请什么？",opts:["转让登记","变更登记","注销登记","抵押登记"],ans:2,exp:"达到报废标准=所有人须向车辆管理所申请注销登记，并将车辆交售给有资质的报废机动车回收企业。注销登记后该车辆不得再上路行驶。",tip:"口诀：报废=注销登记+交给回收企业。不能自己乱拆乱卖。"},
{id:634,cat:"laws",type:"judgment",q:"机动车行驶证灭失、丢失的，机动车所有人应当向登记地车辆管理所申请补领。补领后，原行驶证作废。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"行驶证丢失应当向登记地车辆管理所申请补领。补领后原行驶证作废，不得继续使用。行驶证是车辆合法上路的凭证之一，应妥善保管。",tip:"口诀：行驶证丢了=去车管所补。补了新的，旧的就算找回也不能用。"},
{id:635,cat:"laws",type:"choice",q:"以下哪项不属于醉酒驾车（≥80mg/100ml）的处罚？",opts:["吊销驾驶证","追究刑事责任","5年内不得重新取得驾驶证","仅记12分"],ans:3,exp:"醉驾的处罚是：吊销驾驶证+追究刑事责任（拘役）+5年内禁考——不是简单的记12分。记12分是针对饮酒驾车（20-80mg/100ml）的处罚。",tip:"口诀：醉驾≠12分——醉驾=吊销+坐牢+5年禁考。比酒驾（记12分+扣证6月）重得多。"},
{id:636,cat:"laws",type:"choice",q:"小型、微型非营运载客汽车（私家车）的年检政策中，6-10年的车辆应如何检验？",opts:["每半年检1次","每年检1次","每2年检1次，第6年和第10年上线检验","免检"],ans:2,exp:"私家车6年内免上线检验；第6年和第10年上线检验；第8年申领检验标志（免上线）；10-15年每年1次上线检验；15年以上每半年1次上线检验。",tip:"口诀：6年免上线→第6年上线→第8年领标→第10年上线→之后每年上线→15年+每半年上线。"},
{id:637,cat:"laws",type:"judgment",q:"机动车驾驶证申请人必须是中国公民，外国人不能在中国申请驾驶证。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"外国人在中国境内可以申领中国驾驶证。持境外驾驶证申领中国驾驶证的，需考科目一（大车加考实操）。临时入境的持境外驾驶证翻译公证后可短期使用。",tip:"口诀：外国人也能拿中国驾照。境外驾照换中国证=考科一。"},
{id:638,cat:"laws",type:"judgment",q:"驾驶机动车在高速公路上不得倒车、逆行、穿越中央分隔带掉头或在车道内停车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"上述行为在高速公路均被严格禁止，每一项都记12分。高速公路是封闭的快速通道，任何倒车逆行等「逆向操作」都是极度危险且违法的。",tip:"口诀：高速五禁——不倒车、不逆行、不掉头、不停车道内、不穿越中央分隔带。"},
{id:639,cat:"signals",type:"choice",q:"交通信号灯由红灯、绿灯、黄灯组成。红灯表示禁止通行，绿灯表示准许通行，黄灯表示什么？",opts:["加速通过","警示（已过线的车可继续通行，未过线的应停车）","允许通行","禁止一切通行"],ans:1,exp:"黄灯=警示信号。黄灯亮时已越过停止线的车辆可继续通行，未越过停止线的车辆应减速停车。黄灯是过渡信号，不是催你加速的信号。",tip:"口诀：黄灯=警示——过了线继续走，没过线赶紧停。抢黄灯=抢危险。"},
{id:640,cat:"signals",type:"judgment",q:"交通信号灯中，红灯亮时右转弯车辆在不妨碍被放行车辆和行人通行的情况下可以通行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"红灯亮时，右转弯车辆在不妨碍被放行车辆和行人通行的情况下可以通行——全国通行原则。但若路口设有「红灯禁止右转」标志或红色右转箭头灯则不得右转。",tip:"口诀：红灯可以右转（除非有禁右标志/红灯箭头）。右转时让行人让直行车。"},
{id:641,cat:"signals",type:"choice",q:"当路口信号灯为持续闪烁的黄灯（黄闪）时，车辆应如何通行？",opts:["加速通过","直接通过","减速慢行，注意瞭望确认安全后通过","立即停车等待"],ans:2,exp:"黄闪=注意瞭望+减速+确认安全后通过。通常设在夜间车流量小或无信号灯控制的路口，警示驾驶人谨慎通行。不是强制停车，但必须减速观察。",tip:"口诀：黄灯一闪一闪=小心点走。减速看清楚了再过。"},
{id:642,cat:"signals",type:"choice",q:"箭头信号灯中，绿色左转箭头灯亮时，车辆能否直行？",opts:["可以直行","不能直行，只能左转","可以在确保安全时直行","需看交警手势"],ans:1,exp:"箭头信号灯按箭头方向通行。绿色左转箭头灯仅允许左转，直行车辆须等待直行绿色箭头灯或圆形绿灯亮起。多相位箭头灯控制的交叉口，各方向分开放行。",tip:"口诀：箭头灯=指哪走哪。绿左箭头=只准左转，直行得等直行绿灯。"},
{id:643,cat:"signals",type:"judgment",q:"在道路上遇到交通信号灯和交通警察手势指挥不一致时，应当按信号灯通行。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"交警手势>信号灯>标志标线。这是法定的优先顺序。交警现场指挥的效力最高——即使绿灯亮交警手势示意停车也必须停车。",tip:"口诀：有人听人（交警），没人听灯。交警手势永远是第一优先级。"},
{id:644,cat:"signals",type:"choice",q:"交警左臂向前上方直伸、掌心向前，这个手势表示什么？",opts:["左转弯信号","停止信号","靠边停车信号","直行信号"],ans:1,exp:"交警左臂向前上方直伸、掌心向前=停止信号，面向哪方哪方车辆停止。这是最常用的停止手势。注意与左转弯待转信号（左臂向左下方平伸）的区别。",tip:"口诀：交警手举过头顶=停止。手一抬，车就得停。"},
{id:645,cat:"signals",type:"choice",q:"交警双臂平伸、掌心向前，这个手势表示什么？",opts:["停止","左转弯","直行","变道"],ans:2,exp:"交警双臂平伸、掌心向前=直行信号，准许左右两方直行车辆通行，各方右转弯车辆在不妨碍被放行车辆的情况下也可通行。交警面向哪个方向，哪个方向的车可直行。",tip:"口诀：双臂平伸=直行。交警面朝你=你可以直行。"},
{id:646,cat:"signals",type:"judgment",q:"交警发出左转弯信号时，左臂向右前方平伸、掌心向前，右臂向左前方摆动。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"左转弯手势=左臂向右前方平伸、掌心向前，右臂从前方向左摆动（做「请」的动作）。描述中「右臂向左前方摆动」表述不准确，应为从胸前位置向左水平摆动。",tip:"口诀：左转弯=左手平伸指方向+右手摆动请过来。左手指向，右手邀请。"},
{id:647,cat:"signals",type:"choice",q:"交警右臂向右前方平伸、掌心向前，左臂向右前方摆动，这个手势表示什么？",opts:["右转弯信号","变道信号","靠边停车信号","减速慢行信号"],ans:0,exp:"右转弯手势=右臂向右前方平伸+左臂向右前方摆动。与左转弯对称——右手指方向+左手做「请」的动作。准许右方车辆右转弯。",tip:"口诀：右转弯=右手平伸指方向+左手摆动请过来。手势对称，左右互换。"},
{id:648,cat:"signals",type:"choice",q:"交警右臂向右前方平伸，掌心向下，向左下方摆动（下压式摆动），这个手势表示什么？",opts:["右转弯","变道","减速慢行","靠边停车"],ans:2,exp:"右臂向右前方平伸掌心向下+向左下方摆动=减速慢行信号。交警面向哪方，哪方车辆须减速。注意与变道信号的区别——减速慢行是下压式摆动，变道是水平摆动。",tip:"口诀：手臂平伸+向下压=减速慢行。交警让你慢你就得慢。"},
{id:649,cat:"signals",type:"judgment",q:"交警左臂向左下方平伸、掌心向下，这个手势表示左转弯待转信号。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"左臂向左下方平伸、掌心向下=左转弯待转信号。示意左转弯车辆可以进入路口等待左转时机（但不能直接左转），等待左转信号放行。",tip:"口诀：左臂斜向下=左转待转。让你进路口等着，不是直接转。"},
{id:650,cat:"signals",type:"choice",q:"道路中心线为黄色虚线的，表示什么？",opts:["禁止跨越","允许在安全的情况下跨越超车或左转","分隔同向车道","表示道路边缘"],ans:1,exp:"黄色虚线=对向车流分隔线，允许在确保安全的情况下越线超车或左转弯。黄色实线=禁止跨越。黄色虚实线=虚线侧可跨越，实线侧不可跨越。",tip:"口诀：黄虚线=可跨越超车/转弯。黄实线=绝对禁跨。虚可跨，实不能。"},
{id:651,cat:"signals",type:"choice",q:"道路中心黄色双实线表示什么？",opts:["可以临时跨越","双向均严格禁止跨越超车或压线行驶","一侧可以跨越","用于临时停车"],ans:1,exp:"黄色双实线=对向车流分隔，双向均严禁跨越超车和压线行驶。相当于道路中心的一堵墙。通常在道路较宽、交通流量大的路段使用。",tip:"口诀：黄双实线=双向禁跨（中心一堵墙）。两边都别想跨。"},
{id:652,cat:"signals",type:"judgment",q:"道路中间的黄色虚实线，虚线一侧的车辆可以临时跨越，实线一侧的车辆禁止跨越。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"黄虚实线=虚线侧可跨+实线侧不能跨。通常设在弯道、坡道等视野受限制的路段，给视野好的一侧（虚线侧）超车机会。",tip:"口诀：黄虚实线=谁虚谁过（虚线这边可跨）。实线那边乖乖待着。"},
{id:653,cat:"signals",type:"choice",q:"路口处的白色实线（停止线）表示什么？",opts:["减速慢行线","车辆遇到停止信号时停车的界限","车道分界线","人行横道线"],ans:1,exp:"停止线=红灯或停止信号时车辆应在该线前停止。白色实线，一般与信号灯配合设置。没有停止线的路口应停在路口以外。",tip:"口诀：白实线在路口=停止线。红灯时车头不能越过这条线。"},
{id:654,cat:"signals",type:"choice",q:"路口白色双虚线（减速让行线）表示什么？",opts:["停车让行","减速让行，不妨碍干路车辆时可通过","禁止通行","人行横道"],ans:1,exp:"白色双虚线=减速让行线，车辆应减速观察，确认安全、不妨碍干路车辆时可通过。区别于停车让行线（白色双实线=必须完全停车观察）。",tip:"口诀：白双虚线=减速让行（不一定停）；白双实线=停车让行（必须停！）。虚让实停。"},
{id:655,cat:"signals",type:"judgment",q:"路面上白色的菱形标线表示前方有人行横道预告，应减速慢行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"白色菱形标线=人行横道预告标线，设于人行横道前30-50米处，提醒驾驶人前方有斑马线应减速并做好让行准备。看到第一个菱形就应该开始减速。",tip:"口诀：白色菱形=前方斑马线预告。看到菱形=脚放刹车上。"},
{id:656,cat:"signals",type:"choice",q:"导流线（路口内白色V形斜线填充区域）的作用是什么？",opts:["可以临时停车","引导车辆按规定路线行驶，禁止压线或越线行驶及停车","供行人通行","可以在此区域掉头"],ans:1,exp:"导流线=引导车辆按规定路线行驶，严禁压线、越线或停放车辆。通常设在路口或复杂路段，起分流和引导作用。违者记1分。",tip:"口诀：导流线=禁压、禁停、禁越。V形白斜线区域是「禁区」——不能碰。"},
{id:657,cat:"signals",type:"choice",q:"网状线（黄色网格线）表示什么？",opts:["可以停车","禁止以任何原因停车（可通行但不可停留）","为公交车专用","临时停车区"],ans:1,exp:"黄色网格线=禁止停车区域（可通行但严禁以任何原因在此区域内停车等候），通常设于重要单位出入口、交叉路口等。即使前方拥堵也不能在网格线上停车等待。",tip:"口诀：黄网格=禁停区（能过不能停）。堵车也别停在网格里。"},
{id:658,cat:"signals",type:"judgment",q:"黄底黑边三角形内含感叹号的标志表示「注意危险」警告。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"黄三角+感叹号=「注意危险」标志，设于其他警告标志不能包括的危险路段前，提醒驾驶人谨慎驾驶。是通用的危险警告标志。",tip:"口诀：黄三角+！=注意危险。通用的「前方有情况」预警。"},
{id:659,cat:"signals",type:"choice",q:"警告标志（黄底黑边三角形）和禁令标志（白底红边圆形）在形状上的主要区别是什么？",opts:["颜色一样","警告标志是三角形，禁令标志是圆形（个别除外）","两者都是圆形","形状完全一样"],ans:1,exp:"警告标志=三角形（黄底黑边），提醒注意；禁令标志=圆形（白底红边），表示禁止。例外：禁令标志中「停」字为八角形、「让」字为倒三角形。指路标志为方形。",tip:"口诀：三角=警告（注意），圆形=禁令（禁止），方形=指路（方向）。看形状就知道是什么类型的标志。"},
{id:660,cat:"signals",type:"choice",q:"红色八角形中间写有「停」字的标志表示什么？",opts:["减速慢行","停车让行","禁止停车","临时停车"],ans:1,exp:"红色八角形+「停」=停车让行标志。车辆须在停止线前完全停车瞭望，确认安全后方可通行。与减速让行（红倒三角+「让」）不同——停车让行=必须停，减速让行=减速观察后可走。",tip:"口诀：红八角+停=必须停车让行。「停」字不是建议，是命令。"},
{id:661,cat:"signals",type:"choice",q:"红色倒三角形中间写有「让」字的标志表示什么？",opts:["停车让行","减速让行","禁止驶入","解除限制"],ans:1,exp:"红倒三角+「让」=减速让行标志。车辆应减速慢行或停车瞭望，确认安全后通行。不必完全停车——与「停」字八角形有本质区别。",tip:"口诀：红倒三角+让=减速让行（不一定停）。和八角停字的区别——停=必停，让=减速看后走。"},
{id:662,cat:"signals",type:"judgment",q:"蓝底方形内含有白色箭头指示方向的标志属于警告标志。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"蓝底方形+白色箭头=指示标志（不是警告标志）。指示标志告诉驾驶人应当如何行驶——指示车辆和行人按规定方向行驶。警告标志是黄底三角形。",tip:"口诀：蓝底=指示（告诉你该怎么走），黄三角=警告（提醒你注意危险）。蓝指示，黄警告。"},
{id:663,cat:"signals",type:"choice",q:"指路标志中，高速公路指路标志的底色是什么颜色？",opts:["蓝色","绿色","棕色","黄色"],ans:1,exp:"高速公路指路标志=绿底白字；普通公路指路标志=蓝底白字；旅游区标志=棕底白字。三种颜色区分道路等级和用途。",tip:"口诀：高速指路=绿底，普通路指路=蓝底，旅游区=棕底。绿蓝棕三色分三级。"},
{id:664,cat:"signals",type:"judgment",q:"禁令标志「红圈+白色数字+黑色斜杠」表示解除该数字所对应的限速。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"红圈+数字+黑色斜杠（从右上到左下划过数字）=解除限速标志。例如「80」+斜杠=解除80km/h最高限速。斜杠表示「不再适用」的意思。",tip:"口诀：数字+斜杠=该限速解除。斜杠=划掉=没这个限制了。"},
{id:665,cat:"signals",type:"choice",q:"以下哪个标志表示「禁止驶入」？",opts:["红圈白底","红圈白底中间一条黑色横杠","红色八角形","红色倒三角形"],ans:1,exp:"红圈白底+黑横杠=「禁止驶入」，通常设在禁行路段入口。与「禁止通行」（红圈全白底，无横杠）不同——禁止驶入针对机动车驶入方向，禁止通行针对所有交通参与者。",tip:"口诀：红圈+黑横杠=禁止驶入。红圈+全白=禁止通行。有杠=禁入，无杠=禁行。"},
{id:666,cat:"signals",type:"choice",q:"限速标志中，红圈+黑色数字表示什么？蓝圈+白色数字表示什么？",opts:["都是最高限速","红圈=最高限速，蓝圈=最低限速","红圈=最低限速，蓝圈=最高限速","都是最低限速"],ans:1,exp:"红圈+黑数字=最高限速（不能超过该速度）；蓝圈+白数字=最低限速（不能低于该速度）。红=上限=别超，蓝=下限=别慢。",tip:"口诀：红圈=最高限速（上限，不能超）；蓝圈=最低限速（下限，不能慢）。"},
{id:667,cat:"signals",type:"judgment",q:"绿色底色的指路标志用于所有等级的公路指路。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"绿底指路标志仅用于高速公路和城市快速路。普通公路（国道、省道、县乡道等）的指路标志为蓝底白字。不得混淆。",tip:"口诀：绿底=高速/快速路专用。普通公路=蓝底。颜色不能混。"},
{id:668,cat:"signals",type:"choice",q:"「注意行人」警告标志是黄底三角形内含什么图案？",opts:["感叹号","行人行走的黑色图案","斑马线图案","停止手势图案"],ans:1,exp:"黄三角+行人行走图案=「注意行人」警告标志，提前警示前方路段行人较多或有人行横道。与「注意儿童」（两个儿童图案）不同。",tip:"口诀：黄三角+行人走路=注意行人。看到这个标志说明前方行人多，减速多观察。"},
{id:669,cat:"signals",type:"choice",q:"可变导向车道线（锯齿状白色实线内侧）表示什么？",opts:["固定行驶方向","进入后可根据信号灯指示变更行驶方向","禁止驶入","公交专用道"],ans:1,exp:"可变导向车道=进入后行驶方向不固定，根据上方可变电子标志或信号灯指示确定方向（可能早高峰直行、晚高峰左转等）。应提前观察上方电子标志。",tip:"口诀：锯齿状车道=可变方向。看上方电子牌——它让你怎么走就怎么走。"},
{id:670,cat:"signals",type:"judgment",q:"在设有公交专用车道的路段，其他车辆在任何时候都不得驶入公交专用车道。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"有公交专用时间段的，在非专用时段（如非早晚高峰）其他车辆可以驶入。具体以标志标线标明的时间为准。无专用时间段的，全天禁止驶入。",tip:"口诀：公交专用道看时间——有时段限制的，非高峰可借用；全天专用的，永远不能进。"},
{id:671,cat:"signals",type:"choice",q:"高速公路出口预告标志通常设置在距离出口多远处开始提示？",opts:["500米","1公里、2公里、3公里分段提示","仅出口处","5公里"],ans:1,exp:"高速出口预告标志按距离分段提示：通常从2公里开始→1公里→500米→出口减速车道起点。分段设置确保驾驶人有充分时间变道准备驶离。",tip:"口诀：高速出口逐级提示——2公里→1公里→500米→出口。看到2公里牌就准备向右变道。"},
{id:672,cat:"signals",type:"choice",q:"交通信号灯中红色叉形灯（红叉）亮时表示什么？",opts:["可以通行","本车道禁止通行","可以临时停车","允许掉头"],ans:1,exp:"红叉亮=本车道禁止通行。常见于高速公路或快速路的车道控制信号灯上方——表明该车道因施工、事故等原因关闭。车辆不得驶入红叉指示的车道。",tip:"口诀：红叉=本车道关闭（禁止通行）。看到头顶红叉赶紧变道。"},
{id:673,cat:"signals",type:"judgment",q:"隧道开车灯标志（蓝底方形内有车灯图案）表示进入隧道前应开启前照灯。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"蓝底方形+车灯图案=「隧道开车灯」指示标志，提醒驾驶人进入隧道前开启近光灯。进入隧道不开灯属于不按规定使用灯光，记1分。",tip:"口诀：蓝底+车灯=隧道开灯。进隧道前提前开近光灯，这是指示标志的命令。"},
{id:674,cat:"signals",type:"choice",q:"道路施工安全标志的底色通常是什么颜色？",opts:["黄色","蓝色","橙色","红色"],ans:2,exp:"施工标志=橙色底（或橙白相间）。橙色醒目且与其他标志颜色区分明显，提醒驾驶人注意施工区域。包括施工警告标志、锥形桶、施工护栏等均以橙色为主。",tip:"口诀：施工=橙色。看到一片橙色意味着前方施工，减速慢行。"},
{id:675,cat:"signals",type:"choice",q:"路面上的横向减速标线（一组平行的白色实线横跨车道）的作用是什么？",opts:["停车线","提示驾驶人减速","分道线","停止线"],ans:1,exp:"横向减速标线=设置在车道内的白实线横条（像减速带但只有视觉提醒效果），提示驾驶人该路段应减速行驶。常设于弯道、坡道、隧道入口等需要减速的路段。",tip:"口诀：白色横条线=减速提醒。看到地上一条条白杠杠，脚就放刹车上。"},
{id:676,cat:"signals",type:"judgment",q:"高速公路上的车距确认标线（白色V形图案）供驾驶人确认与前车的安全距离，通常每50米设置一组。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"车距确认标线（V形或长方形白色图案）通常每50米一组，配合路侧的距离标志（0m、50m、100m），帮助驾驶人直观判断与前车的距离是否满足安全要求。",tip:"口诀：高速白V标=车距尺（50米一组）。用它可以量你和前车有多远。"},
{id:677,cat:"signals",type:"choice",q:"禁止停车标线（黄色实线施划于路缘石上）与禁止长时间停车标线（黄色虚线）有什么区别？",opts:["没有区别","黄实线=禁止停车（连临时停车也不行），黄虚线=禁止长时间停车但可临时停车","黄虚线更严格","都可以临时停车"],ans:1,exp:"路缘石上黄实线=严禁停车（含临时停车）；黄虚线=禁止长时间停车但允许临时停车（上下人、装卸货即停即走）。黄实=一律不能停，黄虚=可临停。",tip:"口诀：路边黄实线=一秒都不能停；黄虚线=可以临停（上下人即走）。实禁虚可临。"},
{id:678,cat:"signals",type:"choice",q:"2026年新增的「电动自行车专用道」指示标志的特征是什么？",opts:["与自行车标志相同","蓝底方形内有电动自行车轮廓图案","黄底三角","红圈禁令"],ans:1,exp:"2026年新标准新增电动自行车专用道标志——蓝底方形+电动自行车图案（区别于普通自行车图标，电动自行车图案通常有电池轮廓）。指示该车道仅供电动自行车通行。",tip:"口诀：蓝底+电动车图案=电自专用道。看图案区分——有电池轮廓的是电动自行车。"},
{id:679,cat:"signals",type:"judgment",q:"道路上的白色折线（斑马线前方锯齿状白线）表示前方有减速让行标志。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"斑马线前的锯齿状白线是「车行道纵向减速标线」，用于提示驾驶人前方有斑马线需减速。不是表示前方有减速让行标志——减速让行标志是红色倒三角。",tip:"口诀：斑马线前的锯齿白线=减速提示线。提醒你前面有人行横道，慢点开。"},
{id:680,cat:"signals",type:"choice",q:"高速公路上的「紧急停车带」标志是什么形状和底色？",opts:["黄底三角","绿底方形","蓝底方形","白底红圈"],ans:1,exp:"高速紧急停车带（港湾式停车带）标志为绿底方形，指示前方有紧急停车区域。仅供故障车辆临时停靠使用，不是服务区，不能长时间停留。",tip:"口诀：绿底方形=高速紧急停车带。只给故障车临时停，不是休息区。"},
{id:681,cat:"signals",type:"judgment",q:"电子可变信息标志（LED显示屏）显示的限速、车道指示等内容，与固定的交通标志标线具有同等法律效力。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"电子可变标志=根据实时交通状况动态调整的交通管理措施（如临时限速、车道关闭等），与固定标志具有同等法律效力，驾驶人应当遵守。常见于高速公路上方龙门架。",tip:"口诀：电子显示屏=实时的交通指令，必须遵守。和固定标志一样有效。"},
{id:682,cat:"signals",type:"choice",q:"当信号灯为非箭头灯（圆形灯）且为红灯时，以下哪种情况下右转弯是允许的？",opts:["任何情况下都可以右转","在确保不妨碍被放行车辆和行人通行时可以右转","红灯时一律不得右转","只有深夜才能右转"],ans:1,exp:"圆形红灯=可以右转（前提：不妨碍被放行车辆和行人+无禁止右转标志）。红色右转箭头灯=严禁右转。圆形和箭头逻辑不同。",tip:"口诀：圆红灯=可右转（注意让行）；红右箭头=禁止右转。圆的松，箭头的严。"},
{id:683,cat:"signals",type:"choice",q:"以下哪种情况属于违反交通信号灯？",opts:["黄灯亮时已越过停止线的车辆继续通行","绿灯亮时前方拥堵仍驶入路口","红灯亮时在停止线前停车","绿灯亮时正常通行"],ans:1,exp:"「闯绿灯」也属于违反交通信号。即使绿灯亮起，如果前方路口拥堵、车辆无法一次性通过，仍不得进入路口——应停在停止线外等候。",tip:"口诀：绿灯+路口堵=不能再进（闯绿灯也违法）。信号灯不仅是颜色，还要看路况。"},
{id:684,cat:"signals",type:"judgment",q:"人行横道信号灯绿灯闪烁时，禁止行人进入人行横道，但已进入者可以继续通过或在道路中心线处停留。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"人行绿灯闪烁=禁止新进入人行横道+已进入者可继续通过或在中心线等候。与机动车的黄灯逻辑一致——闪烁=过渡信号，提醒即将变灯。",tip:"口诀：人行绿灯闪=别进了（马上变红灯）。已经在里面的继续走或中心线等。"},
{id:685,cat:"signals",type:"choice",q:"高速公路出口的减速车道上的标线特征是什么？",opts:["白色实线","白色虚线与主线车道分隔，逐渐变宽形成独立车道","黄色双实线","导流线"],ans:1,exp:"减速车道以白色虚线与主线分隔，从主线右侧逐渐分离变宽，形成独立减速车道，驾驶人可提前变入减速车道，在驶入匝道前将速度降低至匝道限速。",tip:"口诀：减速车道=白虚线分隔+逐渐变宽。从这道拐出去，在出去前把速度降下来。"},
{id:686,cat:"signals",type:"judgment",q:"道路上白色实线（同向车道分界线）在任何情况下都不得跨越。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"白色实线=同向车道分隔线，不得跨越变道。这是基本的车道行驶规则。只有在虚线处（白色虚线）才允许变道。记住：白实=不能跨，白虚=可跨。",tip:"口诀：白实线=禁跨变道，白虚线=可变道。「实心」不能碰，「空心」可以过。"},
{id:687,cat:"signals",type:"choice",q:"设置在学校、幼儿园附近的警告标志有什么特征？",opts:["没有特殊标志","黄底三角内含两个儿童图案","蓝底方形","绿底圆形"],ans:1,exp:"「注意儿童」标志=黄底三角+两个儿童行走的黑色图案。设置在学校、幼儿园、少年宫等儿童频繁出入路段前方，提示驾驶人减速慢行，随时准备停车让行。",tip:"口诀：黄三角+两个小孩=注意儿童。看到这个标志=学校附近=30码以下慢行。"},
{id:688,cat:"signals",type:"choice",q:"当交通警察发出停止信号时，车辆应停在什么位置？",opts:["任意位置","停止线以外，无停止线的停在路口以外","越过停止线","停止线内"],ans:1,exp:"交警发出停止信号时，应依次停在停止线以外；无停止线的停在路口以外。与红灯停止规则一致。交警手势的权威高于信号灯。",tip:"口诀：交警让停=有停止线停线后，无停止线停路口外。"},
{id:689,cat:"signals",type:"judgment",q:"交通警察发出靠边停车手势信号时，车辆应当靠道路右侧停车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"交警靠边停车手势（右臂向右前方平伸+左臂向左前方摆动）=示意车辆靠道路右侧停车。驾驶人看到此手势应立即打右转向灯、靠道路右侧安全停车。",tip:"口诀：交警让靠边停=打右灯+靠右停下。配合检查或接受处理。"},
{id:690,cat:"signals",type:"choice",q:"路面上的公交车专用道标线是什么颜色和特征？",opts:["白色实线","黄色虚线","黄色实线并标注「公交车」字样","蓝色实线"],ans:2,exp:"公交专用道=黄色实线（或虚线）+路面标注「公交车」或「公交专用」字样+配合交通标志。其他车辆在专用时段内不得驶入。",tip:"口诀：公交道=黄线+「公交车」字样。看清专用时间，非高峰可借用。"},
{id:691,cat:"signals",type:"judgment",q:"高速公路上的绿色紧急电话标志表示前方有紧急求助电话，供驾驶人在紧急情况下使用。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速绿色紧急电话标志=提示前方有SOS紧急电话。高速公路每隔一定距离（通常1-2公里）设置紧急电话，供驾驶人在车辆故障、事故等紧急情况下免费使用报警求助。",tip:"口诀：高速绿牌+SOS电话=紧急求助电话。手机没信号时用这个。"},
{id:692,cat:"signals",type:"choice",q:"在雨雪雾天气中，高速公路可变限速标志显示的速度与固定限速标志不同时，应以哪个为准？",opts:["永远以固定标志为准","以可变限速标志为准","取两者的平均值","不用遵守"],ans:1,exp:"可变限速=根据实时天气和交通状况动态调整的速度限制，效力等同于甚至高于固定限速。恶劣天气时电子屏显示的临时限速必须遵守——这是根据当前路况安全评估的科学限速。",tip:"口诀：电子临时限速=当前路况的安全速度。固定标志是晴天用的，雨天看电子的。"},
{id:693,cat:"signals",type:"judgment",q:"在没有交通信号的道路上，遇到交通警察指挥时，应当按照交通警察的指挥通行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"无论有无信号灯，交警现场指挥的效力始终最高。交警>信号灯>标志>标线，法定优先顺序在任何道路上不变。",tip:"口诀：有交警听交警——在任何道路上交警指挥永远第一。"},
{id:694,cat:"safe",type:"choice",q:"安全跟车距离的「两秒规则」是指什么？",opts:["与前车保持2米距离","当前车通过某固定点时，本车至少2秒后才到达同一点","与前车保持2个车身距离","每次跟车不超过2分钟"],ans:1,exp:"两秒规则=国际通用的安全跟车距离判断法。前车经过一个参照物（如路牌）后，本车至少数2秒（默念「一千零一、一千零二」）才到达同一参照物。天气不好时延长至3-4秒。",tip:"口诀：2秒规则——前车过参照点后你数2秒才到。雨雪天用3-4秒。"},
{id:695,cat:"safe",type:"judgment",q:"驾驶机动车在雨天应当适当降低车速，增大与前车的安全距离。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"雨天路面湿滑，制动距离延长1.5-2倍，视野受限。应降低车速（比平时慢10-20km/h），拉大跟车距离（平时的2倍以上），避免急刹和急打方向。",tip:"口诀：雨天三宝——慢、远、稳。慢10-20码，拉2倍车距。"},
{id:696,cat:"safe",type:"choice",q:"超车时应从被超车的哪一侧超越？",opts:["右侧","左侧","任何一侧都可以","根据路况决定"],ans:1,exp:"中国实行右侧通行（靠右行驶）制度，超车须从左侧超越。左侧是超车道，右侧超车属于违法行为。唯一例外：前车正在左转弯且占据左侧车道时，可从右侧超越。",tip:"口诀：超车从左超——中国靠右走，快车左边超。右侧超车=违法。"},
{id:697,cat:"safe",type:"choice",q:"以下哪种情况可以超车？",opts:["前车正在左转弯","行经人行横道","在宽阔平直路段、视线良好、有超车条件时","铁路道口附近"],ans:2,exp:"超车条件：宽阔平直+视线良好+有足够超车距离+前车未在左转/超车+对向无来车。前车正在左转/超车/掉头时、在人行横道/道口/路口/弯道/坡道/隧道等危险路段均不得超车。",tip:"口诀：可以超=路宽+视线好+条件够+前车没在转弯超车。安全超车的四个前提。"},
{id:698,cat:"safe",type:"judgment",q:"驾驶机动车在高速公路上变更车道时，应提前开启转向灯，观察后视镜确认安全后迅速变道。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"高速变道应提前3秒以上打转向灯→观察后视镜+盲区→确认安全→平稳变道。注意「平稳」而非「迅速」——突然变道容易导致失控或被后车追尾。",tip:"口诀：高速变道=早打灯（3秒+）+看镜看盲区+平稳打方向。不是突然甩方向。"},
{id:699,cat:"safe",type:"choice",q:"驾驶机动车在交叉路口左转弯时，正确的做法是什么？",opts:["转小弯，紧靠路口中心点左侧通过","转大弯，靠路口中心点左侧通过","随意转弯","走内侧车道"],ans:1,exp:"左转弯应靠路口中心点左侧转大弯——给对面左转和直行车辆留出通行空间。右转弯则应转小弯紧靠右侧。左转大弯，右转小弯。",tip:"口诀：左转转大弯（绕中心点左侧），右转转小弯（靠路边）。大弯不影响对向车，小弯不占别人道。"},
{id:700,cat:"safe",type:"judgment",q:"驾驶机动车在没有中心隔离设施或中心线的道路上会车时，应减速靠右，与其他车辆和行人保持安全距离。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"窄路会车=减速靠右+保持安全横向距离。必要时空出位置让对方先行。有障碍方让无障碍方先行；坡道下坡让上坡先行。",tip:"口诀：窄路会车=减速+靠右+保持间距。能过就慢过，不能过就让。"},
{id:701,cat:"safe",type:"choice",q:"驾驶机动车在隧道内行驶时，以下哪项是正确的？",opts:["开启远光灯","开启近光灯，不得超车和停车","可以变更车道","为省电关闭所有灯光"],ans:1,exp:"隧道=近光灯+不超车+不倒车+不掉头+不停车（紧急除外）。隧道内光线暗、空间窄、逃生通道有限，任何违规操作都可能引发连锁事故。",tip:"口诀：隧道里=开近光+不超车+不倒不掉不停。进隧道老实跟着走。"},
{id:702,cat:"safe",type:"judgment",q:"驾驶机动车遇前方交通拥堵排队时，可以借道超车或占用对面车道穿插等候。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"拥堵时加塞插队一次记3分。排队等候是基本驾驶素养，加塞不仅违法而且破坏通行效率、增加刮擦风险。",tip:"口诀：堵车别加塞=3分。排队是规矩，插进去快不了多少。"},
{id:703,cat:"safe",type:"choice",q:"车辆在路边临时停车时，以下做法正确的是？",opts:["停在人行横道上","紧靠道路右侧，驾驶人不得离车，不得妨碍交通","停在公交站内","停在消防通道上"],ans:1,exp:"临时停车=紧靠右侧+人不离车+不妨碍交通+即停即走。禁止在斑马线、公交站30米内、路口50米内、消防通道、盲道等位置停车。",tip:"口诀：临停=靠右+人不走+不碍事。禁止在斑马线/公交站/路口/消防通道/盲道停。"},
{id:704,cat:"safe",type:"choice",q:"驾驶机动车行经人行横道时，应当怎么做？",opts:["鸣喇叭催促行人","加速通过","减速行驶，遇行人正在通过时应停车让行","保持原速通过"],ans:2,exp:"斑马线=减速→有行人=停车。不礼让行人一次记3分。文明礼让既是法律也是道德——斑马线前的一脚刹车可能挽救一条生命。",tip:"口诀：斑马线=减速+有人就停。不让人=3分+可能伤人。"},
{id:705,cat:"safe",type:"judgment",q:"夜间会车时，应当在距对向来车150米以外将远光灯改为近光灯。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"会车150米改近光灯=法定安全距离。远光灯炫目使对向驾驶人短暂失明（约2-3秒），在这段时间车辆已盲开数十米。跟车行驶时也应使用近光灯。",tip:"口诀：会车150米改近光。远光=盲对向司机2-3秒=盲开几十米=危险。"},
{id:706,cat:"safe",type:"choice",q:"驾驶机动车在夜间通过无交通信号灯控制的交叉路口时，应如何使用灯光？",opts:["使用远光灯照射四方","交替使用远近光灯示意","关闭所有灯光","只使用示廓灯"],ans:1,exp:"夜间过无灯路口=交替闪远近光灯。目的是提醒其他方向来车和行人注意你的存在。通过急弯、坡路、拱桥、人行横道时同样适用。",tip:"口诀：夜过无灯路口=闪灯（远近交替）。闪灯=告诉别人「我来了」。"},
{id:707,cat:"safe",type:"judgment",q:"驾驶机动车行经公交车站时，应减速慢行，注意公交车辆起步和乘客从公交车前方突然横穿马路。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"公交车站=减速+观察公交车动态+注意下车乘客。公交车体积大形成盲区，下车乘客可能从公交车头前方突然跑出（俗称鬼探头），应特别注意。",tip:"口诀：过公交站=减速+防鬼探头（人从车头前突然窜出）。公交车是巨大的移动盲区。"},
{id:708,cat:"safe",type:"choice",q:"驾驶机动车准备进入环形路口（环岛）时，正确的做法是什么？",opts:["加速进入","让已在环岛内行驶的车辆先行","抢在环岛内车辆前面进入","鸣喇叭后进入"],ans:1,exp:"环岛=「先出后进」原则——进入环岛前让已在环岛内行驶的车辆先行。驶出环岛时提前开右转向灯。进入时不需打左转灯（视为直行）。",tip:"口诀：进环岛让岛里的车（先出后进）。出环岛打右灯。"},
{id:709,cat:"safe",type:"judgment",q:"驾驶机动车在没有中心线的狭窄道路上遇到对向来车时，下坡车应让上坡车先行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"窄路坡道会车=下坡让上坡。因为上坡车停车后重新起步困难且有后溜风险。但如果下坡车已行至坡中而上坡车尚未上坡，则上坡车让下坡车先行。",tip:"口诀：坡道会车下让上（上坡起步难）。除非下坡车已到坡中间——先到坡中的有优先权。"},
{id:710,cat:"safe",type:"choice",q:"驾驶机动车在雨天遇到路面水坑时，正确的做法是什么？",opts:["加速冲过去","减速绕过水坑或低速匀速通过，注意避让行人和非机动车","紧急刹车","不管不顾正常通过"],ans:1,exp:"雨天遇水坑=减速+能绕则绕+不能绕低速匀速通过。避免溅水影响行人和非机动车——溅水到行人身上不仅是文明问题，严重时可能造成行人惊吓摔倒从而承担法律责任。",tip:"口诀：路上有水坑=慢过或绕过，别溅行人一身水。溅水到人=没素质+可能惹官司。"},
{id:711,cat:"safe",type:"choice",q:"发动机熄火后转向助力和制动助力会怎样变化？",opts:["不受影响","转向变重、制动踏板变硬，但仍可操作","完全失效","自动切换为手动模式"],ans:1,exp:"熄火后转向助力泵和制动助力泵停止工作，方向变重（需用更大力气打方向）、刹车变硬（需用更大力气踩刹车）。但仍可操作——应保持冷静，用力操作方向并用剩余惯性靠边停车。",tip:"口诀：熄火=方向变重+刹车变硬，但还能用。用劲打方向+使劲踩刹车+靠边停。"},
{id:712,cat:"safe",type:"judgment",q:"驾驶机动车时，驾驶人可以穿拖鞋、高跟鞋（跟高4cm以上）或赤脚。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"穿拖鞋刹车反应变慢（鞋容易脱落卡住踏板）、高跟鞋跟部容易卡在踏板缝隙、赤脚踩踏板力度控制不准——均属于妨碍安全驾驶的违规行为。建议车上备一双平底鞋。",tip:"口诀：开车禁穿拖鞋/高跟鞋/赤脚！平底鞋是最佳选择，车上常备一双。"},
{id:713,cat:"safe",type:"choice",q:"驾驶人下车时，以下哪种开门方式最安全？",opts:["直接推门下车","用靠近车门的手开门（如左手开左边门）","用远离车门的手开门（荷式开门法——右手开左边门，身体自然转动观察后方）","快速开门减少被撞几率"],ans:2,exp:"荷式开门法=用远离车门的手开门（左门用右手开，右门用左手开），迫使身体自然转动→同时视线投向侧后方→自然地观察到后方来车和行人。是预防「开门杀」的标准做法。",tip:"口诀：荷式开门法——右手开左门，身体自然转，看清再开门。防开门杀的神技。"},
{id:714,cat:"safe",type:"judgment",q:"驾驶机动车在高速公路上行驶时，非紧急情况可以在应急车道行驶或停车。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"应急车道=生命通道，非紧急情况严禁行驶或停车。违法占用应急车道一次记9分。紧急情况指车辆故障无法行驶、人员突发危及生命的疾病等。普通疲劳、查看导航不属于紧急情况。",tip:"口诀：应急车道=生命通道。非急占用=9分。困了累了不算紧急！"},
{id:715,cat:"safe",type:"choice",q:"防御性驾驶的核心原则是什么？",opts:["开得更快","预见潜在危险并提前采取预防措施","始终跟在其他车后面","只在白天开车"],ans:1,exp:"防御性驾驶=提前预见危险+提前采取措施。具体包括：保持安全距离、经常扫描路面（每5-8秒看后视镜）、预判其他道路使用者的意图、远离大型车辆盲区、适当使用灯光和喇叭沟通意图。",tip:"口诀：防御性驾驶=预见+预防。不只是自己不犯错，还要防别人犯错。"},
{id:716,cat:"safe",type:"judgment",q:"驾驶机动车在道路上行驶，应经常观察后视镜，了解车辆周围的交通状况，建议每5-8秒扫视一次后视镜。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"经常扫视后视镜（建议5-8秒一次）可以帮助驾驶人建立360度的交通感知，及时发现后方快速接近的车辆、盲区内的车辆等潜在危险。是防御性驾驶的重要习惯。",tip:"口诀：5-8秒扫一次镜子。建立360度感知，别只盯着前面。"},
{id:717,cat:"safe",type:"choice",q:"驾驶机动车遇到大货车右转时，小型车驾驶人应特别注意什么？",opts:["跟紧大货车节省燃油","远离大货车右侧盲区，因为大货车右转有内轮差","超到大货车前面","鸣喇叭提醒"],ans:1,exp:"大货车右转有「内轮差」——前轮通过的区域后轮压不到，形成月牙形危险区。行人和小型车在大货车右侧极容易被卷入后轮（俗称「死亡弯月」）。应远离大货车右侧至少3米以上。",tip:"口诀：大货车右转=死亡弯月。右侧=绝对禁地——远离3米以上！"},
{id:718,cat:"safe",type:"judgment",q:"驾驶机动车夜间会车，对向来车未关闭远光灯时，我方也应当开远光灯回敬。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"对方不关远光=我方视线右移看道路右侧边缘线（用边缘线定位）+适当减速+同时闪灯提醒。绝不开远光回敬——双方互射远光=双方都失明=极可能导致正面碰撞。",tip:"口诀：对方远光=看右边白线+减速+闪灯提醒。千万别对射——两瞎相撞。"},
{id:719,cat:"safe",type:"choice",q:"驾驶机动车行经学校区域时，以下哪种做法正确？",opts:["保持正常速度","减速慢行，注意观察学生和儿童动向，随时准备停车","加速通过","鸣喇叭驱散学生"],ans:1,exp:"学校区域=减速（通常限速30km/h）+高度注意儿童动向+随时准备制动。儿童行为不可预测（可能突然冲上马路），驾驶人应假设有儿童随时会从路边跑出来。",tip:"口诀：学校区域=30码以下+脚放刹车上。孩子不可预测，做好最坏打算。"},
{id:720,cat:"safe",type:"judgment",q:"驾驶机动车在冰雪路面行驶时，应保持比平时大3-4倍的安全车距。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"冰雪路面附着力约为干燥路面的1/4，制动距离延长3-10倍。所以安全车距应比平时大3-4倍。跟车过近在冰雪路面=追尾保证。",tip:"口诀：冰雪路车距=平时的3-4倍。冰面上刹车距离可能10倍——离远点。"},
{id:721,cat:"safe",type:"choice",q:"驾驶机动车行经视线不良的交叉路口时，正确的做法是什么？",opts:["加速通过减少危险时间","减速慢行，交替使用远近光灯（夜间）或鸣喇叭（白天）示意","靠左侧行驶","正常通过"],ans:1,exp:"视线不良路口=减速+闪灯（夜）/鸣笛（昼）+随时准备停车。看不到其他方向的来车=假设可能有车正在驶来。信号灯控制的路口按信号灯指示即可。",tip:"口诀：看不见=减速+闪灯/鸣笛+准备停。看不到的不代表不存在。"},
{id:722,cat:"safe",type:"judgment",q:"驾驶机动车上高速公路前应检查车辆状况，包括轮胎、灯光、制动、燃油/电量等。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"上高速前检查=轮胎（胎压、磨损、损伤）+灯光+制动+燃油/电量+机油+冷却液+雨刮器及玻璃水。高速故障极其危险——花5分钟检查可能避免一次致命事故。",tip:"口诀：上高速前=花5分钟绕车一圈检查。轮胎最重要+灯光+油量+制动。"},
{id:723,cat:"safe",type:"choice",q:"在高速公路上长时间驾驶感到疲劳时，正确的应对措施是什么？",opts:["打开车窗继续驾驶","选择最近的服务区或驶离高速停车休息至少20分钟","加速尽快到达目的地","喝咖啡或能量饮料继续驾驶"],ans:1,exp:"疲劳驾驶=4小时必停20分钟。感到疲劳时应立即驶入最近服务区或出口休息至少20分钟。开窗、喝咖啡等只能暂时缓解，不能根本消除疲劳。疲劳时反应速度下降50%以上，等同于醉酒状态。",tip:"口诀：累了困了=服务区睡20分钟。硬撑=疲劳驾驶=反应慢50%=拿命赌。"},
{id:724,cat:"safe",type:"judgment",q:"服用感冒药、抗过敏药等可能引起嗜睡的药物后不得驾驶机动车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"含抗组胺成分的感冒药、抗过敏药会引起嗜睡、反应迟钝等副作用，服药后驾车极其危险。药品说明书中标注「服药后不得驾驶机、车、船」的，应严格遵守。",tip:"口诀：吃了感冒药/过敏药=别开车。说明书上写了「忌驾车」就必须遵守。"},
{id:725,cat:"safe",type:"choice",q:"驾驶机动车夜间在照明良好的城市道路上行驶时，应使用什么灯光？",opts:["远光灯","近光灯","雾灯","危险报警闪光灯"],ans:1,exp:"城市道路照明良好=近光灯。远光灯仅在无路灯或照明不良路段、且无对向来车时使用。有路灯的路段使用远光会影响前车和对向车辆驾驶人。",tip:"口诀：有路灯=近光。远光只在又黑又没车的时候用。"},
{id:726,cat:"safe",type:"judgment",q:"高速公路同方向有3条车道的，左侧车道最低车速110km/h，中间车道最低90km/h，右侧车道最低60km/h。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"同向3车道=左110+中90+右60。同向2车道=左100+右60。同向4车道=左110+中左90+中右90+右60。记住差值：左快右慢，每道差20。",tip:"口诀：3车道=左110中90右60。2车道=左100右60。车道越多快慢分越细。"},
{id:727,cat:"safe",type:"choice",q:"驾驶机动车在路口右转弯时，遇到右侧有直行非机动车通过，应该如何做？",opts:["加速抢先右转","停车让非机动车先行","鸣喇叭催促非机动车","紧贴非机动车右侧通过"],ans:1,exp:"右转+直行非机动车=转弯让直行（非机动车也是直行方）。应停车让非机动车先通过后再转弯。与非机动车抢道极易发生碰撞，且机动车负主要或全部责任。",tip:"口诀：右转让直行非机动车。非机=弱势方，撞了全责大概率。"},
{id:728,cat:"safe",type:"choice",q:"驾驶机动车在高速公路上，同方向有2条车道的，大型客车和货车应在哪条车道行驶？",opts:["左侧快车道","右侧车道","两条车道都可以","应急车道"],ans:1,exp:"大车应靠右行驶——大型车辆限速低（最高100km/h），原则上在右侧车道行驶。超车时可借用左侧车道，超车完毕应立即驶回右侧车道。不得长期占用左侧快车道。",tip:"口诀：大车=靠右走。超车借左道，超完回右道。不占快车道。"},
{id:729,cat:"safe",type:"judgment",q:"驾驶机动车掉头时，可以在铁路道口、人行横道、隧道、窄桥等地点掉头。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"严禁在铁路道口、人行横道、隧道、窄桥、弯道、陡坡等危险路段掉头。有禁止掉头标志的路段同样不得掉头。掉头应选择道路宽阔、视线良好、不妨碍其他车辆通行的安全地点。",tip:"口诀：道口/人行道/隧道/窄桥/弯/坡=禁掉头。掉头=找安全地点。"},
{id:730,cat:"safe",type:"choice",q:"驾驶机动车在夜间通过急弯、坡路、拱桥、人行横道时，应如何使用灯光？",opts:["一直使用远光灯","交替使用远近光灯示意","关闭所有灯光","只使用示廓灯"],ans:1,exp:"夜间通过危险或视线不良特殊路段=交替闪远近光灯示意。目的是让其他交通参与者注意到你的存在。这是法定的灯光使用规定。",tip:"口诀：夜过弯/坡/桥/人行道/无灯路口=闪远近灯。让看不见你的人知道你来了。"},
{id:731,cat:"safe",type:"judgment",q:"驾驶机动车在交叉路口转弯时，应提前进入相应的导向车道，进入导向车道后不得变更车道。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"导向车道（路口实线车道）=进入后方向锁死不得变道。应提前根据行驶方向选择正确车道——左转进左转道、直行进直行道、右转进右转道。走错导向车道强行变道记1分。",tip:"口诀：进了导向车道=方向锁死。提前选好道，走错将错就错到下一路口再调整。"},
{id:732,cat:"safe",type:"choice",q:"驾驶机动车遇前方儿童在路边玩耍时，以下做法正确的是？",opts:["加速通过","鸣喇叭提醒","大幅减速，保持更大横向距离，做好儿童突然横穿的准备","正常通过"],ans:2,exp:"儿童行为不可预测——看到路边有儿童=立即大幅减速+保持更大横向距离+右脚放在刹车踏板上随时准备紧急制动。儿童可能随时毫无预兆地跑向道路。",tip:"口诀：路边孩子=脚上刹车就绪。家长看不住的孩子=你替他看。"},
{id:733,cat:"safe",type:"choice",q:"驾驶机动车在道路上正常行驶，后车持续跟车过近（有追尾风险）时，正确的应对方法是？",opts:["急刹车警告后车","逐渐减速或变道让后车先行","加速甩开后车","突然变道"],ans:1,exp:"被后车近距离跟车=不可急刹（会导致追尾）+逐渐减速（轻点刹车提示后车）+或打灯变道让其先行。让后面的「路怒症」过去，不与其纠缠。",tip:"口诀：后车跟太近=轻点刹车提醒+让他先走。不斗气，安全第一。"},
{id:734,cat:"safe",type:"judgment",q:"驾驶机动车在道路上行驶时，应主动避让执行紧急任务的特种车辆（警车、消防车、救护车、工程救险车），因避让产生的交通违法记录可申请撤销。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"遇执行紧急任务的特种车辆（开警报器+标志灯具）=立即避让（向右变道或靠边让出通道）。因此产生的闯红灯等违法记录，可凭行车记录仪录像向交管部门申请撤销。不避让=记3分。",tip:"口诀：特种车来=让路。因此违章可撤销。不让=3分。"},
{id:735,cat:"safe",type:"choice",q:"驾驶机动车在人行横道前应当减速，遇行人通过时应停车让行。这体现了什么原则？",opts:["效率优先","行人优先（弱势道路使用者保护原则）","机动车优先","速度优先"],ans:1,exp:"行人优先原则=行人是道路交通中的弱势方，法律给予特别保护。驾驶人应主动礼让行人——不礼让行人记3分。这也是文明驾驶的基本素养。",tip:"口诀：铁包肉让肉包铁。机动车让行人=法律+文明。"},
{id:736,cat:"safe",type:"judgment",q:"驾驶机动车遇到盲人或有行动障碍的行人时，应减速慢行，停车让行。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"遇残疾人、盲人（持白色手杖）、老年人、孕妇等行动不便的行人应减速慢行、主动停车让行。盲人持白色手杖过马路时任何车辆都应停车让行。",tip:"口诀：见盲人（白手杖）=必须停车让。弱势中的弱势，特别保护。"},
{id:737,cat:"safe",type:"choice",q:"驾驶机动车在山区道路上，下长坡连续使用刹车导致制动效能下降（热衰减）时，应如何应对？",opts:["继续使用刹车","抢挂低速挡利用发动机制动，同时寻找紧急避险车道","拉手刹","加速通过"],ans:1,exp:"下长坡刹车热衰减=立即抢挂低速挡用发动机制动→寻找紧急避险车道（上坡砂石路）。山区避险车道是专门为刹车失灵车辆准备的救命设施。平时下坡就应挂低挡用发动机制动，预防热衰减。",tip:"口诀：下坡刹车软了=抢低挡+找避险车道（上坡砂石路）。预防为主——下坡就用低挡发动机制动。"},
{id:738,cat:"safe",type:"choice",q:"驾驶机动车在高速公路上遇前方车辆突然变道或急刹车时，正确的做法是什么？",opts:["紧跟前车","立即急刹车并紧急变道躲避","紧握方向盘，采取点刹减速，同时观察后视镜判断是否可安全变道","加速绕过"],ans:2,exp:"高速前方突然变故=握紧方向+点刹减速（避免急刹被后车追尾）+快速扫视后视镜判断安全变道空间。紧急变道（高速躲闪）极易导致车辆失控侧翻——宁可追尾不翻车。",tip:"口诀：高速前车急刹=握紧+点刹+看镜。不猛打方向——翻车比追尾更致命。"},
{id:739,cat:"safe",type:"judgment",q:"驾驶机动车在交叉路口遇到交通拥堵时，即使绿灯亮起也不得进入路口。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"绿灯+路口堵=不得进入（「闯绿灯」违法）。应在停止线外等候，待路口净空后再通行。绿灯是准许通行信号，但路口拥堵时通行会导致路口锁死加重拥堵。",tip:"口诀：绿灯面前也需等——路口堵了别进。进去了出不来=堵死路口。"},
{id:740,cat:"safe",type:"choice",q:"驾驶机动车从辅路进入主路时，正确的做法是什么？",opts:["直接并入主路","在加速车道内提速，观察左后视镜确认安全后开启左转向灯并入","停在辅路和主路之间等待","鸣喇叭后并入"],ans:1,exp:"辅路进主路=加速车道内提速至与主路车流接近的速度→观察左后视镜+确认安全→打左转向灯→平稳并入主路。不得直接切入主路（速度差大容易追尾），也不得在加速车道尽头停车等待。",tip:"口诀：辅进主=加速道提速→看镜→打灯→平稳并入。融入车流而非切断车流。"},
{id:741,cat:"safe",type:"judgment",q:"驾驶机动车遇到骑行自行车的人，应与其保持1.5米以上的横向安全距离。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"机动车超越非机动车时，应保持1.5米以上横向安全距离。自行车骑行者可能因路面不平、侧风等因素突然偏向机动车道，足够的横向距离提供安全缓冲。",tip:"口诀：超自行车=横向距离1.5米以上。非机动车不稳定，给足安全空间。"},
{id:742,cat:"safe",type:"choice",q:"驾驶机动车在雨天夜间行驶应注意什么？",opts:["开启远光灯看得更清","雨天路面积水反光，应注意辨别路面标线和障碍物，减速慢行","加速通过","关闭灯光"],ans:1,exp:"雨天+夜间=路面反光严重（灯光照亮水面造成眩光）+视野极差+标线看不清。应减速慢行、仔细辨别路面状况、注意积水深度。非必要时尽量避免雨天夜间出行。",tip:"口诀：雨+夜=反光+看不清=慢上加慢。路面亮晶晶的不是灯光效果，是水。"},
{id:743,cat:"safe",type:"judgment",q:"驾驶机动车倒车时，应当察明车后情况、确认安全后方可倒车。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"倒车应：①下车或在车内全面观察车后情况→②确认无行人、车辆、障碍物→③缓慢倒车同时持续观察。不得在铁路道口、交叉路口、单行路、桥梁、急弯、陡坡、隧道中倒车。",tip:"口诀：倒车先看后+确认安全+慢倒。不安全宁可不倒。"},
{id:744,cat:"safe",type:"choice",q:"驾驶机动车超车完成后，应如何安全驶回原车道？",opts:["立即驶回","与后车拉开安全距离后，开启右转向灯，确认安全后平稳驶回","加速驶回","从右侧驶回"],ans:1,exp:"超车完成=从右后视镜看到被超车的整个车头（表示已拉开足够距离）→开启右转向灯→再次确认安全→平稳向右驶回原车道。不可立即驶回（容易「别」到被超车辆）。",tip:"口诀：超完=后视镜看到被超车「全脸」→打右灯→安全回原道。别刚超过去就切回来。"},
{id:745,cat:"safe",type:"judgment",q:"驾驶机动车在道路上发生轻微刮擦事故，车辆可以移动的，应拍照固定证据后迅速撤离现场，到不妨碍交通的地方协商或报警。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"小事故=拍照取证（全景+碰撞部位+细节）→撤离到安全地带→协商或报警。轻微事故不撤离造成拥堵的，双方均可被罚200元。",tip:"口诀：小刮擦=拍照→挪车→再协商。堵在路上双方都罚。"},
{id:746,cat:"safe",type:"choice",q:"驾驶机动车夜间通过照明不良且无对向来车的路段时，应使用什么灯光？",opts:["近光灯","远光灯","雾灯","示廓灯"],ans:1,exp:"无照明+无来车=远光灯（看得远）。但一旦遇到对向来车应在150米外切换为近光灯；跟车行驶时也应用近光灯（防止炫目前车驾驶人）。",tip:"口诀：又黑又没车=远光。有来车=150米改近光。跟车=近光。"},
{id:747,cat:"safe",type:"judgment",q:"儿童乘车时应使用儿童安全座椅，12周岁以下儿童不得坐在副驾驶位置。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"12周岁以下（身高140cm以下）儿童应使用儿童安全座椅并坐在后排。副驾驶安全气囊弹出时的冲击力足以对儿童造成严重伤害甚至死亡。安全座椅安装在后排是国际通用安全标准。",tip:"口诀：12岁以下+140cm以下=后排+安全座椅。副驾气囊=儿童杀手。"},
{id:748,cat:"safe",type:"choice",q:"驾驶机动车遇到前方道路施工时，以下做法正确的是？",opts:["加速通过施工区","按照施工标志指示减速慢行、注意施工人员和设备、不得随意变道超车","逆行绕过施工区","鸣喇叭催促施工人员"],ans:1,exp:"施工路段=按标志减速慢行（通常限速30km/h）+注意施工人员+不变道+不超车。施工工人是道路上的高风险群体——你的减速是对他们生命安全的保障。",tip:"口诀：施工区=慢+看标志+不超车+注意工人。工人在用命修路，你慢一点有什么不行？"},
{id:749,cat:"operation",type:"choice",q:"手动挡汽车起步时正确的操作顺序是？",opts:["踩离合→挂1挡→松手刹→慢抬离合同时轻踩油门","直接挂挡踩油门","先踩油门再挂挡","松手刹→挂挡→踩离合"],ans:0,exp:"手动挡起步=踩离合→挂1挡→松手刹→慢抬离合至半联动（车身微抖）→稳住离合轻踩油门→完全松开离合正常行驶。关键在「慢抬离合」——抬太快会熄火。",tip:"口诀：起步=踩离合→挂一挡→松手刹→慢抬离合+轻给油。慢抬是关键，快抬就熄火。"},
{id:750,cat:"operation",type:"judgment",q:"自动挡汽车停车时，正确的顺序是：踩刹车→挂P挡→拉手刹→熄火。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"正确停车顺序=踩刹车停稳→拉手刹→挂P挡→熄火。先拉手刹再挂P挡可以避免车辆微动导致变速箱锁止机构受力（P挡锁止钩承受车身重量容易损坏）。先P后手刹=变速箱受力。",tip:"口诀：自动挡停车=踩住→拉手刹→挂P→熄火。先手刹后P挡，保护变速箱。"},
{id:751,cat:"operation",type:"choice",q:"手动挡汽车下长坡时，正确的操作方法是什么？",opts:["空挡滑行省油","挂低速挡利用发动机制动，减少刹车使用","一直踩刹车控制速度","挂最高挡让车滑行"],ans:1,exp:"下长坡=挂低挡（2挡或3挡）+发动机制动。利用发动机的阻力控制车速，减少刹车片摩擦频率，防止刹车过热导致热衰减甚至制动失效。空挡滑行极其危险——失去发动机制动，全依赖刹车=刹车迟早过热失灵。",tip:"口诀：下坡挂低挡=让发动机帮你刹车。空挡滑行=全靠刹车=会过热失灵。"},
{id:752,cat:"operation",type:"judgment",q:"自动挡汽车等红灯短时间停车（30秒内）可保持D挡踩刹车；长时间停车（超过30秒）建议挂N挡拉手刹。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"短停D挡踩刹车=变速箱油温微升但可接受；长停N挡+手刹=减少变速箱负荷和油温升高。长时间D挡憋着会使变速箱油温升高、加剧磨损。",tip:"口诀：等红灯：短（<30秒）=D挡踩刹车；长（>30秒）=N挡+手刹。保护变速箱从小习惯开始。"},
{id:753,cat:"operation",type:"choice",q:"仪表板上的ABS（防抱死制动系统）警告灯在正常行驶中亮起，表示什么？",opts:["ABS系统正常工作","ABS系统出现故障，普通制动仍有效但紧急制动时车轮可能抱死","需要更换刹车片","制动液缺少"],ans:1,exp:"ABS灯亮=防抱死系统故障。普通制动仍有效（刹车还能用），但紧急制动时ABS不会介入，车轮可能抱死导致方向失控（无法转向避开障碍物）。应尽快检修。",tip:"口诀：ABS灯亮=防抱死坏了。普通刹车还能用，但急刹时车轮可能抱死→方向失控。快修。"},
{id:754,cat:"operation",type:"choice",q:"仪表板上机油压力报警灯（红色油壶图标）亮起时，应当怎么做？",opts:["继续行驶到目的地","立即靠边停车熄火，检查机油量并呼叫救援","加速行驶到修理厂","忽略该指示灯"],ans:1,exp:"机油红灯=机油压力不足（可能缺机油或机油泵故障）。继续行驶=几分钟内发动机因缺润滑而拉缸、抱瓦→发动机报废。正确做法=立即安全停车熄火→检查机油尺→视情况添加机油或呼叫拖车。",tip:"口诀：机油红灯=立刻停车熄火！再开几分钟=发动机报废。机油是发动机的血液。"},
{id:755,cat:"operation",type:"judgment",q:"仪表板上水温报警灯（红色温度计图标）亮起时，应立即熄火以防止发动机进一步损坏。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"水温红灯亮=发动机过热。不应立即熄火——应靠边停车后让发动机怠速运转（保持水泵循环冷却液），打开暖风帮助散热，等温度降低后再熄火检查。立即熄火=水泵停转=局部温度更高=可能造成更严重损坏。",tip:"口诀：水温高=停车怠速降温（别马上熄火！）。开暖风帮散热，等温度下来再熄。"},
{id:756,cat:"operation",type:"choice",q:"驾驶机动车时正确的方向盘握法是什么？",opts:["单手握住方向盘","双手分别握在方向盘的9点和3点位置（或8点和4点）","双手握在方向盘顶部","一只手握方向盘一只手放变速杆上"],ans:1,exp:"正确握法=双手分别握9点和3点（或8点和4点），推拉式转向。9-3位置可获得最大转向角度和最佳控制力，同时安全气囊弹出时有安全空间。单手握方向盘在紧急情况下无法精确控制方向。",tip:"口诀：方向盘9点3点（或8点4点），双手推拉不打交叉。单手开车=紧急躲不了。"},
{id:757,cat:"operation",type:"judgment",q:"驾驶机动车时应将座椅头枕调整到与头部顶部齐平的位置。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"头枕正确高度=头枕中心与驾驶人后脑中部（耳朵上缘）齐平或略高。头枕的主要功能是在追尾碰撞时限制头部后仰幅度，防止颈椎挥鞭伤。与头顶齐平位置太低，无法有效保护颈椎。",tip:"口诀：头枕=中间对准后脑勺（耳朵上缘）。防追尾挥鞭伤的关键安全装备。"},
{id:758,cat:"operation",type:"choice",q:"自动挡汽车从P挡挂入其他挡位时，应如何操作？",opts:["直接用力挂挡","踩住制动踏板后再挂挡","加油门时挂挡","快速连续挂挡"],ans:1,exp:"自动挡P挡→其他挡=必须踩刹车才能挂出（驻车锁止机构需要解除）。不踩刹车硬拉可能损坏换挡机构。R挡、D挡之间切换也应在车辆停稳时操作。",tip:"口诀：P挡出来=踩刹车。N和D之间切换不用踩刹车（但低速时最好也踩）。"},
{id:759,cat:"operation",type:"judgment",q:"自动挡汽车在坡道上停车时，除挂P挡和拉手刹外，还应将方向盘向路边方向打。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"坡道停车三重保险：手刹+P挡+方向打向路边（上坡左打、下坡右打）。万一溜车，车轮会撞到路边石而停下，不会一直溜到坡底。另可用石块塞住车轮。",tip:"口诀：坡道停车=手刹+P挡+打方向（上左、下右）。三重保险防溜车。"},
{id:760,cat:"operation",type:"choice",q:"检查发动机机油液位时，正确的做法是什么？",opts:["发动机运转时检查","将车停在平坦地面、发动机熄火等待5-10分钟后、拉出机油尺擦拭干净再插入检查","热车刚熄火时立即检查","随便什么时候检查都可以"],ans:1,exp:"查机油=平地+熄火等5-10分钟（让机油流回油底壳）+机油尺擦干净+重新插入到底+拉出看液位（应在上下刻度之间）。热车立即查或发动机运转中查都不准确。",tip:"口诀：查机油=平地+冷车（等5分钟）+尺子擦了再测。上下刻度之间=正常。"},
{id:761,cat:"operation",type:"choice",q:"仪表板上的充电指示灯（电池图标）在行驶中亮起，表示什么？",opts:["蓄电池正在充电","充电系统故障（发电机不发电），车辆依靠蓄电池剩余电量行驶","蓄电池电量已充满","应该更换电池"],ans:1,exp:"电池灯亮=发电机不发电或充电线路故障。车辆此时消耗蓄电池储存的电量，应关闭不必要用电设备（空调、音响、车灯等），尽快驶往修理厂。电量耗尽后车辆将熄火无法启动。",tip:"口诀：电池灯亮=发电机罢工了，在用蓄电池的电。关电器赶紧修，电用完了就趴窝。"},
{id:762,cat:"operation",type:"judgment",q:"驾驶机动车时右脚同时控制油门和刹车踏板（右脚跟着地、脚掌在两个踏板间切换），左脚放在休息踏板上。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"自动挡正确方式=右脚单脚控制油门和刹车（以脚跟为支点、脚掌在油门和刹车间旋转切换），左脚放在左侧休息踏板。两个踏板一个脚控制，避免同时踩下。左脚刹车是错误方式。",tip:"口诀：自动挡=右脚管双踏板（油门+刹车）。一个脚踩一个，不会同时踩。"},
{id:763,cat:"operation",type:"choice",q:"手动挡汽车换挡时，以下哪种做法是正确的？",opts:["低头看挡位","踩下离合器踏板到底后换挡","不踩离合直接换挡","越级换挡（如1挡跳过2挡直接挂3挡）"],ans:1,exp:"换挡=踩离合到底（分离彻底）→挂入目标挡位→平稳松开离合。低头看挡位极其危险（视线离开路面=盲开）；不踩离合换挡=打齿轮；越级换挡在特定情况下可以（如3挡直接升5挡），但非标准操作。",tip:"口诀：换挡=离合踩到底+眼看前方不要低头。「低头=盲开=危险」。"},
{id:764,cat:"operation",type:"judgment",q:"发现轮胎上卡有大石子等异物时，应及时清除以保证轮胎性能和安全。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"胎纹中的石子=影响排水性能（雨天抓地力下降）+高速时可能甩出伤人伤车+长时间压迫胎面造成局部磨损不均。应定期检查并清除胎面异物。",tip:"口诀：轮胎卡石子=排水差+可能飞出伤人。定期抠石子，小动作大安全。"},
{id:765,cat:"operation",type:"choice",q:"车辆行驶中制动踏板突然变软（制动力下降），应如何处理？",opts:["继续正常行驶","反复踩踏制动踏板尝试建立压力，同时抢挂低挡利用发动机制动，打开双闪尽快靠边停车","加速行驶寻找修理厂","拉手刹紧急制动"],ans:1,exp:"刹车变软=可能制动液泄漏或管路进空气。应：①反复猛踩刹车踏板尝试建立压力→②抢挂低挡用发动机制动减速→③开双闪提醒后车→④安全靠边停车→⑤呼叫救援。绝对不能继续行驶。",tip:"口诀：刹车软了=反复猛踩建压+抢低挡+开双闪+靠边。刹车问题不能犹豫。"},
{id:766,cat:"operation",type:"judgment",q:"自动挡汽车可以在下坡时将挡位置于N挡（空挡）滑行以节省燃油，这样不会损坏变速箱。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"自动挡空挡滑行=变速箱油泵可能停止供油或供油不足→内部零件因缺乏润滑和冷却而严重磨损→变速箱损坏。且失去发动机制动极其危险。任何情况严禁自动挡空挡滑行。",tip:"口诀：自动挡严禁N挡滑行！省不了几个油，要的是变速箱的命+你的命。"},
{id:767,cat:"operation",type:"choice",q:"冬季发动机启动困难时，以下做法正确的是？",opts:["持续长时间打火","每次打火不超过5秒，间隔15秒以上再次尝试","用力踩油门帮助启动","用开水浇发动机"],ans:1,exp:"冬季启动困难=每次打火不超过5秒+间隔15秒以上再试。长时间连续打火会耗尽蓄电池电量并使启动机过热损坏。可关闭不必要电器减少电量消耗。必要时使用应急启动电源。",tip:"口诀：冬天打不着=每次5秒+等15秒再试。别一直拧着钥匙，电瓶和启动机受不了。"},
{id:768,cat:"operation",type:"judgment",q:"车辆行驶中发动机突然熄火，转向和制动助力会完全消失，车辆将无法转向和制动。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"熄火后转向助力和制动助力泵停止工作，转向变重、刹车变硬，但仍可操作——只是需要更大的力气。并非完全消失。应冷静用力操作方向+利用剩余惯性和制动将车安全靠边。",tip:"口诀：熄火=方向重+刹车硬（不是没了！）。用劲打方向+使劲踩刹车+靠边停。"},
{id:769,cat:"operation",type:"choice",q:"行车前绕车一周检查，应重点检查哪些项目？",opts:["只看车牌","轮胎状态（胎压、磨损、损伤）、灯光、车身是否有障碍物、车底是否漏液","只看车窗是否干净","只检查反光镜"],ans:1,exp:"开车前绕车检查=①四个轮胎（胎压、磨损、胎面异物）→②灯光（大灯、转向灯、刹车灯）→③车身周围是否有儿童、宠物、障碍物→④车底是否有漏液痕迹→⑤车牌是否清晰。5分钟检查可能避免一次事故。",tip:"口诀：上车前绕一圈——看轮胎+看灯+看车周围+看车底+看车牌。老司机的习惯。"},
{id:770,cat:"operation",type:"judgment",q:"轮胎胎压应按照轮胎侧面标注的最大压力值充气，以确保最佳性能。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"胎压应按照车辆厂家推荐值充气（标注在驾驶位车门框或油箱盖内侧的标签上），而非轮胎侧面标注的最大压力值。轮胎侧壁标注的是「最大允许胎压」而非推荐胎压。按最大压力充气=胎压过高=爆胎风险+舒适性下降。",tip:"口诀：胎压看车门框标签（厂家推荐值），不看轮胎侧壁（那是最大值）。乱充=不是过软就是过硬。"},
{id:771,cat:"operation",type:"choice",q:"车辆涉水时，应如何操作？",opts:["加速冲过去","挂低速挡、保持匀速、中途不换挡不停车，缓慢通过","空挡滑行通过","高速挡通过"],ans:1,exp:"涉水=低速挡（1或2挡）+匀速缓慢通过+中途不换挡不松油门不停车。目的是保持排气压力防止水倒灌入排气管，且避免因操作导致发动机转速变化引起进水。涉水后应轻踩刹车排干制动器水分。",tip:"口诀：涉水=低挡+匀速+中途不停不换不松油。慢过水，稳字当头。"},
{id:772,cat:"operation",type:"judgment",q:"车辆涉水时发动机熄火，应立即重新启动发动机尝试驶出积水区。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"涉水熄火=严禁重新启动！（水可能已进入气缸，再次启动=水不可压缩→活塞上行顶弯连杆→发动机报废）。正确做法：不启动→打开双闪→撤离到安全地带→拨打救援电话→等待专业人员处理。",tip:"口诀：涉水熄火=千万别再打火！一打火发动机就废了。等拖车来救。"},
{id:773,cat:"operation",type:"choice",q:"驾驶手动挡汽车在坡道上起步时，为防止后溜，应如何操作？",opts:["快速松开离合和刹车","拉紧手刹，慢抬离合至半联动后松开手刹同时轻踩油门","猛踩油门冲上去","踩住刹车和离合同时进行"],ans:1,exp:"坡道起步=拉手刹→踩离合挂1挡→慢抬离合至半联动（车身抖动）→轻踩油门→感觉到车有向前的力时松开手刹→同时继续慢抬离合+加油→完成起步。手刹辅助起步可有效防止后溜。",tip:"口诀：坡起=手刹拉住→离合半联动→给油→感觉车要走了松手刹→继续走。"},
{id:774,cat:"operation",type:"judgment",q:"安全气囊（SRS）无论碰撞严重程度如何都会弹出，以最大限度保护驾驶人。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"气囊仅在碰撞强度达到触发阈值时才弹出（通常为正面/接近正面碰撞且减速度大到一定程度）。轻微碰撞、侧面碰撞（无侧气囊时）、追尾等可能不触发。气囊是被动安全装置，必须与安全带配合使用。",tip:"口诀：气囊不是一碰就弹=要够猛才弹。安全带+气囊=黄金组合。不系安全带+气囊=二次伤害。"},
{id:775,cat:"operation",type:"choice",q:"车辆行驶中爆胎时，正确的紧急处置方法是？",opts:["急踩刹车","紧握方向盘，控制方向，松油门缓慢减速，抢挂低挡，驶离主干道后安全停车","猛打方向修正","加速通过"],ans:1,exp:"爆胎=双手紧握方向盘保持直线行驶→松油门自然减速（不要急刹！急刹会导致车辆因重心转移和爆胎侧阻力加大而失控甩尾）→抢挂低挡辅助减速→开启双闪→驶向紧急停车带或安全位置停车。",tip:"口诀：爆胎=握紧方向+松油门减速+别急刹！方向稳住是第一位，速度慢慢降。"},
{id:776,cat:"operation",type:"judgment",q:"ABS的作用是在紧急制动时自动以极高频率点刹，防止车轮抱死，使驾驶人仍能转动方向盘避开障碍物。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"ABS=防抱死制动系统。在紧急制动时自动快速地点刹（每秒可达数十次），防止车轮完全抱死，从而保持转向能力——驾驶人可以在全力刹车的同时转向避开障碍物。ABS工作时制动踏板会有弹脚振动感，属于正常现象。",tip:"口诀：ABS=紧急刹车时车轮不会抱死，还能打方向。踏板弹脚=ABS在工作，别松开。"},
{id:777,cat:"operation",type:"choice",q:"车辆在冰雪路面起步时车轮打滑，应如何操作？",opts:["大油门冲出去","用2挡起步（自动挡选择雪地模式），轻踩油门缓慢起步","快速抬起离合器","猛打方向增加摩擦力"],ans:1,exp:"冰面起步=用2挡（减小扭矩输出减少打滑）+轻踩油门+缓慢抬离合（手动挡）。自动挡选择雪地模式（如有）或手动模式2挡起步。大油门=车轮空转=越陷越滑。",tip:"口诀：冰雪起步=2挡+轻油+慢离合。雪地模式最好。大油门=越滑越惨。"},
{id:778,cat:"operation",type:"judgment",q:"手动挡汽车在换挡时，如果听到变速箱发出「咔咔」打齿声，说明离合器没有踩到底或换挡时机不对。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"打齿声=离合器未完全分离（没踩到底）→齿轮还在旋转就强行啮合→齿轮撞击。应立即踩下离合器重新挂挡。经常打齿会严重损坏变速箱齿轮和同步器。",tip:"口诀：挂挡「咔咔」响=离合没踩到底或挂太快。踩到底再挂，爱护变速箱。"},
{id:779,cat:"operation",type:"choice",q:"巡航定速（定速巡航）功能最适合在什么路况下使用？",opts:["市区拥堵路段","高速公路、路况良好的长距离行驶","山区弯道","雨雪天气"],ans:1,exp:"定速巡航=高速公路+路况良好+车流稀疏。不适合市区、弯道、雨雪天气、拥堵路段——这些路段需要频繁调整车速，使用定速巡航反而增加操作负担和安全隐患。",tip:"口诀：定速巡航=高速+好路+少车。市区/弯道/雨雪=别用。"},
{id:780,cat:"operation",type:"judgment",q:"车辆长时间停放后再次启动前，应当检查机油、冷却液、制动液、轮胎气压等。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"长时间停放后启动前应检查：机油液位、冷却液液位、制动液、轮胎气压（长时间停放可能漏气）、蓄电池电量。简单检查能发现潜在问题，避免行驶中发生故障。",tip:"口诀：长时间没开=启动前花2分钟检查液位+轮胎。放久了车也会有「起床气」。"},
{id:781,cat:"operation",type:"choice",q:"关于经济驾驶（省油技巧），以下说法正确的是？",opts:["频繁急加速","保持匀速行驶，避免急加速和急刹车，合理使用挡位","空挡滑行省油","低速高挡行驶"],ans:1,exp:"省油=匀速行驶+预见性驾驶（提前松油减速而非到跟前急刹）+合理换挡（2000-2500转升挡）+保持正常胎压+减少不必要载重。急加速急刹车的油耗比匀速高出30%以上。",tip:"口诀：省油=匀速+预见+合理换挡。一脚油门一脚刹车=最费油的开法。"},
{id:782,cat:"operation",type:"judgment",q:"车辆胎压过低比胎压过高更容易导致爆胎。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"胎压过低=轮胎侧壁过度弯曲+高速行驶时反复弯折产生大量热量→轮胎结构强度下降→爆胎。实际上胎压低比胎压高更危险——很多人以为低压安全，其实是最大误区。保持厂家推荐标准胎压最安全。",tip:"口诀：胎压低比胎压高更易爆胎！低压=胎壁反复弯折发热=爆胎。标准胎压最安全。"},
{id:783,cat:"operation",type:"choice",q:"仪表板上制动系统故障灯（红色感叹号圆形图标）亮起，可能表示什么？",opts:["手刹已拉紧","制动液不足或制动系统故障","ABS正在工作","制动片正常磨损"],ans:1,exp:"制动红灯=可能原因：①手刹未完全松开→②制动液不足（泄漏）→③制动系统严重故障。应先检查手刹是否完全松开，如手刹已松则说明制动系统有严重问题，应立即停车检查。",tip:"口诀：制动红灯=先看手刹松了没。手刹松了还亮=制动系统有问题，马上停车。"},
{id:784,cat:"operation",type:"judgment",q:"驾驶机动车时应双手握方向盘，转弯时采用交叉手方式打方向。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"正确转弯打方向方式=双手推拉式（一手推一手拉），不交叉手臂。交叉手方式在安全气囊弹出时可能将手臂弹向面部造成严重伤害。9点3点握法+推拉式转向=最安全。",tip:"口诀：转弯打方向=推拉式（不交叉手）。交叉手+气囊弹出=手臂弹脸上。"},
{id:785,cat:"operation",type:"choice",q:"夜间会车时，对向来车未关闭远光灯，导致我方眩目看不清路，正确的做法是什么？",opts:["也开远光回敬","闭上一只眼","视线向右偏移看道路右侧边缘线，同时减速","伸头出窗外看路"],ans:2,exp:"远光眩目=视线右移看道路右侧白色边缘线（利用边缘线判断车身在道路中的位置）+适当减速+必要时靠边停车。绝对不开远光回敬——双方同时失明=正面相撞高风险。",tip:"口诀：被远光晃=看右边白线定位+减速。不对射——两瞎相撞更惨。"},
{id:786,cat:"operation",type:"judgment",q:"检查制动液（刹车油）液位时，液位应在储液罐的MIN和MAX刻度之间。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"制动液应在MIN-MAX之间。低于MIN=可能制动液泄漏或刹车片磨损过度（随刹车片磨损制动液液面会下降）；应添加指定型号制动液并检查制动系统。",tip:"口诀：刹车油液面=MIN和MAX之间。低了=可能漏了或刹车片该换了。"},
{id:787,cat:"operation",type:"choice",q:"车辆行驶中，发动机舱突然冒烟（非白烟/蒸汽），应如何处置？",opts:["继续行驶","立即靠边停车，关闭发动机，打开引擎盖前先观察是否有明火，全员撤离到安全地带并报警","立即打开引擎盖泼水","加速行驶到修理厂"],ans:1,exp:"行驶中冒烟=立即安全停车→关闭发动机→全员撤离到安全地带→打119/122→不要贸然打开引擎盖（新鲜空气进入可能引发明火爆燃）→使用灭火器时从引擎盖缝隙喷入而非完全打开。",tip:"口诀：车冒烟=停车→熄火→人撤→报警。不要贸然开引擎盖（可能爆燃）！"},
{id:788,cat:"operation",type:"judgment",q:"使用雨刮器前应先喷玻璃水润湿挡风玻璃，避免干刮损坏雨刮片和挡风玻璃。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"干刮=雨刮片橡胶在干燥的挡风玻璃上硬摩擦→刮片快速磨损+玻璃表面产生细微划痕→雨天刮不干净影响视线。应先喷玻璃水→再启动雨刮器。",tip:"口诀：先喷水再刮——干刮=损坏雨刮片+刮花玻璃。有水的玻璃才好刮。"},
{id:789,cat:"operation",type:"choice",q:"在炎热天气下，对轮胎的检查应特别注意什么？",opts:["胎压越低越好","胎压应保持厂家推荐值，注意检查胎面是否有鼓包或损伤","可以忽略胎压","必须调低胎压防爆胎"],ans:1,exp:"高温天气轮胎检查=保持标准胎压（不要刻意调低！胎压低反而更容易因胎壁过度弯曲发热而爆胎）+检查胎面是否有鼓包、裂纹或嵌入异物+长途行驶途中适时停车让轮胎降温。",tip:"口诀：夏天胎压=标准值别调低。低胎压+高温=爆胎加速器。检查鼓包和裂纹。"},
{id:790,cat:"operation",type:"judgment",q:"驾驶机动车时，如果仪表板上多个警告灯同时亮起，可以继续行驶到目的地后再检查。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"多灯同时亮起=可能是发电机不发电或电气系统严重故障（如发电机皮带断裂），导致多个系统同时报警。应立即安全停车检查，继续行驶可能导致车辆彻底趴窝或发生危险。",tip:"口诀：多灯齐亮=大事不好，立刻停车。可能是发电机罢工了——很快全车断电。"},
{id:791,cat:"operation",type:"choice",q:"车辆发生侧滑（甩尾）时，正确的修正方法是？",opts:["向侧滑相反方向猛打方向","向车尾甩出的方向（侧滑方向）缓慢修正方向，同时松油门","急踩刹车","加速拉直车身"],ans:1,exp:"侧滑修正=方向顺着车尾走——车尾往右甩=方向往右轻轻打、车尾往左甩=方向往左轻轻打。同时松油门让速度自然降低，绝对不要急刹。口诀「车尾往哪去，方向往哪修」。",tip:"口诀：车尾往哪甩，方向往哪轻打。松油门别刹车，跟着车尾走。"},
{id:792,cat:"operation",type:"judgment",q:"方向盘的安全气囊弹出位置在方向盘中央（通常有SRS或Airbag标识），驾驶人不应在此位置粘贴手机支架等物品。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"气囊弹出时速度极高（约300km/h），方向盘中央粘贴的手机支架等物品会被气囊以极高速度弹向驾驶人面部，造成严重二次伤害。气囊弹出区域=绝对禁贴任何物品。",tip:"口诀：方向盘中间=气囊弹出区。别贴手机支架——气囊弹出时它就是炮弹。"},
{id:793,cat:"accident",type:"choice",q:"驾驶机动车发生交通事故后，首先应该做什么？",opts:["驾车离开现场","立即停车、保护现场","与对方争吵","自行判断责任"],ans:1,exp:"事故后第一步=立即停车（不可逃逸！）→开启双闪→设置警告标志。然后根据伤亡情况决定后续步骤。逃逸是比事故本身更严重的违法行为。",tip:"口诀：出事故第一步=停车！跑了=肇事逃逸=罪加一等。"},
{id:794,cat:"accident",type:"judgment",q:"发生交通事故造成人员伤亡的，驾驶人应立即抢救伤员并迅速报告执勤交通警察或公安机关交通管理部门。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"有人身伤亡的事故=停车→保护现场→抢救伤员（拨打120）→报警（122）。因抢救伤员需变动现场的，应当标明伤者原始位置。救人第一，报警第二。",tip:"口诀：人伤事故=停车+救人（120）+报警（122）。救人比报警更紧急。"},
{id:795,cat:"accident",type:"choice",q:"发生仅造成轻微财产损失且基本事实清楚的交通事故，当事人应如何处理？",opts:["在现场等待交警处理","先拍照固定证据，再将车辆移至不妨碍交通的地方协商或报警","驾车离开","在现场争吵"],ans:1,exp:"轻微事故=拍照取证（全景+碰撞部位+细节+对方车牌）→撤离现场到安全或不碍事的地方→协商赔偿或报警。造成交通堵塞的，双方均可被罚款200元。",tip:"口诀：小刮擦=拍照→挪车→再谈。堵在路上双方都罚200。"},
{id:796,cat:"accident",type:"judgment",q:"发生交通事故后逃逸的，由公安机关交通管理部门吊销驾驶证，且终身不得重新取得驾驶证。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"肇事逃逸=吊销驾驶证+终身禁驾。无论事故后果轻重，只要逃逸就适用终身禁驾。如果逃逸构成交通肇事罪（致人死亡或重伤），还将追究刑事责任。",tip:"口诀：肇事逃逸=终身禁驾（一辈子别想再开车）。跑了就别想再摸方向盘。"},
{id:797,cat:"accident",type:"choice",q:"交通肇事致一人以上重伤，负事故全部或主要责任，并具有下列哪种情形的，构成交通肇事罪？",opts:["酒后驾车","吸食毒品后驾车","无驾驶资格驾车","以上都构成"],ans:3,exp:"致一人以上重伤+负全部/主要责任+具有下列情形之一=交通肇事罪：①酒驾/毒驾②无证驾驶③明知安全装置不全或失灵④明知无牌证或报废车⑤严重超载⑥逃逸。此时重伤也可入罪（通常致死或3人重伤才入罪）。",tip:"口诀：重伤+全责/主责+酒驾/毒驾/无证/报废车/逃逸=交通肇事罪。重伤也可定罪的条件。"},
{id:798,cat:"accident",type:"choice",q:"交通肇事致一人以上死亡，负事故全部或主要责任的，量刑标准是什么？",opts:["仅罚款","处3年以下有期徒刑或拘役","处3年以上7年以下有期徒刑","处7年以上有期徒刑"],ans:1,exp:"致1人死亡+负全责/主责=交通肇事罪，处3年以下有期徒刑或拘役。致2人以上死亡=处3-7年有期徒刑。逃逸致人死亡=处7年以上有期徒刑。逃逸是加重量刑的关键情节。",tip:"口诀：死1人+主责=3年以下；死2人+=3-7年；逃逸致死=7年以上。逃逸=罪加一等。"},
{id:799,cat:"accident",type:"judgment",q:"发生交通事故后，当事人故意破坏现场、伪造现场的，应当承担全部责任。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"破坏现场、伪造现场=承担全部责任。这是一种恶意逃避责任的行为，法律对此规定「推定全部责任」——即无论实际过错如何，破坏现场一方承担全部责任。",tip:"口诀：破坏现场=全责（不管事故本来是谁的错）。现场是证据，动了就是你的错。"},
{id:800,cat:"accident",type:"choice",q:"发生交通事故后，当事人对事故事实和成因有争议的，应如何处理？",opts:["自行协商解决","立即报警（122），保护现场，等待交警处理","驾车追逐对方","自行判断责任"],ans:1,exp:"有争议=报警+保护现场+等交警。交警到场后勘查现场、绘制现场图、询问当事人和证人、进行检验鉴定，最终出具「交通事故认定书」划分责任。",tip:"口诀：谈不拢=报警等警察。交警来了画图、取证、出认定书。"},
{id:801,cat:"accident",type:"judgment",q:"交通事故认定书是划分当事人事故责任的法律文书，当事人对认定书不服的可以向上级公安机关交通管理部门申请复核。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"对交通事故认定书不服=可在收到认定书后3日内向上一级公安机关交通管理部门申请复核（仅限一次）。复核期间不影响保险理赔和民事赔偿程序。也可在诉讼中向法院提出异议。",tip:"口诀：不服认定书=3天内申请复核（只能一次）。过了3天就生效。"},
{id:802,cat:"accident",type:"choice",q:"发生交通事故后，以下哪些证据应当注意收集和保存？",opts:["只需记住对方车牌号","现场照片/视频、行车记录仪录像、对方驾驶证和行驶证信息、证人联系方式和证言","只需对方联系方式","无需收集证据"],ans:1,exp:"事故证据=①现场照片/视频（全景+碰撞部位+车牌）②行车记录仪录像③交换驾驶证和行驶证信息④报警记录⑤证人联系方式⑥保险报案记录。完整证据链对后续理赔和责任认定至关重要。",tip:"口诀：事故证据=拍照+录像+换证照信息+留证人电话+报警。证据越全越主动。"},
{id:803,cat:"accident",type:"judgment",q:"发生交通事故后，当事人未在现场报警，事后请求公安机关处理的，公安机关应当受理。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"事后报警=公安机关应当受理，但应提供事故证据（照片、录像、证人等）。若无法提供证据又无法查证事实的，公安机关可能无法出具认定书。所以现场报警是最好的选择。",tip:"口诀：事后也能报警，但证据不足可能查不清。有条件=现场就报警。"},
{id:804,cat:"accident",type:"choice",q:"发生交通事故后，交强险的赔偿限额（2026年）中，死亡伤残赔偿限额是多少？",opts:["110000元","180000元","200000元","500000元"],ans:1,exp:"2026年交强险有责赔偿限额：死亡伤残180000元、医疗费用18000元、财产损失2000元。无责赔偿限额大幅降低（约十分之一）。超过交强险限额部分由商业险或责任人自行承担。",tip:"口诀：交强险上限=死亡18万+医疗1.8万+财产2千。撞了人交强险不够赔，商业险+自掏腰包。"},
{id:805,cat:"accident",type:"choice",q:"机动车与机动车之间发生交通事故，责任划分遵循什么原则？",opts:["谁的车更贵谁负责","过错责任原则——有过错方承担责任，双方过错按比例分担","一律五五分","后车永远全责"],ans:1,exp:"机动车之间事故=过错责任原则。有过错方承担赔偿责任；双方均有过错=按过错比例分担。机动车与非机动车/行人之间=无过错责任原则（机动车即使无过错也需承担不超过10%的赔偿）。",tip:"口诀：车vs车=过错责任（谁错谁赔）；车vs人=无过错责任（车基本都要赔）。"},
{id:806,cat:"accident",type:"judgment",q:"道路交通事故社会救助基金可以垫付事故中受害人的抢救费用、丧葬费用。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"救助基金=在以下情况垫付受害人的抢救费和丧葬费：①肇事车辆未投保交强险②肇事车辆逃逸③抢救费用超过交强险责任限额。基金垫付后可向责任人追偿。",tip:"口诀：救助基金=车没保险/车跑了/费用超交强险时救命用的。先垫后追。"},
{id:807,cat:"accident",type:"choice",q:"发生交通事故后，当事人在什么情况下可以先撤离现场再协商？",opts:["任何情况","仅造成轻微财产损失且基本事实清楚、无争议","有人受伤","车辆无法移动"],ans:1,exp:"可先撤离条件=轻微财产损失+事实清楚+无争议。有人伤、车不能动、有争议、涉及酒驾毒驾等情况=必须保护现场并报警。撤离前必须先拍照固定证据。",tip:"口诀：小+清+无争议=可先撤离。大/伤/车不能动/争=必须等警察。"},
{id:808,cat:"accident",type:"judgment",q:"驾驶人在道路上发生交通事故后，因收集证据需要可以扣留对方车辆。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"只有公安机关交通管理部门才有权依法扣留事故车辆。当事人无权扣留对方车辆——私自扣车属于违法行为，可能构成非法扣押。应通过报警由交警依法处置。",tip:"口诀：普通人无权扣对方车。只有交警才能扣车。私下扣车=违法。"},
{id:809,cat:"accident",type:"choice",q:"发生交通事故后，对交通事故损害赔偿有争议的，当事人可以采取哪些合法途径解决？",opts:["只有诉讼","请求公安机关交通管理部门调解、自行协商、向人民法院提起民事诉讼","只有自行协商","只能请律师"],ans:1,exp:"赔偿争议解决途径（三选一或逐步递进）：①自行协商→②请求公安机关交通管理部门调解（收到认定书后10日内书面申请）→③向人民法院提起民事诉讼。调解不是诉讼的前置程序，可直接诉讼。",tip:"口诀：赔偿有争议=协商→交警调解→法院诉讼。三条路都可以走，不一定按顺序。"},
{id:810,cat:"accident",type:"choice",q:"交通肇事逃逸的，由公安机关吊销驾驶证。醉酒驾车发生重大交通事故构成犯罪的，除追究刑事责任外还有什么后果？",opts:["仅记12分","吊销驾驶证，终身不得重新取得","暂扣驾驶证","罚款"],ans:1,exp:"醉酒驾车+发生重大交通事故+构成犯罪=吊销驾驶证+终身禁驾+追究刑事责任。与逃逸的终身禁驾相同——两者都是法规中最严厉的处罚。",tip:"口诀：醉驾+重大事故+犯罪=终身禁驾。和肇事逃逸一样，一辈子别想开车。"},
{id:811,cat:"accident",type:"judgment",q:"发生交通事故后，驾驶人将伤员送往医院后可以不再报警。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"有人身伤亡的事故，即使已送伤员就医，也必须报警（122）。送医和报警是两个独立的法律义务，送医不豁免报警义务。不报警可能被认定为逃逸。",tip:"口诀：送医院+报警=两件事都要做。光送人不报警=可能算逃逸。"},
{id:812,cat:"accident",type:"choice",q:"发生交通事故后，因抢救伤员需要移动事故车辆的，应如何处理？",opts:["直接移动","标明车辆和伤员原始位置（拍照或在地面标记）后再移动","不允许移动","只移动伤员不移车"],ans:1,exp:"因抢救伤员需变动现场=应当在变动前标明车辆和伤者原始位置（拍照/录像/在地面划线标记）。目的是既及时救人，又尽可能保全现场证据供交警定责。",tip:"口诀：救人移车=先拍照/标记位置再移。救人重要，证据也重要。"},
{id:813,cat:"accident",type:"judgment",q:"事故现场拍照取证时，应包括全景照片（拍摄事故地点全貌和交通环境）、碰撞部位照片和车辆细节照片。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"事故拍照三要素=①全景照（远距离拍摄事故现场全貌+道路环境+交通标志标线）②碰撞照（特写碰撞部位+受损情况）③细节照（对方车牌、驾驶证、挡风玻璃上车架号等）。完整的三类照片能有效还原事故真相。",tip:"口诀：事故拍照=全景（环境）+撞点（损伤）+细节（对方车牌证照）。三样拍全才有效。"},
{id:814,cat:"accident",type:"choice",q:"发生事故后通知保险公司的时限一般为多少？",opts:["事故发生后48小时内","事故发生后7天内","任何时候都可以","不需要通知"],ans:0,exp:"保险报案=一般要求事故发生后48小时内通知保险公司。超过时限可能影响理赔（保险公司以无法核实损失为由拒赔或减少赔偿）。发生事故后应尽快拨打保险公司报案电话。",tip:"口诀：出事了48小时内报保险。拖久了保险公司可能不认账。"},
{id:815,cat:"accident",type:"judgment",q:"发生交通事故后，未投保交强险的机动车驾驶人应当先在交强险责任限额内自行承担赔偿，不足部分再按责任比例承担。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"未投保交强险=本应由交强险赔付的部分由驾驶人自行全额承担。也就是说，即使对方也有过错，未投保方仍需按交强险限额全额赔偿，不受责任比例限制。这是对不投保交强险的惩罚性规定。",tip:"口诀：没买交强险=不管谁错你先赔全额。不买保险的代价——自掏腰包赔到肉疼。"},
{id:816,cat:"accident",type:"choice",q:"发生涉及人员伤亡的交通事故后，公安机关交通管理部门应在接到报警后多长时间内赶到现场？",opts:["15分钟内","应当立即派交通警察赶赴现场","1小时内","24小时内"],ans:1,exp:"交警=接到报警后应当立即赶赴现场。法律未规定具体分钟数但要求「立即出动」。城区一般在10-30分钟内到达，偏远地区可能更久。",tip:"口诀：交警接警=立即出警。城里一般很快就到。"},
{id:817,cat:"accident",type:"judgment",q:"交通事故中的伤者因抢救无效死亡的，驾驶人仍然需要承担相应的赔偿责任。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"伤者经抢救无效死亡=民事责任（赔偿）不受影响，应赔偿死亡赔偿金、丧葬费、精神损害抚慰金等。同时根据事故责任和情节，可能涉及刑事责任（交通肇事罪）。",tip:"口诀：人没救过来≠你没责任。民事赔偿照赔，严重的话还要判刑。"},
{id:818,cat:"accident",type:"choice",q:"发生交通事故，驾驶人「无能力赔偿」是否构成交通肇事罪？",opts:["构成（只要造成重大损失就构罪，不管是否有赔偿能力）","不构成","取决于法官心情","只要赔了钱就不构罪"],ans:0,exp:"交通肇事罪=看事故后果和过错程度，与有无赔偿能力无关。无力赔偿是民事执行问题，不影响刑事责任认定。但积极赔偿并取得谅解=酌定从轻量刑情节。",tip:"口诀：赔不起≠不犯罪。先定罪再谈赔偿。没钱赔≠无罪。"},
{id:819,cat:"accident",type:"judgment",q:"交通事故造成公共设施（如护栏、信号灯等）损坏的，驾驶人只需维修自己的车辆，公共设施损坏不用管。此说法是否正确？",opts:["正确","错误"],ans:1,exp:"撞坏公共设施（护栏、路灯、信号灯等）=必须报警（122）并赔偿。驾车离开=肇事逃逸（即使未伤及他人）。公共设施属于国家财产，损坏必须赔偿。",tip:"口诀：撞了护栏/路灯=报警+赔钱。跑了=肇事逃逸。公家的东西碰坏了也得赔。"},
{id:820,cat:"accident",type:"choice",q:"发生交通事故后，以下哪种行为是正确的？",opts:["对方逃逸时驾车追赶","在现场与对方争吵","保持冷静，开启双闪，设置警告标志，检查伤亡情况，报警和呼叫救护车","移动车辆清除证据"],ans:2,exp:"事故后正确行为=冷静→开双闪→设警告牌→检查有无人员受伤→有人伤打120→打122报警→拍照取证→交换证照信息→通知保险公司。情绪化行为只会让事情更糟。",tip:"口诀：事故后=冷静+双闪+警示牌+看人+120+122+拍照+换证照+报保险。按流程来，不慌。"},
{id:821,cat:"accident",type:"choice",q:"发生交通事故后，对方驾驶人疑似酒驾或毒驾，应当如何处理？",opts:["私下协商解决","立即报警，协助警方固定证据（如记录对方行为和状态）","放对方离开","接受对方私了建议"],ans:1,exp:"对方疑似酒驾/毒驾=必须报警+不私了。酒驾毒驾属于严重违法行为，私了包庇同样是违法。注意记录对方行为特征（言语不清、步态不稳、身上有酒气等）供警方调查。",tip:"口诀：对方酒驾毒驾=必须报警别私了。包庇酒驾=你也有责任。"},
{id:822,cat:"accident",type:"judgment",q:"行车记录仪的录像可以作为交通事故的证据使用。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"行车记录仪录像=具有证据效力。在事故责任认定、保险理赔、法院诉讼中均可作为证据采信。建议驾驶人都安装行车记录仪——关键时刻是「沉默的证人」。",tip:"口诀：行车记录仪=铁证。关键时刻帮你说话。没装记录仪=有理说不清。"},
{id:823,cat:"accident",type:"choice",q:"在高速公路上发生事故后，车上人员应该怎么做？",opts:["留在车内等待","下车站在车旁讨论","迅速转移到右侧路肩或护栏外的安全地带","在车后方推车"],ans:2,exp:"高速事故=人员立即转移到护栏外（不要待在车内和车道上！）。高速公路上二次事故（后车追尾事故车）的死亡率极高。人撤离后开启双闪、150米外设警告牌、报警。",tip:"口诀：高速出事=人先撤到护栏外！车道上站一秒=赌一次命。"},
{id:824,cat:"accident",type:"judgment",q:"发生交通事故后，公安机关交通管理部门进行检验鉴定需要扣留事故车辆的，扣留时限一般不超过30日，经批准可延长至60日。此说法是否正确？",opts:["正确","错误"],ans:0,exp:"检验鉴定扣车=一般不超过30日+经批准可延长至60日（特殊情况可再延）。扣车期间应妥善保管车辆，扣留期满后应及时将车辆退还当事人。",tip:"口诀：事故扣车检验=一般30天，最长可延到60天。不是无限期扣着。"},
{id:825,cat:"accident",type:"choice",q:"「快处快赔」机制适用于什么类型的交通事故？",opts:["所有事故","仅造成轻微财产损失、车辆可移动、无人员伤亡、事实清楚、责任无争议的事故","只有高速公路事故","只有城市道路事故"],ans:1,exp:"快处快赔=轻微财损+车能动+无人伤+事实清楚+无争议。流程=拍照（上传保险公司APP或交管12123）→撤离现场→在线定责定损→快速理赔。是解决轻微事故的最便捷方式。",tip:"口诀：快处快赔=小事故的VIP通道——拍照上传→挪车→在线理赔。轻微事故不用等交警。"},
{id:826,cat:"highway",type:"choice",q:"机动车驶入高速公路时，应在哪个车道上将车速提高到60km/h以上？",opts:["匝道","加速车道（合流车道）","行车道","应急车道"],ans:1,exp:"进入高速公路应先经匝道（限速40km/h），然后进入加速车道（合流车道），在加速车道内将车速提高到60km/h以上，观察左后方来车，确认安全后并入行车道。匝道弯多路窄，在匝道内就加速非常危险。",tip:"口诀：匝道慢行40码→加速车道提速到60+→看左后→并入主线。三步进高速，一步不能乱。"},
{id:827,cat:"highway",type:"judgment",q:"驶离高速公路时，应在匝道内开始减速至40km/h以下。",opts:["正确","错误"],ans:1,exp:"驶离高速公路的正确顺序：先进入减速车道，在减速车道内完成减速，然后再进入匝道。匝道弯道半径小，如果在匝道内才开始减速，容易因车速过快而失控。应在进入匝道前就完成减速。",tip:"口诀：先出主线进减速车道→减速→再进匝道。在匝道里才想起减速已经晚了。"},
{id:828,cat:"highway",type:"choice",q:"高速公路加速车道的作用是什么？",opts:["超车","停车休息","让车辆加速到与主线车流速度匹配后安全并入","应急避险"],ans:2,exp:"加速车道（合流车道）连接匝道和高速主线，作用是让车辆将速度提升至与主线车流相当的水平（≥60km/h），在速度匹配后寻找合适间隙并入主线，避免因速度差过大引发追尾事故。",tip:"口诀：加速车道=给你空间提速，和主线车「同速」才能安全合流。速度差越大越危险。"},
{id:829,cat:"highway",type:"choice",q:"驶离高速公路进入减速车道后，以下做法正确的是？",opts:["立即急刹车","保持原速进入匝道","在减速车道内平稳减速，进入匝道前将车速降至匝道限速范围内","关闭转向灯"],ans:2,exp:"进入减速车道后应平稳减速，在到达匝道入口前将车速降至40km/h左右（匝道限速）。驶入减速车道时就应开启右转向灯，示意后方车辆你要驶离高速。减速要在减速车道上完成，不要拖到匝道里。",tip:"口诀：看到出口预告→开右灯→进减速车道→平稳减速至40→进匝道。减速在减速车道完成。"},
{id:830,cat:"highway",type:"judgment",q:"从加速车道并入高速主线时，主线车辆有义务减速让行。",opts:["正确","错误"],ans:1,exp:"匝道车辆并入主线属于变更车道，应当让行主线正常行驶的车辆。主线车辆没有减速让行的法定义务（但出于安全可以礼让）。并入车辆必须观察、等待、确认安全后才能并入。",tip:"口诀：并入主线=你让主线车，不是主线车让你。主路上的车有优先权。"},
{id:831,cat:"highway",type:"choice",q:"在有三条车道的高速公路上，设计时速110km/h的小型客车应在哪条车道行驶？",opts:["最右侧车道","中间车道","最左侧车道","任意车道"],ans:2,exp:"同方向3条车道的高速公路：最左侧车道最低限速110km/h，中间90km/h，右侧60km/h。设计时速110km/h的小型客车可以且应当在最左侧车道行驶。长期占用最左侧车道低速行驶属于违法行为。",tip:"口诀：三车道高速→左道110+，中道90+，右道60+。按速度选车道，小车高速走左道。"},
{id:832,cat:"highway",type:"choice",q:"高速公路上「爬坡车道」的主要作用是什么？",opts:["供小型车超车使用","供车速降低的大型货车使用，避免影响其他车辆通行","紧急停车使用","掉头使用"],ans:1,exp:"爬坡车道设于长陡上坡路段右侧，专供爬坡能力不足、车速显著下降的大型货车使用。大货车进入爬坡车道后，主线车道保持畅通，小型车可正常通行不受慢车影响。",tip:"口诀：爬坡车道=给大货车上坡用的慢车道。大车靠右慢慢爬，不堵小车。"},
{id:833,cat:"highway",type:"judgment",q:"高速公路最左侧车道为快车道，任何车辆都可以长时间占用行驶。",opts:["正确","错误"],ans:1,exp:"最左侧车道虽为快车道，但设计时速低于最低限速的车辆不得驶入。不超车时长时间占用最左侧车道行驶（「龟速占快道」）属于违法行为，影响通行效率且易引发后车路怒和右侧超车危险。",tip:"口诀：左道=超车道，超完车就回中间。别当「移动路障」占着快车道龟速。"},
{id:834,cat:"highway",type:"choice",q:"高速公路上同方向有2条车道的，左侧车道最低限速是多少？",opts:["60km/h","90km/h","100km/h","110km/h"],ans:2,exp:"同方向有2条车道：左侧车道最低限速100km/h，右侧车道最低限速60km/h。同方向3条车道：左侧最低110km/h，中间最低90km/h，右侧最低60km/h。",tip:"口诀：两车道→左100右60；三车道→左110中90右60。从右往左逐步递增。"},
{id:835,cat:"highway",type:"judgment",q:"高速公路应急车道在车辆发生故障时可以临时停车，但不得长时间占用或借道行驶。",opts:["正确","错误"],ans:0,exp:"应急车道仅供车辆发生故障、交通事故等紧急情况时临时停车，或执行紧急任务的特种车辆通行。正常情况下任何车辆不得占用行驶或停车，违者记6分。",tip:"口诀：应急车道=生命通道。非紧急不占用，占用了记6分。"},
{id:836,cat:"highway",type:"choice",q:"在高速公路上，小型载客汽车的最高限速是多少？",opts:["100km/h","110km/h","120km/h","130km/h"],ans:2,exp:"我国高速公路最高限速为120km/h（小型载客汽车）。其他车辆限速：摩托车80km/h、大型客车和货车100km/h。部分路段可能有低于120km/h的限速标志，按标志行驶。",tip:"口诀：小车高速120封顶，大车100封顶，摩托车80封顶。120→100→80，依次递减20。"},
{id:837,cat:"highway",type:"choice",q:"高速公路最低限速是多少？",opts:["40km/h","50km/h","60km/h","70km/h"],ans:2,exp:"高速公路最低限速为60km/h（最右侧车道）。设计最高时速低于70km/h的机动车不得进入高速公路。车速过低的车辆无法安全融入高速车流，极易引发追尾事故。",tip:"口诀：高速最低60码，跑不到70码的车压根不让上高速。"},
{id:838,cat:"highway",type:"judgment",q:"大型客车在高速公路上行驶速度不得超过100km/h。",opts:["正确","错误"],ans:0,exp:"大型载客汽车（大巴、旅游客车等）在高速公路最高限速为100km/h。同方向有三条及以上车道的，大型客车可在中间车道行驶（最低限速90km/h）。",tip:"口诀：大客车高速=100码封顶。一车人的安全在你脚下。"},
{id:839,cat:"highway",type:"choice",q:"高速公路同方向有4条车道时，最左侧车道的限速范围是多少？",opts:["60-120km/h","90-120km/h","100-120km/h","110-120km/h"],ans:3,exp:"同方向4条车道：最左（第一车道）110-120km/h，第二车道90-120km/h，第三车道80-100km/h，最右（第四车道）60-100km/h。小型客车应在左侧两条车道行驶。",tip:"口诀：四车道→左一110-120、左二90-120、左三80-100、右四60-100。数字从右往左递增。"},
{id:840,cat:"highway",type:"judgment",q:"在高速公路上行驶时，车速低于60km/h的机动车应当在最右侧车道行驶。",opts:["正确","错误"],ans:1,exp:"高速公路最低限速就是60km/h，正常情况下车速不得低于60km/h。只有遇恶劣天气、交通拥堵、施工等特殊情况才可以低于60km/h行驶，此时应开启危险报警闪光灯。正常情况下低于最低限速行驶本身就是不允许的。",tip:"口诀：高速低于60码=根本不允许（除非堵车/恶劣天气）。不是走哪条道的问题，是不该这么慢。"},
{id:841,cat:"highway",type:"choice",q:"在高速公路上车速超过100km/h时，与前车应保持多少米以上的安全距离？",opts:["50米","80米","100米","150米"],ans:2,exp:"高速公路车速超过100km/h时，应与前车保持100米以上安全距离。车速低于100km/h时可适当缩短但不得少于50米。可利用路面车距确认线辅助判断距离。",tip:"口诀：高速超100码→跟车100米。车速多少就大概跟多少米。路面白色箭头帮你量距离。"},
{id:842,cat:"highway",type:"judgment",q:"高速公路上车速低于100km/h时，与前车安全距离可以少于50米。",opts:["正确","错误"],ans:1,exp:"车速低于100km/h时安全距离可适当缩短，但不得少于50米。50米是最低底线，不可以任意缩短。安全距离还应综合考虑天气、路面、载重等因素。",tip:"口诀：高速跟车最少50米，无论速度多低。50米=高速安全距离的绝对底线。"},
{id:843,cat:"highway",type:"choice",q:"高速公路上的「车距确认线」是什么样子的？",opts:["黄色实线","白色折线或白色箭头标志，间隔50米","红色虚线","蓝色标线"],ans:1,exp:"车距确认线=路面白色折线标线或路侧白色箭头标志，每组间隔50米（0m、50m、100m）。驾驶人可利用这些标线判断与前车的距离。通常设置在长直路段。",tip:"口诀：路面白色折线/箭头=车距确认线，每50米一个。帮你「量」安全距离。"},
{id:844,cat:"highway",type:"judgment",q:"雨雪天气在高速公路行驶时，安全跟车距离应比正常天气增加一倍以上。",opts:["正确","错误"],ans:0,exp:"雨雪天气路面附着系数大幅降低（湿滑路面摩擦系数约为干燥路面的1/2到1/3），制动距离显著增加。安全跟车距离应比正常天气至少增加1-2倍，车速应相应降低。",tip:"口诀：雨雪天跟车距离翻倍。路面越滑，离前车越远。"},
{id:845,cat:"highway",type:"choice",q:"高速公路上能见度低于200米时，车速和跟车距离的要求是什么？",opts:["车速不超过80km/h，距离不少于80米","车速不超过60km/h，距离不少于100米","车速不超过40km/h，距离不少于50米","车速不超过100km/h，距离不少于50米"],ans:1,exp:"能见度低于200米：车速≤60km/h，与前车保持100米以上距离，开启雾灯、近光灯、示廓灯和前后位灯。这是高速公路恶劣天气「三速三距」规则中的一档。",tip:"口诀：能见度200米→车速60→距离100。记住200-60-100这个组合。"},
{id:846,cat:"highway",type:"choice",q:"在高速公路上车辆发生故障难以移动时，应在来车方向多少米外设置警告标志？",opts:["50米","100米","150米","200米"],ans:2,exp:"高速公路故障车应在来车方向150米外设置警告标志（普通道路50-100米）。夜间或恶劣天气应适当增加距离。车上人员须迅速转移到右侧护栏外安全地带，严禁在车道内停留。",tip:"口诀：高速放警示牌150米（和会车改近光距离一样）。普通路50-100米。"},
{id:847,cat:"highway",type:"judgment",q:"在高速公路上车辆故障停车后，驾驶人可以在车内打电话报警等待救援。",opts:["正确","错误"],ans:1,exp:"绝对不可以！车辆在高速公路上发生故障停车后，车上所有人员（包括驾驶人）应立即转移到右侧护栏外安全区域，然后再报警（拨打12122）。留在车内或站在车旁极其危险，后方来车可能因视线不佳或注意力不集中而发生碰撞。",tip:"口诀：高速抛锚=人先出护栏外，再打电话。车可以报废，人不能出事——命比车贵。"},
{id:848,cat:"highway",type:"choice",q:"高速公路报警救援电话号码是多少？",opts:["110","122","12122","120"],ans:2,exp:"全国高速公路报警救援统一电话为「12122」。遇故障、事故、需要拖车等情况均可拨打。拨打电话时需提供高速公路名称、行驶方向和大致里程桩号（路侧护栏上公里牌的数字）。",tip:"口诀：高速求救拨12122（一二一二二）。看路边公里牌报位置，救援来得快。"},
{id:849,cat:"highway",type:"choice",q:"在高速公路上发生轻微交通事故且车辆可以移动时，正确的做法是什么？",opts:["原地等交警","拍照取证后迅速将车辆移至应急车道或最近出口","双方在行车道上协商","只需打开双闪"],ans:1,exp:"高速公路发生无人员伤亡的轻微事故，车辆可移动的，应拍照取证后迅速将车移至应急车道、服务区或最近出口。严禁在行车道内停车争执。占用行车道不撤离将被罚款并记分。",tip:"口诀：高速小剐蹭→拍照→快撤到应急车道/服务区→再协商。行车道不是协商室。"},
{id:850,cat:"highway",type:"judgment",q:"夜间在高速公路应急车道停车时，除开启危险报警闪光灯外，还需开启示廓灯和后位灯。",opts:["正确","错误"],ans:0,exp:"夜间或能见度不良时在应急车道停车，须同时开启危险报警闪光灯（双闪）、示廓灯和后位灯。三灯齐亮提高自身可见度，让后方来车能及时发现你的车辆。",tip:"口诀：夜间应急停车=三灯齐亮（双闪+示廓+后位）+150米外警示牌。让自己变成发光体。"},
{id:851,cat:"highway",type:"choice",q:"高速公路上的「港湾式紧急停车带」设置在什么位置？",opts:["行车道中间","每隔一定距离设置在道路右侧","隧道内","收费站附近"],ans:1,exp:"港湾式紧急停车带通常每隔约2-5公里设置在高速公路右侧，是道路外侧拓宽形成的凹入区域，供车辆紧急停车使用。与应急车道不同，港湾式停车带完全在行车道之外，停车更安全。",tip:"口诀：港湾停车带=高速路边凹进去的「避风港」。比应急车道更安全，每隔几公里一个。"},
{id:852,cat:"highway",type:"judgment",q:"在高速公路上发生车辆故障后，可以用其他车辆牵引故障车从最近出口驶离高速。",opts:["正确","错误"],ans:1,exp:"高速公路上禁止非专业救援车辆牵引故障车。故障车应拨打12122由专业清障救援车辆进行牵引。自行用普通车辆在高速上牵引故障车极度危险，且属于违法行为。",tip:"口诀：高速拖车=叫专业救援（12122）。自己拿绳子拖=违法+找死。"},
{id:853,cat:"highway",type:"choice",q:"进入高速公路隧道前，驾驶人应当做什么？",opts:["加速通过","开启远光灯并加速","开启近光灯、减速，注意隧道入口的限速标志","关灯通过"],ans:2,exp:"进隧道前应开启近光灯、减速至隧道限速（通常80km/h或更低）、注意隧道入口的光线变化（黑洞效应）。进隧道瞬间人眼需要适应光线变化，约0.5-1秒内几乎看不清，所以必须提前减速。",tip:"口诀：进隧道=开近光+减速+看限速。黑洞效应→进洞瞬间看不清，减速是关键。"},
{id:854,cat:"highway",type:"judgment",q:"隧道内行驶时可以变更车道超车。",opts:["正确","错误"],ans:1,exp:"隧道内通常为实线标线，禁止变更车道和超车。隧道内空间狭窄、视线受限，变道极易引发严重事故。进入隧道前就应选择好车道，在隧道内保持在本车道内行驶。",tip:"口诀：隧道内=禁止变道+禁止超车。进隧道前选好道，进去就别动了。"},
{id:855,cat:"highway",type:"choice",q:"高速公路隧道内行车时，与前车应保持的安全距离比隧道外应如何调整？",opts:["可以缩小距离","与隧道外一致","应比隧道外更大，通常建议100米以上","无所谓"],ans:2,exp:"隧道内视线条件更差，一旦发生事故疏散困难，安全跟车距离应比隧道外更大（建议100米以上）。隧道内常设有车距确认标志（蓝底白字），提示驾驶人保持安全距离。",tip:"口诀：隧道内跟车距离要加大→至少100米。洞里出事故=无处可逃，离远点。"},
{id:856,cat:"highway",type:"choice",q:"高速公路隧道出口处的「白洞效应」是什么？",opts:["隧道内灯光太亮","出隧道瞬间外部光线过强导致短暂看不清","隧道墙壁反光","路面湿滑"],ans:1,exp:"「白洞效应」=驶出隧道瞬间，外部强光导致驾驶人瞳孔来不及收缩，出现短暂「眼前一片白」的看不清现象（约0.5-1秒）。出隧道前应适当减速，适应光线变化后再加速。戴太阳镜有助于缓解。",tip:"口诀：出隧道=白洞效应→眼前一白→看不清。出洞前减速，等眼睛适应了再加速。"},
{id:857,cat:"highway",type:"judgment",q:"2026年新建高速公路隧道普遍配备智能调光系统，隧道入口段灯光亮度可根据外部光线自动调节。",opts:["正确","错误"],ans:0,exp:"2026年新建和改建高速公路隧道大量配备智能调光系统（过渡照明），隧道入口段灯光亮度随外部光线自动调节，白天增强以缩小内外亮度差，夜间减弱避免眩光，有效缓解黑洞和白洞效应。",tip:"口诀：新隧道=智能调光。白天洞口灯更亮，晚上灯变暗——自动帮你适应光线。"},
{id:858,cat:"highway",type:"choice",q:"通过高速公路ETC车道时，车速应控制在什么范围？",opts:["不限制","不超过20km/h","不超过40km/h","不超过60km/h"],ans:1,exp:"通过ETC专用车道时车速应控制在20km/h以下，并与前车保持5米以上距离。车速过快可能导致ETC设备无法正常读取OBU（车载单元），栏杆不抬起造成急刹车甚至撞杆事故。",tip:"口诀：ETC车道=20码以下慢通过+离前车5米。快了读不到OBU，栏杆不抬你慌了。"},
{id:859,cat:"highway",type:"judgment",q:"没有安装ETC的车辆可以借用ETC车道通行。",opts:["正确","错误"],ans:1,exp:"未安装ETC（电子不停车收费系统）的车辆不得进入ETC专用车道，应走人工收费车道（MTC）。误入ETC车道会导致后车受阻、栏杆不抬、需要倒车退出——在收费站区域倒车非常危险且违规。",tip:"口诀：没装ETC=别走ETC道。走错了要倒车出来，收费站倒车=扣分+危险。"},
{id:860,cat:"highway",type:"choice",q:"高速公路服务区的主要功能不包括以下哪项？",opts:["停车休息","加油充电","餐饮如厕","车辆大修和钣金喷漆"],ans:3,exp:"高速公路服务区提供停车、加油/充电、餐饮、如厕、购物等基本服务。部分大型服务区设有简易维修点，但车辆大修、钣金喷漆等并非服务区的标准化功能。小型停车区可能只有停车和如厕功能。",tip:"口诀：服务区=吃喝拉撒+加油充电。车辆大修请下高速找修理厂。"},
{id:861,cat:"highway",type:"judgment",q:"在高速公路服务区内停车休息后，可以直接从服务区出口驶入高速行车道。",opts:["正确","错误"],ans:1,exp:"从服务区驶出后应先进入加速车道，将车速提高到60km/h以上，观察左后方交通情况，确认安全后方可并入主线行车道。服务区出口和高速入口一样，都要经过加速车道合流。",tip:"口诀：服务区出来≠直接进高速。同样要走加速车道提速到60+再并入。和进高速一个流程。"},
{id:862,cat:"highway",type:"choice",q:"在高速公路上遇到强侧风（横风）时，正确的做法是？",opts:["紧急刹车","加速冲过去","紧握方向盘，松油门缓慢减速，轻微修正方向","猛打方向抵抗侧风"],ans:2,exp:"高速+强侧风（横风）=紧握方向盘+松油门缓慢减速+轻微修正方向。急刹车或猛打方向极易导致车辆失控。注意高速公路桥梁、山口、隧道口等路段常有「注意横风」警告标志。",tip:"口诀：高速遇横风=握紧方向+松油门慢减速。急刹=失控；猛打=翻车。稳稳来。"},
{id:863,cat:"highway",type:"judgment",q:"在高速公路上错过出口时，可以在确保安全的情况下倒车回到出口。",opts:["正确","错误"],ans:1,exp:"高速公路上严禁倒车、逆行！错过出口应继续行驶至下一出口驶离高速再折返。高速公路倒车一次记12分。任何「确保安全」的倒车在高速公路上都不存在——后方车辆车速极快，倒车等于自杀。",tip:"口诀：错过出口=继续走到下一个。倒车回去=12分+可能送命。多绕十公里，好过丢驾照。"},
{id:864,cat:"highway",type:"choice",q:"高速公路上以下哪种行为是合法的？",opts:["行人在应急车道行走","在行车道上临时停车接电话","从车内向外抛撒物品","在服务区内停车休息"],ans:3,exp:"行人不得进入高速公路；行车道上禁止随意停车；向车外抛物是违法行为（记3分）。服务区内停车休息是唯一合法的选项。高速公路是全封闭道路，任何非机动车和行人均不得进入。",tip:"口诀：高速上只有服务区里能休息。其他——行人/抛物/随意停车统统违法。"},
{id:865,cat:"highway",type:"judgment",q:"高速公路上的交通管制措施包括限速、分流、封闭车道和临时关闭入口等，驾驶人必须服从。",opts:["正确","错误"],ans:0,exp:"高速公路遇大雾、暴雪、重大事故等情况时，交警部门可采取限速、分流、封闭车道、临时关闭收费站入口等管制措施。驾驶人必须服从交警指挥和电子显示屏的提示，违反管制措施将加重处罚。",tip:"口诀：高速管制=交警说了算。限速/分流/封路/关入口，必须服从。"},
{id:866,cat:"highway",type:"choice",q:"在高速公路长下坡路段，为防止刹车过热失效，正确的做法是？",opts:["挂空挡滑行","连续踩刹车控制车速","利用发动机制动（降档），配合间歇性刹车","高速冲坡"],ans:2,exp:"长下坡路段应降档利用发动机制动控制车速（手动挡挂低档，自动挡切换至手动模式或L/S档），配合间歇性刹车（点刹）。连续踩刹车会导致刹车片过热、制动液汽化，最终刹车完全失效。",tip:"口诀：高速长下坡=降档用发动机制动+点刹。死踩刹车到底=刹车片过热→刹不住。"},
{id:867,cat:"highway",type:"choice",q:"高速公路桥梁路段驾驶时，冬季最需要警惕什么？",opts:["路面湿滑","桥面可能结冰（桥面温度低于普通路面）","风速大","有行人"],ans:1,exp:"冬季高速公路桥梁路段最危险的是桥面结冰——桥面悬空，上下通风，温度比普通路面低2-3°C，其他路面未结冰时桥面可能已经结冰（黑冰，不易察觉）。看到桥梁时应提前减速、匀速通过、避免急刹和猛打方向。",tip:"口诀：冬天过桥=小心黑冰。桥面比路面先结冰，看不见的冰最危险。"},
{id:868,cat:"weather",type:"choice",q:"雨天行车时，路面附着力与干燥路面相比大约降低多少？",opts:["降低10%-20%","降低30%-40%","降低50%-70%","基本不变"],ans:2,exp:"雨天路面湿滑，摩擦系数降低约50%-70%。这意味着制动距离可能是干燥路面的2-3倍。雨天还可能出现「水滑现象」（hydroplaning），轮胎与路面之间形成水膜，导致完全失去附着力。",tip:"口诀：雨天路面摩擦力减半到减七成。刹车距离=干燥路面的2到3倍。下雨=加倍小心。"},
{id:869,cat:"weather",type:"judgment",q:"刚下雨时路面最滑，因为雨水与路面油污和灰尘混合形成一层油膜。",opts:["正确","错误"],ans:0,exp:"刚下雨的前10-20分钟路面最滑——雨水与长期沉积在路面上的油污、橡胶粉末、灰尘混合，形成一层极滑的油水混合薄膜。持续降雨后油污被冲走，路面反而相对好一些。",tip:"口诀：刚下雨时比下雨中更滑。雨水+油污=天然润滑剂。头20分钟最危险。"},
{id:870,cat:"weather",type:"choice",q:"大雨天气在高速公路上行驶，能见度极低时正确的做法是？",opts:["加速驶离雨区","开启双闪、近光灯、雾灯，降低车速，从最近出口驶离高速或进入服务区","靠边停在应急车道等雨停","继续以原速行驶"],ans:1,exp:"大雨导致能见度极低时应开启近光灯、雾灯、必要时开启危险报警闪光灯，大幅降低车速，最好从最近出口驶离高速或在服务区等待雨势减小。暴雨时继续高速行驶极其危险。",tip:"口诀：大雨=灯全开+慢慢开+能下高速就下。硬着头皮冲=拿命赌。"},
{id:871,cat:"weather",type:"choice",q:"雨天驾驶时发生「水滑」（hydroplaning）现象，正确的处理方法是？",opts:["猛踩刹车","急打方向避让","紧握方向盘，松油门让车速自然降低","加速冲过去"],ans:2,exp:"水滑（水膜滑行）=轮胎与路面之间形成一层水膜，车辆完全失去转向和制动能力。此时任何猛打方向或急刹车都极其危险，正确做法是紧握方向盘保持车辆直线行驶，松开油门让车速自然降低，等待轮胎重新接触路面。",tip:"口诀：水滑=握紧方向+松油门+别刹车别打方向。等水膜破了轮胎着地就好了。"},
{id:872,cat:"weather",type:"judgment",q:"暴雨天气在高速公路上应当开启远光灯以提高可见度。",opts:["正确","错误"],ans:1,exp:"暴雨天开远光灯反而更糟——远光在雨滴上产生强烈散射和反射，形成「白墙效应」，驾驶人眼前一片白茫茫，反而什么也看不见。雨天应使用近光灯+雾灯。",tip:"口诀：暴雨=禁止远光。远光照雨滴=眼前白光一片（白墙效应）。近光+雾灯才是正确组合。"},
{id:873,cat:"weather",type:"choice",q:"冰雪路面驾驶时，最关键的驾驶原则是什么？",opts:["快速通过","所有操作都要「轻柔」——慢加速、慢转向、慢刹车","猛踩油门增加牵引力","挂空挡滑行"],ans:1,exp:"冰雪路面附着力极低，任何突然的操作（急加速、急打方向、急刹车）都会打破轮胎与冰面的脆弱附着平衡导致失控。核心原则=所有动作都要轻柔渐进——「慢」字当头。",tip:"口诀：冰雪路面=慢字诀。慢加油、慢打方向、慢刹车。一切动作都比平时慢半拍。"},
{id:874,cat:"weather",type:"judgment",q:"冰雪路面起步时车轮打滑，应加大油门摆脱打滑状态。",opts:["正确","错误"],ans:1,exp:"车轮打滑时加大油门只会让情况更糟——车轮高速空转使冰面融化形成更滑的水膜（冰上加水），车辆反而更难起步。正确做法：手动挡用二档起步（降低扭矩），自动挡选择雪地模式，轻踩油门，必要时在驱动轮下垫砂石或装防滑链。",tip:"口诀：冰上打滑=别轰油门。越轰越滑（冰面变水膜）。二档起步/雪地模式+轻踩油门。"},
{id:875,cat:"weather",type:"choice",q:"在冰雪路面上，制动距离通常是干燥路面的多少倍？",opts:["1-2倍","3-4倍","5-10倍","基本不变"],ans:2,exp:"冰雪路面摩擦系数极低（约为干燥路面的1/5到1/10），制动距离可达干燥路面的5-10倍。例如干燥路面100km/h制动距离约40米，冰雪路面可能需要200-400米。这就是为什么冰雪天必须大幅降低车速和增大跟车距离。",tip:"口诀：冰雪路刹车距离=平时5到10倍。平时40米刹住→冰雪要200-400米。车速必须一降再降。"},
{id:876,cat:"weather",type:"judgment",q:"在冰雪路面行驶时应该降低轮胎胎压以增加接触面积，提高附着力。",opts:["正确","错误"],ans:1,exp:"降低胎压并不会显著增加冰雪路面的附着力，相反会增加轮胎磨损和爆胎风险。正确做法：使用冬季轮胎（雪地胎）或安装防滑链，保持标准胎压。冬季轮胎的花纹设计和橡胶配方可在低温下保持弹性并提供更好抓地力。",tip:"口诀：冰雪路面别放气降压。装防滑链/换雪地胎才是正确操作。保持标准胎压。"},
{id:877,cat:"weather",type:"choice",q:"车辆在冰雪路面上坡时，以下做法正确的是？",opts:["加速冲坡","低档匀速上坡，避免中途停车或换挡","挂高速档","跟紧前车借力上坡"],ans:1,exp:"冰雪路面爬坡=低档位（大扭矩但低轮速）+匀速+不要在半坡停车或换挡（停车后可能无法再起步）。上坡前应预判坡道长度和坡度，确认前方无阻挡后一气呵成。跟车太近可能因前车滑坡而相撞。",tip:"口诀：冰雪上坡=低档匀速一口气上去。半坡停下来就上不去了。别紧跟，前车可能溜。"},
{id:878,cat:"weather",type:"choice",q:"雾天驾驶时，能见度低于多少米应开启雾灯？",opts:["500米","300米","200米","100米"],ans:2,exp:"能见度低于200米时应开启雾灯（前雾灯+后雾灯）、近光灯、示廓灯和前后位灯。后雾灯穿透力极强（红色高亮度），能让后车在雾中远距离发现你的车辆。能见度改善后应及时关闭后雾灯以免影响后车。",tip:"口诀：能见度<200米→开雾灯。后雾灯=红色高亮穿透雾。天晴了记得关，晃后车眼。"},
{id:879,cat:"weather",type:"judgment",q:"能见度低于50米时，在高速公路上行驶速度不得超过30km/h。",opts:["正确","错误"],ans:0,exp:"高速公路雾天「三速三距」规则：能见度<200米→车速≤60km/h，距前车≥100米；能见度<100米→车速≤40km/h，距前车≥50米；能见度<50米→车速≤30km/h，尽快驶离高速。",tip:"口诀：能见度200→60→100；100→40→50；50→30→快下高速。三级递减，数字规律好记。"},
{id:880,cat:"weather",type:"choice",q:"高速公路上能见度低于50米时，以下做法正确的是？",opts:["开启远光灯","车速不超过30km/h，开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯，尽快从最近出口驶离","继续以原速度行驶","在应急车道等待"],ans:1,exp:"能见度低于50米属于极恶劣天气，应开启全部灯光（雾灯+近光+示廓+前后位灯+双闪），车速降至30km/h以下，尽快从最近出口驶离高速公路或在服务区停车等待。",tip:"口诀：能见度<50米=全灯亮+30码以下+赶紧下高速。这种天继续开=蒙眼狂奔。"},
{id:881,cat:"weather",type:"judgment",q:"雾天行车应多使用喇叭，以引起其他车辆和行人的注意。",opts:["正确","错误"],ans:0,exp:"雾天视线受阻，适时的喇叭声可以帮助其他车辆和行人判断你的位置和距离——「听声辨位」。特别是在通过路口、弯道、人行横道等位置时，鸣喇叭是一种有效的安全补充手段。但不应持续长时间鸣喇叭造成噪音污染。",tip:"口诀：雾天=多按喇叭。看不见就让人听见。经过路口/弯道时按一声，听到对方回应就心中有数。"},
{id:882,cat:"weather",type:"choice",q:"雾天驾驶时前挡风玻璃内侧起雾，正确的除雾方法是？",opts:["用抹布边开边擦","开启空调暖风吹玻璃+外循环，或开启前挡除雾功能","打开车窗让风吹","关闭所有空调"],ans:1,exp:"挡风玻璃起雾=车内湿度大+内外温差导致水汽凝结。最快除雾=空调暖风+吹前挡风玻璃+外循环（引入干燥空气）。部分车型有「一键除雾」按钮（扇形+三条气流图案）。注意除雾期间可能短暂加重雾气，应减速或靠边。",tip:"口诀：玻璃起雾=暖风吹前挡+外循环。一键除雾按钮=扇形+三条气流。不要边开边擦。"},
{id:883,cat:"weather",type:"choice",q:"沙尘暴天气驾驶时，错误的做法是什么？",opts:["开启前照灯、雾灯和示廓灯","减速慢行","开启远光灯","保持安全车距"],ans:2,exp:"沙尘暴中开远光灯同样会产生「光幕效应」——强光在沙尘颗粒上反射，形成一片光幕，反而降低能见度。应使用近光灯+雾灯+示廓灯，减速慢行，保持更远的安全距离。",tip:"口诀：沙尘暴=禁远光（同雾天）。开了远光=沙尘反光=眼前一片黄。近光+雾灯才是正确的。"},
{id:884,cat:"weather",type:"judgment",q:"高温天气长时间驾驶容易导致「热疲劳」，应每2小时停车休息一次。",opts:["正确","错误"],ans:0,exp:"高温天气下人体更易疲劳和脱水，热疲劳会导致注意力下降、反应迟钝。建议每2小时或感到困倦时立即停车休息，补充水分，用冷水洗脸提神。热疲劳+驾驶=重大安全隐患。",tip:"口诀：高温驾驶=2小时必休息。热疲劳=反应变慢=容易出事。多喝水，常休息。"},
{id:885,cat:"weather",type:"choice",q:"高温天气长时间停车时，车内不能放置哪些物品？",opts:["矿泉水","打火机、碳酸饮料罐、充电宝、香水等含酒精物品","纸巾","遮阳挡"],ans:1,exp:"夏季烈日下密闭车内温度可升至70°C以上——打火机（液化气膨胀爆炸）、碳酸饮料罐（CO2膨胀炸裂）、充电宝（锂电池高温膨胀起火）、含酒精香水（挥发自燃）均为高危物品。矿泉水瓶也可能形成凸透镜效应聚焦阳光引燃座椅。",tip:"口诀：夏天车内=烤箱。打火机/可乐/充电宝/香水=定时炸弹。下车带走这些东西。"},
{id:886,cat:"weather",type:"judgment",q:"寒冷天气冷车启动后应立即高速行驶，使发动机快速升温。",opts:["正确","错误"],ans:1,exp:"冷车启动后机油粘度大、流动性差，立即高速行驶会加剧发动机磨损。应原地热车30秒至1分钟（不宜过长），然后低速行驶（不超过2000-2500转）2-3公里，待水温表指针开始上升后再正常驾驶。",tip:"口诀：冬天启动=原地热车30秒→低速走2-3公里→水温上来再正常开。别一启动就飙。"},
{id:887,cat:"weather",type:"choice",q:"冬季在高速公路上遭遇「团雾」（局部浓雾）时正确的做法是？",opts:["加速冲出团雾区","急踩刹车","开启全部灯光，大幅减速，寻找机会驶离高速或进入服务区","保持原速"],ans:2,exp:"团雾=能见度可能从几百米骤降至十几米的局部浓雾，被称为「高速杀手」。遇到团雾应：开全部灯光+大幅减速+不要急刹（防后车追尾）+尽快驶离高速。团雾来得快去得也快，但每年都造成大量连环追尾事故。",tip:"口诀：团雾=瞬间致盲→全灯亮+慢慢减速+下高速。别冲，团雾可能很长一段。高速杀手非浪得虚名。"},
{id:888,cat:"weather",type:"choice",q:"山区道路下长坡时，自动挡车辆的最佳操作是什么？",opts:["一直挂D档踩刹车","切换至L档或手动模式低档位，利用发动机制动","挂N档滑行","频繁切换D和R档"],ans:1,exp:"山区长下坡：自动挡车辆应切换至L档（低速档）、S档或手动模式的2-3档，利用发动机制动降低刹车系统负荷。一直D档踩刹车会导致刹车热衰减甚至失效。严禁N档滑行——失去发动机制动且变速箱润滑不足。",tip:"口诀：自动挡下长坡=挂L/S档或手动低档。D档死踩刹车=刹车片烧掉。N档滑行=找死。"},
{id:889,cat:"weather",type:"judgment",q:"山区道路会车时，靠近山体一侧的车辆应让行靠近悬崖一侧的车辆。",opts:["正确","错误"],ans:1,exp:"山区窄路会车=靠近山体一侧的车辆有天然「靠山」可避让，靠近悬崖一侧的车辆没有避让空间，若被挤到路缘极易坠崖。因此靠近山体的车辆应主动让行。这是山区会车的安全原则。",tip:"口诀：靠山让靠崖——因为靠崖的没地方退，退了就下去了。山体侧有安全冗余，应该主动让。"},
{id:890,cat:"weather",type:"choice",q:"夜间行车时对方来车未关闭远光灯，正确的做法是？",opts:["也用远光灯回敬对方","视线右移避开对方灯光，减速或靠右停车让行","闭眼通过","加速冲过去"],ans:1,exp:"遭遇对向远光灯眩目（远光狗）=视线向右偏移看路边标线或路缘（避开对方灯光直射）+必要时减速或靠右停车让对方先行。用远光回敬（斗光）只会让两个人都看不清，增加事故风险。",tip:"口诀：被远光晃=视线往右看路边+减速。别斗光（双方都瞎了=撞车）。让远光狗先走。"},
{id:891,cat:"weather",type:"judgment",q:"夜间在没有路灯或照明不良的道路上行驶，应使用远光灯。",opts:["正确","错误"],ans:0,exp:"夜间无路灯或照明不良时，应使用远光灯以获得足够的视距。但遇对向来车150米内应改用近光灯，跟车行驶时也应用近光灯，通过路口应交替使用远近光灯示意。",tip:"口诀：没灯的路=开远光。但有来车150米内+跟车=切近光。该亮就亮，该关就关。"},
{id:892,cat:"weather",type:"choice",q:"夜间会车时，应在距对向来车多少米外改用近光灯？",opts:["50米","100米","150米","200米"],ans:2,exp:"夜间会车应在距对向来车150米外将远光灯改为近光灯。150米是法规规定的安全距离——既保证了对向来车不被眩目，又给自己留出了足够的反应时间。",tip:"口诀：会车改近光=150米。和高速放警示牌距离一样，一个数字记住两件事。"},
{id:893,cat:"weather",type:"judgment",q:"夜间通过有交通信号灯控制的交叉路口时，应交替使用远近光灯示意。",opts:["正确","错误"],ans:0,exp:"夜间通过路口（无论是否有信号灯控制）应交替使用远近光灯（闪灯）示意，提醒其他交通参与者注意。这是夜间行车的标准操作——「闪灯示意，减速通过」。",tip:"口诀：夜里过路口=闪灯示意（远近光交替）+减速。一明一暗引起别人注意。"},
{id:894,cat:"weather",type:"choice",q:"泥泞道路行驶时，以下做法正确的是？",opts:["高速通过","使用中低速档，匀速通过，避免换挡和停车","空挡滑行","急打方向绕过泥坑"],ans:1,exp:"泥泞道路附着力低，应使用中低速档+匀速通过+避免中途换挡或停车（泥泞中停车可能无法再起步）。保持方向盘稳定，避免急打方向。若车轮打滑空转，应倒车退出另选路线，不可猛加油门。",tip:"口诀：泥路=低速档+匀速+别停。停车=陷车。打滑了倒车换路，别硬刨。"},
{id:895,cat:"weather",type:"judgment",q:"涉水行驶时一旦发动机熄火，应立即重新启动发动机驶离积水区。",opts:["正确","错误"],ans:1,exp:"涉水熄火后绝对不可以重新启动发动机！水可能已经进入气缸（水不可压缩），重新启动会造成「顶缸」——连杆弯曲、缸体破裂等毁灭性损坏，且保险公司对涉水二次启动造成的损坏不予赔偿。正确做法：断电、下车、拨打救援电话等待拖车。",tip:"口诀：涉水熄火=千万别再点火！再启动=发动机报废（顶缸）+保险不赔。下车等拖车。"},
{id:896,cat:"weather",type:"choice",q:"车辆通过积水路段前，以下哪项做法是错误的？",opts:["停车观察水位深度","参考前车通过情况","确认水深不超过排气管高度即可快速通过","低档匀速通过"],ans:2,exp:"涉水深度应以发动机进气口高度为参考（不是排气管），水深超过半个车轮或保险杠下沿时就应谨慎。正确做法：停车观察水位→参考其他车辆通过情况→确认水深安全→挂低档匀速通过（避免激起水浪进入进气口）。快速冲过会激起水浪，反而增加进水风险。",tip:"口诀：涉水看进气口高度（不是排气管）。水深超半个轮子就别过。低档匀速慢慢过，别冲。"},
{id:897,cat:"weather",type:"judgment",q:"夜间行车时，如果灯光照射距离由远变近，说明前方是上坡路段。",opts:["正确","错误"],ans:0,exp:"车灯照射距离变化可辅助判断道路地形：照射距离由远变近→进入上坡（路面「拱起」遮挡灯光）；由近变远→下坡或进入平路；突然消失→前方可能有急弯或陡坡顶点。利用灯光变化提前预判路况是夜间驾驶的重要技能。",tip:"口诀：灯光近=上坡（路面抬起来挡住了光）；灯光远=下坡；灯光消失=急弯/坡顶。夜间灯光是眼睛的延伸。"},
{id:898,cat:"weather",type:"choice",q:"大风天气在高速公路上行车，哪种车辆受横风影响最大？",opts:["小型轿车","大型货车、厢式货车、大巴等侧面面积大的车辆","摩托车","所有车辆影响相同"],ans:1,exp:"横风对侧面面积大的车辆（大型货车、厢式货车、大巴、面包车等）影响最大——侧面像一面帆，横风可以将车辆吹离车道甚至吹翻。小型轿车受横风影响相对较小。桥梁、山口、隧道口是高横风区域。",tip:"口诀：横风=侧面面积越大越危险。大货车/大巴=大风天=移动的帆。小车虽然稳但也要小心。"},
{id:899,cat:"weather",type:"judgment",q:"在碎石或砂砾路面行驶时，应适当降低车速并增大跟车距离，以防前车卷起的石子打碎挡风玻璃。",opts:["正确","错误"],ans:0,exp:"砂石路面：前车轮胎可能卷起石子（像子弹一样射向后车），打碎挡风玻璃或砸伤车漆。应拉大跟车距离（至少是平时的2倍）+降低车速。同时砂石路面附着力低，制动距离变长，更需加大跟车距离。",tip:"口诀：砂石路=离前车远点。前车轮胎=石子发射器。跟太近=挡风玻璃遭殃。"},
{id:900,cat:"weather",type:"choice",q:"夜间在窄路、窄桥上与非机动车会车时，应使用什么灯光？",opts:["远光灯","近光灯","关闭所有灯光","交替使用远光和近光"],ans:1,exp:"窄路窄桥+非机动车=必须用近光灯。远光灯会使骑车人因眩目而无法看清路面边缘，可能骑车摔倒——骑车人摔倒了，机动车驾驶人通常要承担责任。保护对方就是保护自己。",tip:"口诀：窄路遇上骑车人=近光灯（别闪远光）。你一晃他倒了就是你的责任。"},
{id:901,cat:"weather",type:"judgment",q:"在结冰路面上行驶时，应尽量沿着前车车辙印记行驶，因为车辙处冰已被压碎，附着力相对较好。",opts:["正确","错误"],ans:0,exp:"结冰路面沿着前车车辙行驶=利用前车已压碎冰面的轨迹获得更好的附着力。但应注意车辙可能积水（冰融化后再结冰更滑），同时不要盲目跟随——判断车辙是否安全后再跟进。",tip:"口诀：冰面跟着车辙走——别人压过的路比自己开新路安全。但注意车辙可能积水结暗冰。"},
{id:902,cat:"weather",type:"choice",q:"以下哪种路面状况最容易被驾驶人忽视且极其危险？",opts:["明显积水","积雪","黑冰（透明薄冰，路面看起来只是湿的）","泥泞"],ans:2,exp:"黑冰（Black Ice）=透明薄冰层，路面看起来只是湿润反光而非结冰，驾驶人毫无防备以正常速度驶过时突然失去控制。常出现在凌晨和桥面。遇到路面「异常反光」时应高度警觉，可能那就是要命的黑冰。",tip:"口诀：路面异常反光=可能是黑冰。看起来是水其实是冰。凌晨+桥面=黑冰高发，格外小心。"},
{id:903,cat:"weather",type:"judgment",q:"路面有油渍时（如加油站附近、事故泄漏），应降低车速、避免在该区域刹车或急转向。",opts:["正确","错误"],ans:0,exp:"油渍路面=几乎零附着力的极端危险路面。看到路面有彩色反光（油膜）时应提前减速，匀速直线通过，避免在油渍区域刹车、加速或转向。摩托车在油渍路面几乎100%会摔倒。",tip:"口诀：路面彩色反光=油渍→极度湿滑。匀速直线通过，别刹车别转向。摩托车手尤其小心。"},
{id:904,cat:"weather",type:"choice",q:"夏季高温天气长途驾驶前，应特别检查以下哪项？",opts:["音响系统","轮胎胎压和胎温、冷却液液位","座椅舒适度","车漆光泽"],ans:1,exp:"夏季高温长途驾驶前重点检查：轮胎（胎压、磨损、有无鼓包——高温+高速=爆胎高发）、冷却液（是否充足，防止开锅）、空调系统、制动系统。胎压应调整到厂家推荐值（不是降低胎压防爆胎）。",tip:"口诀：夏天跑长途=重点查轮胎（防爆胎）+冷却液（防开锅）。保持标准胎压，别放气。"},
{id:905,cat:"weather",type:"judgment",q:"冬季应使用与夏季相同的玻璃水，无需更换。",opts:["正确","错误"],ans:1,exp:"冬季必须更换防冻玻璃水（冰点低于当地最低气温），夏季玻璃水在低温下结冰会冻裂玻璃水储液壶和管路，且在挡风玻璃上结冰严重影响视线。同理冷却液（防冻液）也应检查冰点。",tip:"口诀：冬天换防冻玻璃水。夏天用的水=冬天结冰→撑破水壶+玻璃上结冰=啥也看不见。"},
{id:906,cat:"weather",type:"choice",q:"车辆在湿滑路面发生侧滑时，正确的纠正方向是？",opts:["向侧滑方向打方向","向侧滑反方向打方向","刹车到底","加速纠正"],ans:0,exp:"后轮侧滑（甩尾）：向侧滑方向（车尾偏移的方向）轻打方向盘纠正——即「车尾往哪滑，方向往哪打」。前轮侧滑：松油门减速，向侧滑反方向轻微修正。注意任何纠正动作都要轻柔，过度修正会导致反向侧滑（钟摆效应）。",tip:"口诀：甩尾=车尾往哪甩，方向往哪打。轻柔修正，别用力过猛（用力过猛=反向甩尾）。前轮滑=松油门+反向微调。"},
{id:907,cat:"weather",type:"judgment",q:"恶劣天气下能见度降低的根本解决办法是开启远光灯。",opts:["正确","错误"],ans:1,exp:"恶劣天气（雨、雪、雾、沙尘）中开远光不但不能提高能见度，反而因光线被水滴/雪花/沙尘反射形成「光幕效应」，能见度更差。正确做法：近光灯+雾灯+降低车速+增大跟车距离。真正的解决方法是减速或驶离。",tip:"口诀：恶劣天气=禁远光（光幕效应=越照越看不清）。近光+雾灯+慢行才是正道。"},
{id:908,cat:"emergency",type:"choice",q:"高速行驶中发生前轮爆胎时，正确的应急处置方法是？",opts:["猛踩刹车","紧握方向盘，松油门，待车速降低后轻踩刹车，驶入应急车道","急打方向修正","加速行驶到服务区"],ans:1,exp:"前轮爆胎（转向轮爆胎）最危险——车辆会突然向爆胎一侧强烈偏转。正确做法：双手紧握方向盘尽力控制方向（不要被爆胎的偏转力带走）+松油门让车速自然下降+不要急刹车（急刹会加剧偏转）+车速降到较低时轻踩刹车靠边停车。",tip:"口诀：前轮爆胎=死死握住方向+松油门+别急刹。爆胎瞬间方向盘会猛拽，握住了别松手。"},
{id:909,cat:"emergency",type:"choice",q:"后轮爆胎与前轮爆胎相比，哪种更危险？",opts:["后轮爆胎更危险","前轮爆胎更危险","一样危险","都不危险"],ans:1,exp:"前轮爆胎比后轮爆胎更危险——前轮是转向轮，爆胎瞬间方向控制力丧失，车辆「不听使唤」地偏转。后轮爆胎主要表现为车尾摆动，相对容易控制。但无论前后轮爆胎，都应握稳方向盘、松油门、不要急刹。",tip:"口诀：前轮爆胎>后轮爆胎（危险度）。前轮=管方向，爆了方向就失控。后轮=管稳定性，爆了车尾摆。"},
{id:910,cat:"emergency",type:"judgment",q:"发生爆胎后应立即紧急制动，尽快将车辆停下。",opts:["正确","错误"],ans:1,exp:"爆胎后急刹车是最大的错误——爆胎瞬间车辆已经处于不稳定状态，急刹车会打破仅存的车轮附着力平衡，导致车辆完全失控甚至翻车。正确做法：握稳方向盘+松油门+利用发动机制动+车速降低后轻踩刹车。",tip:"口诀：爆胎=严禁急刹。急刹=失控甚至翻车。松油门让车自己慢下来再轻刹。"},
{id:911,cat:"emergency",type:"choice",q:"行车中突然发现刹车踏板踩下去没有阻力（刹车失灵），首先应该怎么做？",opts:["拉手刹","反复踩刹车踏板尝试恢复制动压力，同时降档利用发动机制动","熄火","跳车"],ans:1,exp:"刹车失灵（刹车踏板软、无阻力）=首先反复快速踩刹车踏板（可能只是制动液汽化，多次踩踏可恢复部分压力）+同时降档利用发动机制动减速+如仍无效再使用手刹（电子手刹持续拉起）。不要立即拉手刹——手刹制动力有限且容易抱死后轮。",tip:"口诀：刹车失灵=先猛踩几脚试试+降档。不行再拉手刹。反复踩=可能把「气」挤出去恢复压力。"},
{id:912,cat:"emergency",type:"judgment",q:"下长坡时刹车突然完全失效，可以利用路侧的紧急避险车道（砂石上坡道）进行紧急停车。",opts:["正确","错误"],ans:0,exp:"紧急避险车道（刹车失灵缓冲区）=一段铺满砂石的上坡岔道，专门用于刹车失灵的车辆紧急停车。发现刹车失灵且前方有避险车道时应果断驶入——砂石的滚动阻力和上坡的重力共同作用可使车辆快速停下。宁可损坏车辆也要保全人命。",tip:"口诀：避险车道=刹车失灵救命道。沙石+上坡→车自然停下来。看见了就果断冲进去，车比命便宜。"},
{id:913,cat:"emergency",type:"choice",q:"使用手刹（驻车制动）辅助紧急制动时，以下哪种方法是正确的？",opts:["猛拉手刹到底","反复拉放电子手刹按钮，或传统手刹缓慢拉起到刚好不抱死的程度","只拉一半","不拉手刹"],ans:1,exp:"使用手刹辅助紧急制动：电子手刹=持续拉起不放（系统会以最大但可控的制动力减速，同时ESP介入保持稳定）。传统手刹=缓慢拉起到后轮刚好不抱死的程度，拉太猛后轮抱死会导致甩尾。",tip:"口诀：电子手刹=持续拉起不松（智能制动）；传统手刹=慢慢拉，别一把拉死（拉死后轮=甩尾）。"},
{id:914,cat:"emergency",type:"judgment",q:"转向突然失灵时，应紧急刹车将车停下。",opts:["正确","错误"],ans:1,exp:"转向失灵时急刹车可能加剧车辆失控——车辆可能冲向不可预测的方向。正确做法：松油门减速+开启双闪+利用剩余的转向能力尝试靠边+在车速降低后轻踩刹车停车。如果完全无法转向，应松油门让车自然减速并报警。",tip:"口诀：方向失灵=松油门+开双闪+尽量靠边。别急刹——方向失控+急刹=车辆可能打转。"},
{id:915,cat:"emergency",type:"choice",q:"驾驶中发动机舱突然冒烟起火，首先应做什么？",opts:["立即打开发动机盖灭火","立即靠边停车、熄火、断电、迅速撤离并报警","加速行驶到服务区","往发动机盖上浇水"],ans:1,exp:"发动机舱冒烟/起火=立即靠边停车→熄火→切断电源→车上人员全部撤离到安全距离（50米以上）→拨打119报警。绝对不要贸然打开发动机盖——打开瞬间大量氧气涌入会导致火势瞬间爆燃，可能造成严重烧伤。",tip:"口诀：发动机冒烟=停车+熄火+断电+人跑远+报警。别开盖！开盖=氧气进=火炸了。"},
{id:916,cat:"emergency",type:"judgment",q:"车辆起火时可以用水扑灭油类和电器火灾。",opts:["正确","错误"],ans:1,exp:"油类火灾（汽油、机油）用水灭=油浮在水上继续燃烧+水沸腾飞溅扩大火势。电器火灾用水灭=触电危险。正确做法：使用车载灭火器（干粉或二氧化碳灭火器）对准火焰根部喷射。发动机舱冒烟时通过进气格栅缝隙喷射灭火剂，不要打开舱盖。",tip:"口诀：车辆起火=别用水（油火水灭不了，电火水会触电）。车载干粉灭火器=对准火焰根部喷。通过格栅缝喷，别开盖。"},
{id:917,cat:"emergency",type:"choice",q:"新能源车（电动车）电池起火的正确处理方式是？",opts:["用水灭火","使用大量水持续冷却降温，同时拨打119并告知是电动车火灾","用干粉灭火器就够了","不管它自己灭"],ans:1,exp:"电动车电池火灾（热失控）=极其危险——锂电池热失控会持续产生高温并复燃（温度可达1000°C以上），普通灭火器难以彻底扑灭。正确做法：使用大量水持续冷却电池组降温+拨打119并明确告知是「电动车电池火灾」+人员远离（有毒烟气含氟化氢等剧毒物质）。",tip:"口诀：电车起火=大量水冷却+打119说清楚是电动车。电池火会反复烧，水要一直浇降温。人远离毒烟。"},
{id:918,cat:"emergency",type:"judgment",q:"车辆落水后应在水位上升到车窗高度时再尝试开门逃生，因为内外水压差小更容易打开车门。",opts:["正确","错误"],ans:0,exp:"车辆落水后不要立即开门——车外水压远大于车内，门根本推不开。应等待水进入车内，当车内水位接近车外水位（内外水压差减小时），车门即可打开。在此之前应解开安全带、打开或砸碎侧窗玻璃逃生（侧窗比挡风玻璃容易砸碎）。",tip:"口诀：落水=别急着开门（推不开的）。等水快灌满时内外压力平衡→开门逃。之前先开窗/砸窗。"},
{id:919,cat:"emergency",type:"choice",q:"车辆落水后砸窗逃生，应砸玻璃的什么位置？",opts:["玻璃中央","玻璃四个角或边缘","玻璃底部","随便哪都行"],ans:1,exp:"钢化玻璃的四个角和边缘是应力集中的脆弱点，容易砸碎。中央部位反而有弹性不易碎。使用安全锤（尖头）或头枕金属插杆对准侧窗玻璃边角用力敲击。不要砸挡风玻璃——挡风玻璃是夹层玻璃，即使碎了也不会散开。",tip:"口诀：砸窗=砸四角/边缘（不是中央）。安全锤尖头对准角落使劲。侧窗可砸，挡风玻璃砸不穿。"},
{id:920,cat:"emergency",type:"judgment",q:"油门踏板被脚垫卡住无法回位时，应立即低头用手去拉油门踏板。",opts:["正确","错误"],ans:1,exp:"油门卡住时低头用手拉=视线离开前方=极其危险。正确做法：用脚尝试向上勾油门踏板（也许只是脚垫顶住了边缘）+立即踩刹车+挂入N档（空挡）切断动力+打双闪靠边停车+熄火。自动挡车辆在N档时发动机会空转但不会加速。",tip:"口诀：油门卡住=别低头看。脚往上勾+踩刹车+挂N档+靠边停。先切断动力再处理。"},
{id:921,cat:"emergency",type:"choice",q:"行车中突然有动物冲入车道，正确的做法是？",opts:["猛打方向避让","急刹车避让","紧握方向盘，点刹减速，避免急打方向（宁撞勿翻）","加速冲过去"],ans:2,exp:"突发动物横穿=握稳方向盘+点刹减速+不要急打方向避让。高速行驶中急打方向避让动物可能导致车辆失控、翻车或冲入对向车道——「宁撞勿翻」是国际通用的安全原则。车辆稳定可控>避让动物。小动物可适度减速通过。",tip:"口诀：突然窜出动物=减速但别猛打方向。宁撞勿翻——翻车=你可能死，撞动物=保险赔。握稳方向是第一。"},
{id:922,cat:"emergency",type:"judgment",q:"行车中挡风玻璃突然碎裂遮挡视线时，应立即紧急刹车。",opts:["正确","错误"],ans:1,exp:"挡风玻璃碎裂时立即急刹可能导致后车追尾。正确做法：保持冷静+松油门减速+根据残余视线和两侧后视镜判断位置+开启双闪+缓慢靠边停车。如果玻璃完全无法看透，可用力将碎裂的挡风玻璃向外推出（夹层玻璃不会散落伤人）以获得前方视野。",tip:"口诀：挡风玻璃碎了=别急刹。松油门+看后视镜+开双闪+慢慢靠边。急了后车会追你尾。"},
{id:923,cat:"emergency",type:"choice",q:"车辆在高速公路行车道上突然熄火无法重新启动，首先应该做什么？",opts:["下车推车","开启危险报警闪光灯，利用车辆惯性滑行至应急车道；无法移动时车上人员立即撤离至护栏外","坐在车内等待救援","在车后挥手拦车求助"],ans:1,exp:"高速行车道上突然熄火=立即开双闪+利用剩余惯性尽力滑行到应急车道或路肩。若无法移动（停在行车道上），车上所有人员立即撤离到护栏外+150米外放警示牌+拨打12122。绝对不要试图在行车道上推车或拦车。",tip:"口诀：高速突然熄火=开双闪+往应急车道滑。滑不过去=人马上翻护栏外。行车道不是修车的地方。"},
{id:924,cat:"emergency",type:"judgment",q:"驾驶途中突然感到剧烈胸痛或身体严重不适，应尽力将车安全停靠路边，再拨打120求救。",opts:["正确","错误"],ans:0,exp:"驾驶中突发严重疾病（如心梗、脑卒中等）=用最后的意识尽力将车安全停靠路边（保自己命也保他人命）+开双闪+拨打120并报出准确位置。千万不要硬撑着继续开——突然失去意识会导致严重事故。",tip:"口诀：开车时突然发病=拼命先把车靠边停好。停住了再叫120。硬撑=失去意识=车毁人亡。"},
{id:925,cat:"emergency",type:"choice",q:"运输危险化学品的车辆发生泄漏时，其他车辆应该怎么做？",opts:["靠近查看","迅速驶离泄漏区域，向上风方向撤离，严禁烟火","停车拍照","用水冲洗泄漏物"],ans:1,exp:"危化品车辆泄漏=其他车辆应立即远离+向上风（逆风）方向撤离（远离毒气扩散方向）+严禁任何火源（抽烟、打火机、电器开关等都可能引爆可燃气体）+拨打122和119报警并说明泄漏物质（看车辆上的危险品标识牌）。",tip:"口诀：危化品泄漏=往上风方向跑+禁止一切火源。风向=逃生方向，逆着风跑。"},
{id:926,cat:"emergency",type:"judgment",q:"下长坡时如果闻到浓烈的焦糊味，说明刹车片过热，应立即靠边停车让刹车系统自然冷却。",opts:["正确","错误"],ans:0,exp:"下长坡时闻到焦糊味=刹车片/刹车盘严重过热，摩擦材料开始焦化——这是刹车即将失效的前兆。应立即在安全位置靠边停车，让刹车系统自然冷却（不要往刹车盘上浇水——骤冷会导致刹车盘变形甚至开裂）。冷却后检查刹车效能再继续行驶。",tip:"口诀：下坡闻到焦味=刹车片烧焦了。赶紧靠边停，自然冷却。别浇水（浇水=刹车盘炸裂）。"},
{id:927,cat:"emergency",type:"choice",q:"发生交通事故后，以下哪种情况不应移动伤者？",opts:["伤者在燃烧的车内","伤者怀疑有脊柱损伤","伤者在漏油的车辆旁","伤者在不安全的位置"],ans:1,exp:"疑似脊柱损伤（颈椎、胸椎、腰椎）的伤者=非专业人员切勿移动！不当移动可能导致永久性截瘫甚至死亡。应保持伤者原体位+保持呼吸道通畅+等待专业急救人员。其他危及生命的情况（火灾、爆炸风险、溺水等）才需要不顾脊柱风险紧急转移。",tip:"口诀：疑似脊柱伤=别动（动了可能截瘫）。只有火烧/爆炸/淹水这些马上要命的危险才搬。原地等120。"},
{id:928,cat:"emergency",type:"judgment",q:"对没有呼吸和心跳的伤员进行心肺复苏（CPR）时，按压与人工呼吸比例为30:2。",opts:["正确","错误"],ans:0,exp:"成人CPR标准=胸外按压30次+人工呼吸2次（30:2），按压频率100-120次/分钟，按压深度5-6厘米。如果施救者不愿或不具备人工呼吸条件，可以只进行不间断的胸外按压（单纯按压式CPR）。",tip:"口诀：心肺复苏=30次按压+2次吹气。按压位置=两乳头连线中点。频率=1秒2次。深度=5-6厘米。"},
{id:929,cat:"emergency",type:"choice",q:"伤员大出血时，止血带应绑在伤口的什么位置？",opts:["直接绑在伤口上","伤口近心端（靠近心脏一侧），距伤口5-10厘米","伤口远心端（远离心脏一侧）","膝关节和肘关节上"],ans:1,exp:"止血带止血=绑在出血部位的近心端（靠近心脏一侧）+距伤口5-10厘米+用衬垫保护皮肤+标记绑扎时间。每隔30-60分钟松解1-2分钟（防止肢体缺血坏死）。严禁使用铁丝、电线等无弹性材料当止血带。",tip:"口诀：止血带=伤口上方（靠近心脏那边）5-10厘米。记住绑扎时间，每半小时松1-2分钟。"},
{id:930,cat:"emergency",type:"judgment",q:"烧伤创面可以用牙膏、酱油等涂抹处理。",opts:["正确","错误"],ans:1,exp:"烧伤创面涂抹牙膏、酱油、面粉等偏方=不仅无效还增加感染风险+影响医生对烧伤深度和面积的判断。正确做法：流动冷水冲洗降温15-20分钟（化学烧伤冲洗30分钟以上）→覆盖干净纱布或保鲜膜→就医。不要刺破水泡。",tip:"口诀：烧伤=冷水冲15-20分钟+干净纱布盖。别抹牙膏酱油面粉——只会帮倒忙！"},
{id:931,cat:"emergency",type:"choice",q:"发生交通事故后，如果伤者被卡在变形的车内，以下做法正确的是？",opts:["强行拉拽将伤者拖出","拨打119（消防）请求破拆救援，同时安抚伤者","用撬棍自行破拆","不管伤者先拍照取证"],ans:1,exp:"伤者被卡车内=拨打119消防部门请求专业破拆救援。消防有液压扩张器、剪切器等专业破拆工具。自行盲目拉拽可能导致伤者二次损伤（特别是脊柱和内脏损伤）。在等待救援期间与伤者保持沟通、安抚情绪、注意保暖。",tip:"口诀：人卡住了=打119叫消防（破拆救人）。别硬拉——可能把人拉瘫痪。消防有专业工具。"},
{id:932,cat:"emergency",type:"judgment",q:"发生交通事故后车辆漏油，围观群众可以在现场吸烟，只要离车远一点就行。",opts:["正确","错误"],ans:1,exp:"车辆漏油（汽油/柴油挥发气体）+任何火源（烟头、打火机、电器开关火花）=爆炸风险。事故现场应严禁一切火源，并疏散围观群众到安全距离外。汽油挥发气体在空气中达到一定浓度遇明火即爆燃。",tip:"口诀：事故漏油=现场绝对禁火。汽油挥发气+烟头=爆炸。所有人远离+别抽烟。"},
{id:933,cat:"emergency",type:"choice",q:"夜间在普通道路上车辆故障难以移动时，警告标志应放在来车方向多少米，夜间应为多少米？",opts:["白天50米，夜间100米","白天100米，夜间150米","白天50米，夜间50米","白天150米，夜间200米"],ans:0,exp:"普通道路故障车：白天在来车方向50米外设警告标志，夜间应增加至100米外（夜间视线差，需要更长的预警距离）。高速公路统一150米。注意夜间还需开启示廓灯和后位灯。",tip:"口诀：普通路=白天50米、夜间100米。高速=无论白天黑夜均150米。夜间距离要翻倍。"},
{id:934,cat:"emergency",type:"judgment",q:"车辆在铁路道口熄火无法启动时，应迅速组织人员将车辆推离道口，无法移动时立即报警并通知铁路部门。",opts:["正确","错误"],ans:0,exp:"铁路道口熄火=立即组织所有人推车驶离道口（挂空挡推行）。如无法移动，立即拨打110（公安）和铁路应急电话（道口通常设有紧急电话或报警按钮），通报铁路部门采取紧急措施（拦停即将通过的列车）。人命关天，速度第一。",tip:"口诀：铁路道口熄火=推车离开铁轨（挂空挡推）。推不动=马上报警+通知铁路拦停火车。跟火车抢道=必死。"},
{id:935,cat:"emergency",type:"choice",q:"车辆在上坡路段熄火后溜时，正确的应急措施是？",opts:["跳车逃生","踩死脚刹+拉紧手刹+挂入1档或倒档（手动挡）/P档（自动挡）+用石块垫住车轮","猛踩油门","打方向让车撞向山体"],ans:1,exp:"上坡后溜=立即踩死脚刹+拉紧手刹+挂入1档或倒档（利用发动机制动辅助停车）+在车轮下垫三角木或石块防止继续后溜。自动挡车辆优先挂P档。如果后溜无法阻止且后方是悬崖，打方向让车侧面蹭山体减速是最后手段。",tip:"口诀：坡上后溜=脚刹+手刹+挂档+垫石头。多重制动一起上。别跳车——跳车=自己送命。"},
{id:936,cat:"emergency",type:"judgment",q:"车辆在高速公路上因燃油耗尽无法行驶，可以在应急车道内从其他车辆上抽油或购买「路边卖油」。",opts:["正确","错误"],ans:1,exp:"高速公路上严禁私自买卖燃油和自行加油。燃油耗尽应拨打12122请求高速公路救援。路边卖油=违法+燃油质量无保证（可能损坏发动机）。在高速公路上自行抽油和加油操作本身也极度危险。",tip:"口诀：高速没油=打12122等救援。别买路边油（假油+违法+危险）。出门前加满油/充满电。"},
{id:937,cat:"emergency",type:"choice",q:"车辆涉水时发动机进水熄火，应如何处理？",opts:["重新启动发动机","断电、不要重新启动、下车、拨打救援电话","挂空挡推出水面","往排气管塞布防进水"],ans:1,exp:"涉水发动机进水熄火=绝对不要重新启动（二次启动会造成发动机顶缸报废+保险不赔）。正确操作：关闭电源→不要尝试启动→人员撤离到安全处→拨打救援电话等待拖车→通知保险公司。车辆修理需拆解发动机清理积水。",tip:"口诀：涉水熄火=千万别点火。一打火=发动机报废+保险不赔。断电+下车+等拖车。"},
{id:938,cat:"emergency",type:"judgment",q:"行车中如果突然遭遇山体滑坡或落石，应立即倒车逃离。",opts:["正确","错误"],ans:1,exp:"突发山体滑坡/落石时倒车逃生往往来不及（倒车速度慢且后方可能有来车）。更安全的做法：判断落石滑坡方向→如果落石在前方从右侧山体滑落，迅速向左侧（远离山体一侧）加速逃离。如果无法逃离，停车并寻找坚固遮挡物或躲在座椅下方。",tip:"口诀：山体滑坡=别倒车（太慢）。判断滑坡方向，往远离山体那边冲。跑不掉就躲。"},
{id:939,cat:"emergency",type:"choice",q:"车辆发生侧翻后，车内人员第一步应该做什么？",opts:["立即解开安全带","先关闭发动机（熄火），检查自身和他人伤情，再有序逃生","大声呼救","用脚踹挡风玻璃"],ans:1,exp:"车辆侧翻后：第一步=熄火（防止燃油泄漏引发火灾）+评估伤情+保持冷静。如果有燃油泄漏迹象（闻到浓烈汽油味），应尽快逃生。逃生时注意不要踩踏破碎玻璃。如果车门无法打开，可用安全锤敲碎侧窗或后窗玻璃逃生。",tip:"口诀：翻车后=先熄火（防火）。再评估伤情。闻到汽油味=赶紧逃。侧窗是逃生出口（挡风玻璃敲不碎）。"},
{id:940,cat:"emergency",type:"judgment",q:"车辆在高速行驶中突然爆胎，应利用发动机制动和剩余的方向控制能力，将车辆缓慢驶入应急车道。",opts:["正确","错误"],ans:0,exp:"爆胎后正确的处理流程：握稳方向盘控制方向+松油门利用发动机制动+车速明显下降后轻踩刹车+驶入应急车道停车。核心要点=不要急刹+不要猛打方向+利用发动机制动是逐渐降低车速最安全的方式。",tip:"口诀：爆胎=握稳方向+松油门+发动机制动自然减速。慢下来了再轻刹靠边。一套流程要连贯。"},
{id:941,cat:"emergency",type:"choice",q:"使用车载灭火器时，正确的操作顺序是？",opts:["直接喷射","拔掉保险销→对准火焰根部→压下压把→左右扫射","先摇一摇再喷","对着火焰顶部喷"],ans:1,exp:"灭火器使用口诀「提拔握压扫」：①提起灭火器→②拔掉保险销→③握住喷管对准火焰根部（不是火焰顶部）→④压下压把→⑤左右扫射覆盖着火区域。站在上风方向距火源2-3米处。",tip:"口诀：灭火器=提拔握压扫。拔销→对火根→压下→扫射。站上风口，离火2-3米。"},
{id:942,cat:"emergency",type:"judgment",q:"如果发生交通事故后对方驾驶人试图驾车逃逸，应驾车追赶逼停对方车辆。",opts:["正确","错误"],ans:1,exp:"对方肇事逃逸=记下对方车牌号、车型、颜色、逃逸方向+立即报警（122）+寻找目击证人和监控。驾车追赶逃逸车辆极其危险——可能引发更严重的事故，且追赶过程中发生事故你也要承担相应责任。记住信息比冒险追赶更明智。",tip:"口诀：对方跑了=记车牌+报警。别开车追——追车=高风险+出事了你也担责。记住车牌就是最大的胜利。"},
{id:943,cat:"emergency",type:"choice",q:"在高速公路上行驶时，前方突然发生连环追尾事故，正确的应对是？",opts:["加速从旁边绕过去","立即开启双闪+点刹提醒后车+在确保安全的前提下驶入应急车道或减速停车，人撤离到护栏外","停车观看","倒车离开"],ans:1,exp:"前方突发连环追尾=第一时间开双闪警告后方来车+点刹渐进减速（不要急刹，给后车反应时间）+在安全情况下驶入应急车道或靠边+车上人员全部撤离到护栏外+报警。连环追尾后最怕的是后车刹不住继续撞上来。",tip:"口诀：前方连环撞=先开双闪提醒后车+平稳减速+人快撤护栏外。连环追尾=后面的车可能还在撞上来。"},
{id:944,cat:"emergency",type:"judgment",q:"车辆起火后，如果火势已经很大，应放弃灭火，迅速撤离到安全距离并报警。",opts:["正确","错误"],ans:0,exp:"火势较大（发动机舱大面积燃烧、车内起火蔓延等）=车载灭火器已无能为力，保命第一。迅速撤离到至少50米外（车辆可能爆炸）+拨打119+警告其他车辆远离。车可以再买，命只有一条。",tip:"口诀：大火=别救了，跑远50米+报警。油箱爆炸可不是闹着玩的。命比车值钱。"},
{id:945,cat:"emergency",type:"choice",q:"车辆在夜间无路灯路段抛锚，为防止后车追尾，除开启双闪和在来车方向设警示牌外，还可以做什么？",opts:["关闭所有灯光省电","让同车人在车后挥舞手机屏幕","穿着反光背心在来车方向挥动发光或反光物品警示","在车后点燃篝火"],ans:2,exp:"夜间抛锚=双闪+示廓灯+后位灯+警示牌+反光背心。车上人员应穿反光背心（车内应常备）到护栏外来车方向摇动发光/反光物品（手机手电筒、反光三角板等）增加预警效果。注意人员必须在护栏外，不要站在车道上。",tip:"口诀：夜间抛锚=车灯全亮+人穿反光背心在护栏外挥亮东西。让自己和车都被看见。"},
{id:946,cat:"emergency",type:"judgment",q:"运输易燃易爆物品的车辆发生事故，周围车辆和人员应迅速向上风方向撤离。",opts:["正确","错误"],ans:0,exp:"易燃易爆物品泄漏=向上风方向（逆风）撤离=毒气和可燃蒸气被风吹向下风方向，上风方向是安全的。同时严格禁止一切火源（吸烟、电器开关、拨打电话等都可能产生火花引发爆炸）。",tip:"口诀：危险品泄漏=往上风跑。上风=风往你背后吹→毒气往你前方散。记住风的方向就是逃生的反方向。"},
{id:947,cat:"emergency",type:"choice",q:"以下关于交通事故现场急救优先顺序的说法，正确的是？",opts:["先救重伤员","先救呼喊声音最大的","先救容易救出的","先止血后包扎再固定最后搬运"],ans:3,exp:"交通事故现场急救四原则=①先止血（大出血是几分钟内致命的第一杀手）→②包扎伤口（防感染）→③固定骨折（防二次损伤）→④搬运（脊柱损伤需专业搬运）。急救优先顺序：无呼吸心跳>大出血>休克>骨折>轻伤。",tip:"口诀：急救顺序=止血→包扎→固定→搬运。先处理要命的（大出血/无心跳），再处理不致命的。"},
{id:948,cat:"emergency",type:"judgment",q:"车辆落水时，如果车窗无法打开，可以用座椅头枕的金属插杆击碎侧窗玻璃。",opts:["正确","错误"],ans:0,exp:"车辆落水后电器系统短路→车窗可能无法电动降下。此时可用座椅头枕拔出后的金属插杆尖头，对准侧窗玻璃的四个角或边缘用力击打，玻璃会碎裂脱落。安全锤更好，头枕金属杆是有效的替代工具。",tip:"口诀：落水车窗打不开=拔头枕用金属杆砸侧窗角。头枕=隐藏的逃生锤。记住砸角不砸中间。"},
{id:949,cat:"emergency",type:"choice",q:"烫伤或烧伤面积较大时，正确的现场处理方式是？",opts:["涂抹烫伤膏","用流动冷水冲洗降温15-20分钟后覆盖干净纱布就医","用冰敷","刺破水泡"],ans:1,exp:"大面积烧烫伤=立即流动冷水冲洗降温15-20分钟（减少热量继续向深层组织传导）+用干净湿纱布或保鲜膜覆盖创面（保持湿润和清洁）+尽快就医。不要刺破水泡（水泡皮是天然的保护屏障），不要用冰直接敷（冰会导致血管收缩加重组织损伤）。",tip:"口诀：烫伤=冷水冲15-20分钟+干净纱布盖+去医院。别挑水泡，别用冰直接敷。"},
{id:950,cat:"emergency",type:"judgment",q:"发生交通事故后，驾驶人应当首先抢救伤员，然后报警，最后才是保护现场。",opts:["正确","错误"],ans:1,exp:"交通事故处理正确顺序：①立即停车→②保护现场（设置警示标志、拍照取证）→③抢救伤员（拨打120）→④报警（122）。保护现场是取证的关键，但人命优先——如伤者需要紧急送医，可在标记车辆和伤者位置后使用肇事车辆或拦截其他车辆送医。",tip:"口诀：事故处理顺序=停车→保护现场→救伤员→报警。救人要紧但现场也要留证据。标记位置后再送医。"},
{id:951,cat:"emergency",type:"choice",q:"对怀疑颈部受伤的伤员，以下做法正确的是？",opts:["扶起伤员让其坐起来","用双手固定伤员头部两侧，防止颈部转动，等待专业急救","让伤员自行活动颈部以判断伤情","给伤员喝水"],ans:1,exp:"怀疑颈部（颈椎）损伤=绝对固定头颈部不要有任何活动。施救者用双手扶住伤员头部两侧保持中立位+等待120专业急救人员携带颈托到来。颈椎损伤后不恰当的移动=可能造成高位截瘫（四肢瘫痪）或死亡。",tip:"口诀：疑似颈椎伤=用手固定头别动+等120。动了脖子=可能一辈子坐轮椅或直接死亡。"},
{id:952,cat:"emergency",type:"judgment",q:"如果伤者的断肢（手指、手臂等）掉在地上，应将其放入冰水中保存，随伤者一起送医。",opts:["正确","错误"],ans:1,exp:"断肢保存正确方法=用干净纱布或布料包裹断肢→放入密封塑料袋中→将塑料袋放入有冰块的容器中（低温但不直接接触冰）→标记时间→随伤者送医。断肢绝对不要直接放入冰水（会导致组织冻伤坏死），也不要用水或消毒液浸泡。",tip:"口诀：断肢保存=纱布包→密封袋→放进冰桶（不直接接触冰）。别泡水别泡酒精。干燥低温保存活。"},
{id:953,cat:"ev",type:"choice",q:"新能源汽车交流慢充（AC）与直流快充（DC）的主要区别是什么？",opts:["没有区别","交流慢充通过车载充电机将交流电转为直流电充电，功率较小（通常3-7kW）；直流快充直接以直流电充电，功率大（通常30-350kW）","交流慢充速度更快","直流快充对电池更好"],ans:1,exp:"交流慢充（AC）=电网交流电→车载充电机→转换为直流电→充入电池，功率3-7kW（家用充电桩），充满需6-10小时。直流快充（DC）=充电桩直接输出直流电→绕过车载充电机→直接充入电池，功率30-350kW，80%电量约需30分钟。快充频繁使用会加速电池老化。",tip:"口诀：慢充（AC）=交流电→车载充电机→电池，功率小时间长（家用过夜充）。快充（DC）=直流直入电池，功率大时间短（高速赶路用）。快充虽快但伤电池。"},
{id:954,cat:"ev",type:"judgment",q:"新能源汽车在充电时可以在车内开空调或使用娱乐系统等待。",opts:["正确","错误"],ans:0,exp:"充电时可以正常使用空调和车内电子设备（车辆设计允许充电时用电），但会分走一部分充电功率使充电速度变慢。安全方面没有问题——充电管理系统会自动调节。但建议不要在雷雨天充电时长时间待在车内。",tip:"口诀：充电时能开空调听歌——但充电会变慢。雷雨天充电最好下车等待。"},
{id:955,cat:"ev",type:"choice",q:"新能源汽车上橙色的高压线缆代表什么？",opts:["普通电线","高压电（通常300-800V），严禁触碰","低压12V线路","信号线"],ans:1,exp:"新能源车高压线缆统一使用橙色（国际标准），工作电压通常300-800V（部分车型超过800V），远超人体安全电压36V。非专业人员严禁触碰、切割或拆卸任何橙色线缆——触电可致死。事故救援时消防员会特别注意避开橙色线缆。",tip:"口诀：新能源车=看到橙色线=高压电=远离。橙色的线=能电死人的线。哪怕车泡水了照样带电。"},
{id:956,cat:"ev",type:"judgment",q:"纯电动汽车在下雨天可以正常充电，因为充电接口具有防水设计。",opts:["正确","错误"],ans:0,exp:"符合国家标准的充电桩和车辆充电接口具有防水设计（通常IP55或更高防护等级），小雨到中雨天气可以安全充电。但暴雨、雷电天气或充电接口有明显积水时建议暂停充电——安全第一。充电前检查接口是否干燥清洁。",tip:"口诀：电车雨天能充电（接口防水设计的）。但大暴雨+打雷=暂停。插枪前看一下接口有没有水。"},
{id:957,cat:"ev",type:"choice",q:"纯电动汽车冬季续航里程大幅下降的主要原因是什么？",opts:["轮胎打滑","电池低温活性下降+空调制热耗电量大","发动机效率降低","汽油凝固"],ans:1,exp:"冬季续航缩水（俗称「电动爹冬天现原形」）主因：①锂电池在低温下电化学反应速率下降，可用容量减少（0°C时约减少20%，-10°C时减少30%以上）；②PTC空调制热或热泵空调消耗大量电量（可达续航的15%-30%）。预热电池（利用充电桩电力预热）可有效缓解。",tip:"口诀：冬天续航打折=电池怕冷+开暖气费电。出门前插着充电桩预热电池=续航保得多。热车再走。"},
{id:958,cat:"ev",type:"judgment",q:"新能源汽车在长时间不用时，应保持电量在50%-80%之间，而不是100%满电或0%亏电存放。",opts:["正确","错误"],ans:0,exp:"锂电池最佳存储SOC（电量状态）=50%-80%。100%满电存放会加速电池老化（高电压应力），0%亏电存放可能导致电池过放损坏（不可逆容量损失）。长时间停放建议保持60%左右电量，每3个月补电一次。",tip:"口诀：电车长时间不开=电量保持50%-80%。满电存放=伤电池；空电存放=电池可能饿死。中间电量最养电池。"},
{id:959,cat:"ev",type:"choice",q:"以下关于新能源车涉水行驶的说法，哪项是正确的？",opts:["电车不怕水，可以像船一样开","纯电动车涉水深度通常不高于30cm（参考用户手册），超过可能导致电池包进水","电车遇水会自动断电不用担心","电车涉水速度和油车完全一样"],ans:1,exp:"纯电动车电池组在底盘，虽然电池包有防水密封（IP67），但涉水深度不宜超过用户手册规定（通常25-30cm，约半个车轮高度）。超过涉水极限→水可能进入电池包内部→电池短路起火（进水后数小时至数天才可能出现，称为「延迟性热失控」）。涉水后应尽快到4S店检查。",tip:"口诀：电车涉水=不超过半个轮子。电池在底盘=水太深就泡电池了。涉水后去检查，别等几天后自燃。"},
{id:960,cat:"ev",type:"judgment",q:"新能源车电池包具有IP67防水等级，意味着可以在1米深的水中浸泡30分钟而不会进水损坏。",opts:["正确","错误"],ans:0,exp:"IP67=防尘等级6（完全防尘）+防水等级7（1米水深浸泡30分钟不进水）。但这是出厂时的实验室标准——车辆使用后密封件可能老化，涉水时的水压也不同于静态浸泡（行驶时的水压更大）。因此不能因为有IP67就随便涉水。",tip:"口诀：IP67=静态泡水1米30分钟不进水。但行驶中水压更大+密封会老化。有IP67也别当船开。"},
{id:961,cat:"ev",type:"choice",q:"新能源车的「再生制动」（能量回收）功能是什么？",opts:["刹车助力","车辆减速或制动时将动能转化为电能充入电池","发动机发电","太阳能充电"],ans:1,exp:"再生制动（Regenerative Braking）=车辆减速或下坡时，驱动电机反转为发电机，将车辆的动能转化为电能充入电池，同时产生阻力帮助减速。优点=增加续航（城市工况可回收10%-30%能量）+减少刹车片磨损。部分车型可调节能量回收强度等级。",tip:"口诀：再生制动=松油门或踩刹车→电机变发电机→动能变电能存回电池。省电又省刹车片。"},
{id:962,cat:"ev",type:"judgment",q:"新能源车在能量回收强度设为最高档时，松油门后车辆的减速效果类似于轻踩刹车。",opts:["正确","错误"],ans:0,exp:"高能量回收模式下（单踏板模式/强回收模式），松油门（电门）后车辆明显减速（减速度可达0.2-0.3G），类似于燃油车轻踩刹车——这就是所谓的「单踏板驾驶」。熟练后大部分减速可只用油门踏板控制，减少右脚在油门和刹车之间的移动。但紧急情况仍需踩刹车。",tip:"口诀：强回收=松电门像轻踩刹车。单踏板驾驶=一个踏板控制加减速。但急刹还是得踩刹车踏板。"},
{id:963,cat:"ev",type:"choice",q:"关于新能源车拖车，以下说法正确的是？",opts:["可以像燃油车一样四轮着地拖车","多数纯电动车要求使用平板拖车（四轮离地），禁止车轮着地拖行","可以用任何方式拖车","可以自行用绳子拖车"],ans:1,exp:"多数纯电动车禁止车轮着地拖行——车轮转动会带动电机旋转产生感应电流，可能损坏电机控制器和逆变器。正确方式：平板拖车（四轮离地）或使用辅助轮（驱动轮离地）。具体拖车方式以用户手册为准，部分车型有「拖车模式」可短距离低速拖行。",tip:"口诀：电车拖车=平板拖车（四个轮子都不着地）。轮子转=电机转=电流回灌=烧控制器。叫专业救援按手册来。"},
{id:964,cat:"ev",type:"judgment",q:"新能源车电量显示为0%时，车辆会立即停止不动。",opts:["正确","错误"],ans:1,exp:"大多数新能源车电量显示0%后仍保留约2-5%的「隐藏电量」（安全冗余），可继续行驶10-20公里（龟速模式，动力受限）。这是为了保护电池不过放而设计的。但不要依赖这个——深度放电会严重缩短电池寿命。电量低于10%就应尽快充电。",tip:"口诀：表显0%=还有一点点隐藏电量（几公里）。但别赌——经常开到0%=电池早衰。电量10%就该找充电桩了。"},
{id:965,cat:"ev",type:"choice",q:"使用直流快充时，电池电量从多少开始充电速度最快，超过多少后充电速度显著下降？",opts:["0%开始最快","通常在20%-80%区间充电速度较快，超过80%后充电功率大幅下降","50%开始最快","90%以上最快"],ans:1,exp:"直流快充的充电曲线=20%-80%区间功率最大（「甜区」），超过80%后为了保护电池，BMS（电池管理系统）会大幅降低充电功率，80%-100%可能比20%-80%用时更长。因此长途出行建议充到80%即走（够用就好），不要每次充满以节省时间。",tip:"口诀：快充=20%到80%最快（甜区）。80%以上=「涓流充电」慢如蜗牛。赶路充到80%就走，别干等充满。"},
{id:966,cat:"ev",type:"judgment",q:"长时间不使用的新能源车，小电瓶（12V蓄电池）也可能亏电导致车辆无法启动。",opts:["正确","错误"],ans:0,exp:"新能源车有两个电源系统：高压动力电池（驱动车辆）+12V小电瓶（给车机、灯光、门锁、BMS等低压设备供电）。长时间不开车→小电瓶亏电→车门可能都打不开/车辆无法上电。解决：搭电或给小电瓶充电（和燃油车一样），或每隔1-2周让车辆通电运行一段时间让DC-DC给小电瓶充电。",tip:"口诀：电车也有12V小电瓶。长时间不开=小电瓶先亏电→门都打不开。隔一两周通一次电。"},
{id:967,cat:"ev",type:"choice",q:"插电式混合动力汽车（PHEV）与增程式电动车（EREV）的主要区别是？",opts:["完全相同","PHEV的发动机可以直接驱动车轮；EREV的发动机只发电不直接驱动车轮","PHEV不能充电","EREV没有发动机"],ans:1,exp:"PHEV（插电混动）=发动机可以通过变速箱直接驱动车轮+电动机也能驱动+可外部充电。EREV（增程式）=发动机只作为「发电机」给电池充电或给电动机供电，不直接驱动车轮——车轮始终由电动机驱动。EREV驾驶感受更接近纯电动车。",tip:"口诀：PHEV=油电都能驱动轮子（并联）。EREV=油只发电，电再驱动轮子（串联）。EREV=自带发电机的电车。"},
{id:968,cat:"ev",type:"judgment",q:"新能源车长期使用直流快充会加速电池容量衰减，建议日常以交流慢充为主。",opts:["正确","错误"],ans:0,exp:"直流快充=大电流+高热量→加速电池内部化学反应副反应（SEI膜增厚等）→电池容量衰减更快。日常使用交流慢充（小电流）=对电池更友好，电池寿命更长。建议「慢充为主，快充为辅」——高速赶路时用快充，日常家用充电桩用慢充。",tip:"口诀：快充=偶尔应急用（伤电池）。慢充=日常用（养电池）。慢充为主、快充为辅=电池长寿秘诀。"},
{id:969,cat:"ev",type:"choice",q:"购买新能源车后，家用充电桩的安装通常需要协调以下哪方面？",opts:["不需要协调","物业同意+电力公司审批+专业安装","只需自己买设备","只需物业同意"],ans:1,exp:"家用充电桩安装流程=物业出具同意安装证明→向电力公司申请电表安装（独立电表享受峰谷电价）→由具备资质的专业安装公司进行安装。老旧小区可能因电容不足需要增容。2026年各地简化了报装流程，可通过「网上国网」等APP一站式办理。",tip:"口诀：家充桩安装=物业同意+电力公司装表+专业人员安装。网上国网APP一站式搞定。老小区可能电容不够要增容。"},
{id:970,cat:"ev",type:"judgment",q:"新能源车在充电过程中如果充电枪被他人拔出，不会对车辆造成任何损害。",opts:["正确","错误"],ans:1,exp:"充电中强行拔枪可能导致电弧放电（尤其是直流快充大电流时），损坏充电接口和充电枪，严重时可能造成触电或火灾。正常充电中充电枪会被电子锁锁定，拔不下来——这个锁的作用就是防止意外拔枪。充电结束后电子锁自动解锁。",tip:"口诀：充电中枪是锁住的（拔不动的）。硬拔=电弧→损坏接口+危险。电子锁保护你也在保护车。"},
{id:971,cat:"ev",type:"choice",q:"新能源车电池的「热管理系统」的主要功能是什么？",opts:["只有加热","只有冷却","使电池组保持在最佳工作温度范围（通常20-40°C），高温散热，低温加热","只有通风"],ans:2,exp:"电池热管理系统=液冷/风冷散热（高温时）+PTC/热泵加热（低温时）+智能温控策略。保持电池在20-40°C最佳工作温度范围，确保电池效率、安全性和寿命。快充前部分车辆会自动预热/预冷电池以达到最佳充电温度。",tip:"口诀：电池热管理=夏天给电池开空调散热+冬天给电池开暖气预热。电池也怕冷怕热，20-40°C最舒服。"},
{id:972,cat:"ev",type:"judgment",q:"纯电动汽车因为没有发动机，所以不需要做任何定期保养。",opts:["正确","错误"],ans:1,exp:"纯电动车虽然不需要换机油、火花塞等燃油车常规保养，但仍需定期保养：①每1-2万公里检查高压系统（电池包、高压线缆、充电接口）；②更换空调滤芯、刹车油（2年/4万公里）；③检查齿轮箱油（减速器油）；④检查底盘、轮胎、制动系统。保养项目比燃油车少，但并非零保养。",tip:"口诀：电车也要保养——不用换机油，但要检查高压系统+刹车油+空调滤+齿轮箱油。项目少了但没完全消失。"},
{id:973,cat:"ev",type:"choice",q:"新能源车电池的「SOC」代表什么？",opts:["车速","State of Charge，即电池荷电状态（剩余电量百分比）","轮胎气压","充电次数"],ans:1,exp:"SOC（State of Charge）=电池剩余电量百分比，相当于燃油车的「油量表」。BMS通过测量电压、电流、温度等参数估算SOC。低SOC时（<10%）车辆会限功率输出，提示尽快充电。SOC显示精度受温度和电池老化影响。",tip:"口诀：SOC=电量百分比（相当于油表）。SOC 10%=该充电了。冬天SOC掉得比实际快（低温虚电）。"},
{id:974,cat:"ev",type:"judgment",q:"新能源车「续航里程」显示的数字在任何情况下都能准确反映实际可行驶里程。",opts:["正确","错误"],ans:1,exp:"表显续航里程（剩余续航）是基于近期驾驶习惯、温度、空调使用等估算的——上坡、高速、低温、开空调都会使实际续航大打折扣。冬季高速+暖风=实际续航可能只有表显的50%-70%。驾驶人对表显续航应「打七折」留安全余量。",tip:"口诀：表显续航=参考值不是准确值。冬天+高速+开空调=实际打5-7折。留足余量，别信表显到零。"},
{id:975,cat:"ev",type:"choice",q:"新能源车在公共充电站充电时，以下哪种行为是正确的？",opts:["充电完成后不挪车，继续占着充电车位","充电完成后及时将车辆移至普通停车位，让出充电资源","在充电车位停燃油车","拔别人的充电枪给自己的车充"],ans:1,exp:"公共充电站礼仪=充电完成后及时挪车让位+不要占用充电车位停车+燃油车不要停在充电车位+不要碰别人的充电枪。充电APP通常有超时占位费（充满后未挪车按分钟计费），2026年越来越多充电站实施此政策。",tip:"口诀：充完电=赶紧挪车让别人充。占着充电位不走=超时费+招人恨。公共资源大家共享。"},
{id:976,cat:"ev",type:"judgment",q:"电池「热失控」是新能源车火灾的主要原因，其一旦开始就无法被常规灭火器扑灭。",opts:["正确","错误"],ans:0,exp:"锂电池热失控=电池内部连锁化学反应产生大量热量和可燃气体，温度可达1000°C以上，且电池自带氧化剂，无需外部氧气即可持续燃烧。普通干粉灭火器只能灭明火，无法降低电池温度——热失控仍在内部持续。需要大量水持续冷却降温。",tip:"口诀：热失控=电池内部自己烧自己（自带氧气）。灭火器灭不掉，只有大量水持续冷却才行。"},
{id:977,cat:"ev",type:"choice",q:"新能源车使用「预约充电」功能的主要好处是什么？",opts:["没有好处","利用夜间低谷电价充电，降低充电成本，同时避开用电高峰","充电速度更快","可以不用充电桩"],ans:1,exp:"预约充电=设定在夜间谷电时段（如23:00-7:00）自动开始充电。好处：①享受低谷电价（约0.3元/度，峰电约0.6-1元/度），充电成本减半；②避开用电高峰，对电网友好；③部分城市有「有序充电」补贴。",tip:"口诀：预约充电=设好夜里自动充。谷电便宜一半，省下的电费一年够吃好几顿火锅。"},
{id:978,cat:"ev",type:"judgment",q:"「电池均衡」是指充电到100%后继续插枪一段时间，让BMS对各电芯进行电压均衡的操作，有利于电池健康。",opts:["正确","错误"],ans:0,exp:"电池均衡（Cell Balancing）=充满电后BMS对电池组中各个电芯的电压进行微调平衡，使所有电芯状态一致。建议每月至少慢充至100%并继续插枪1-2小时进行一次均衡，这有助于维持电池组一致性和延长寿命。快充通常不会触发均衡。",tip:"口诀：每月至少一次慢充充满+继续插1-2小时=电池均衡。让所有电芯「步调一致」。专用慢充做。"},
{id:979,cat:"ev",type:"choice",q:"新能源车电机（驱动电机）的最高转速通常在什么范围？",opts:["1000-3000转/分","3000-6000转/分","8000-20000转/分","和燃油车发动机一样"],ans:2,exp:"驱动电机转速范围极广，最高可达8000-20000转/分（高性能车型甚至更高）。因此在绝大多数工况下不需要多档变速箱——单级减速器即可满足从0到最高车速的全范围。这也是为什么电动车开起来「丝滑无顿挫」——没有换挡过程。",tip:"口诀：电机转速=8000-20000转/分=燃油发动机的2-3倍。转速范围广=不需要变速箱=行驶丝滑无顿挫。"},
{id:980,cat:"ev",type:"judgment",q:"新能源车在极寒天气（-20°C以下）下，电池可能无法充电或放电，需要先通过电池加热系统预热。",opts:["正确","错误"],ans:0,exp:"极寒环境下（-20°C以下）锂电池内阻急剧增大，电化学反应几乎停滞——可能无法充电也无法正常放电。需要电池加热系统（PTC加热或热泵）先将电池温度提升到0°C以上才能正常工作。预热期间车辆可能限功率输出，预热时间通常5-20分钟。",tip:"口诀：零下20度以下=电池冬眠了。需要先预热（用充电桩的电预热最好）才能正常开。出发前预热=续航不恐慌。"},
{id:981,cat:"ev",type:"choice",q:"关于新能源车「换电模式」，以下描述正确的是？",opts:["换电就是换电池","到换电站由机器人自动将亏电电池更换为满电电池，全程约3-5分钟，可媲美加油速度","换电需要自己手动操作","所有电动车都支持换电"],ans:1,exp:"换电模式=车辆驶入换电站→机器人自动卸下亏电电池→安装满电电池→3-5分钟完成离开。目前主要是部分品牌（如蔚来）支持换电。换电速度与加油相当，解决了充电时间长的痛点，但需要品牌建立换电站网络。",tip:"口诀：换电=3-5分钟换块满电电池，和加油一样快。但不是所有品牌都支持换电。"},
{id:982,cat:"ev",type:"judgment",q:"新能源车的充电接口分为快充口和慢充口，两个接口位置不同，插错无法充电。",opts:["正确","错误"],ans:0,exp:"绝大多数新能源车有两个充电接口：直流快充口（较大，9孔或两个大孔+辅助孔）和交流慢充口（较小，7孔）。物理上不兼容——快充枪插不进慢充口，慢充枪插不进快充口。部分车型将两个接口整合在一个盖板下（Combo接口），但仍能区分。",tip:"口诀：快充口和慢充口长得不一样——快充口大，慢充口小。大的插不进小的，小的也插不进大的（防呆设计）。"},
{id:983,cat:"ev",type:"choice",q:"新能源车在行驶中如果仪表盘显示「乌龟灯」（动力限制指示灯）亮起，意味着什么？",opts:["可以正常行驶","车辆进入跛行模式，动力输出受限（可能是电池过热/过冷或电量过低），应尽快安全停车检查","需要加速行驶","车辆可以高速行驶"],ans:1,exp:"「乌龟灯」（通常是一个乌龟图案或功率限制标志）=车辆因电池/电机温度过高、电量过低或系统故障而限制动力输出（跛行模式/limp mode），车速可能被限制在40-60km/h以下。应尽快在安全位置停车、排查原因或拨打救援电话。",tip:"口诀：乌龟灯=车跑不快了（强制限速）。电池太热/太冷/没电了→车在自我保护。靠边停，别硬开。"},
{id:984,cat:"ev",type:"judgment",q:"新能源车「电池衰减」属于正常现象，国家规定动力电池质保期内衰减超过20%可免费更换。",opts:["正确","错误"],ans:0,exp:"电池容量随充放电次数增加而自然衰减是正常现象（类似手机电池）。按国家标准，动力电池在8年/12万公里质保期内（多数厂家提供更长质保），如容量衰减超过20%可要求免费维修或更换。正常使用下5年衰减约10%-15%。",tip:"口诀：电池衰减=正常老化（和手机电池一样）。8年/12万公里内衰减超20%=免费换。好好养电池衰减慢。"},
{id:985,cat:"ev",type:"choice",q:"新能源车「电池预加热」功能的最佳使用方式是什么？",opts:["开车时开启","在连接充电桩的情况下，通过APP远程启动电池预加热，利用外部电力预热而非消耗电池自身电量","停车后使用","不需要使用"],ans:1,exp:"电池预加热=出发前通过充电桩的电力提前将电池加热到最佳工作温度，而非消耗电池自身电量（否则越预热续航越少）。配合「预约出发」功能，设定出发时间，车辆自动在出发前完成预热。冬季使用可显著提高续航表现。",tip:"口诀：预热电池=插着充电桩预热（用外电不耗自己电）。APP远程开启+预约出发=冬天续航救星。"},
{id:986,cat:"ev",type:"judgment",q:"新能源车「单踏板模式」下完全不需要踩刹车踏板，仅靠松油门即可实现所有减速和停车。",opts:["正确","错误"],ans:1,exp:"单踏板模式（强能量回收模式）可应对大多数日常减速场景，但不等于不需要刹车踏板：①紧急制动时能量回收的减速力度远不足够，必须踩刹车；②低速时（接近停止）能量回收效率降低，需要刹车配合完全刹停；③满电时能量回收功能会减弱或暂时关闭（电池已满无法再充电），此时松油门几乎没有减速效果。",tip:"口诀：单踏板≠没有刹车。紧急情况=必须踩刹车。满电时回收功能会减弱（电满了没地方充），别以为每次松油门都会减速。"},
{id:987,cat:"ev",type:"choice",q:"新能源车无线充电技术（WPT）目前的主要应用场景是？",opts:["高速公路上边开边充","固定停车位（家用/公共），停车后自动感应充电，无需插枪","所有停车场都已普及","可以边走边充"],ans:1,exp:"无线充电（感应式充电）=车辆停在无线充电板上方→电磁感应传输电能→车载接收器→充入电池。目前主要应用于固定停车位（家用、公交场站等）。功率通常3.3-11kW（慢充级别），效率略低于有线充电（约85-90%）。边开边充的动态无线充电仍在试验阶段。",tip:"口诀：无线充电=车停上去自动充（不用插枪）。但目前还是慢充速度+效率比插枪低。停车即充，懒人福音。"},
{id:988,cat:"ev",type:"judgment",q:"新能源车碰撞事故后，即使外观无明显损伤，也必须检查高压系统和电池包是否受损。",opts:["正确","错误"],ans:0,exp:"新能源车事故后（即使轻微追尾或底盘磕碰），高压系统和电池包可能受到「内伤」——内部电芯变形或隔膜破损，当时不表现出来，但数小时至数天后可能突发热失控自燃。事故后应到专业维修点用诊断仪全面检测高压系统。",tip:"口诀：电车撞了=不管外面看着怎样，都要去检查电池和高压系统。看不见的内伤=定时炸弹（延迟热失控）。"},
{id:989,cat:"ev",type:"choice",q:"新能源车电池的「循环寿命」是指什么？",opts:["开了多少年","电池从100%用到0%再充到100%为一个完整充放电循环，电池在容量衰减到80%前能完成的循环次数","开了多少公里","充电次数"],ans:1,exp:"一次完整充放电循环=累计放电达到100%（不一定是连续从100%用到0%——两次从80%用到30%的累计放电也是1个循环）。主流动力电池循环寿命约1000-2000次（容量衰减至80%），对应行驶里程约30-60万公里。浅充浅放（如30%-80%）可延长循环寿命。",tip:"口诀：电池寿命=不是充电次数，是完整充放电循环次数。浅充浅放（30%-80%用）=比深充深放（0%-100%）活得久。"},
{id:990,cat:"ev",type:"judgment",q:"新能源车如果长期不使用，建议断开12V小电瓶负极，防止小电瓶亏电导致车辆无法启动。",opts:["正确","错误"],ans:0,exp:"长期停放（超过1个月）的新能源车建议：①保持动力电池SOC在50%-60%；②断开12V小电瓶负极（防止车辆待机耗电把小电瓶耗光）；③每3个月检查一次并补电。小电瓶亏电=车辆一切低压设备瘫痪=即使动力电池满电也无法启动。",tip:"口诀：电车长期停放=动力电池保持50%+断开小电瓶负极。小电瓶亏了=动力电池再满也白搭。"},
{id:991,cat:"smart",type:"choice",q:"自适应巡航控制（ACC）系统的主要功能是什么？",opts:["自动泊车","根据前车速度自动调整本车速度，保持设定跟车距离，实现自动跟车行驶","自动变道","完全自动驾驶"],ans:1,exp:"ACC（Adaptive Cruise Control）=定速巡航的升级版——通过雷达/摄像头感知前车距离和速度，自动加减速以保持设定跟车距离。当前车减速时ACC自动减速；前车加速或变道离开后自动恢复到设定巡航速度。属于L2级辅助驾驶，驾驶人必须始终保持注意力并随时准备接管。",tip:"口诀：ACC=自动跟车——前车快我快，前车慢我慢，前车走了我恢复到设定速度。L2辅助=眼睛看路手扶方向盘。"},
{id:992,cat:"smart",type:"judgment",q:"开启ACC自适应巡航后，驾驶人可以将双手离开方向盘做其他事情。",opts:["正确","错误"],ans:1,exp:"ACC属于L2级辅助驾驶，要求驾驶人全程保持注意力、双手放在方向盘上、随时准备接管。系统无法识别所有障碍物（如静止的锥桶、行人横穿、突然切入的车辆等），把ACC当「自动驾驶」使用已经导致了多起致命事故。",tip:"口诀：ACC≠自动驾驶。开了ACC也要手扶方向盘眼看路。它只是帮你省了「脚」的活，不是省了「眼和脑」。"},
{id:993,cat:"smart",type:"choice",q:"车道保持辅助（LKA）在什么情况下可能失效？",opts:["任何情况下都有效","车道标线模糊、磨损或被积雪覆盖时、强光直射摄像头时、弯道半径过小时","只在高速上失效","只在城市失效"],ans:1,exp:"LKA（Lane Keeping Assist）依赖摄像头识别车道标线。以下情况可能失效：①车道线模糊/磨损/被雨雪覆盖→摄像头「看不见」线；②强光直射摄像头（日出/日落正对太阳）→摄像头眩光致盲；③急弯（曲率半径过小）→系统无法及时响应；④道路分叉或汇合处。",tip:"口诀：LKA=靠摄像头看车道线。线看不清=系统就「瞎了」。模糊线/强逆光/急弯=LKA可能突然退出，随时准备接管。"},
{id:994,cat:"smart",type:"judgment",q:"车道居中控制（LCC）可以让车辆在各种路况下完全自动保持在车道中央行驶。",opts:["正确","错误"],ans:1,exp:"LCC（Lane Centering Control）与LKA一样依赖清晰的车道标线和良好的环境条件。在标线不清、恶劣天气、施工区域、复杂交叉口等情况下LCC可能无法正常工作或突然退出。系统退出时仅有短暂提示音，驾驶人需时刻保持注意力。",tip:"口诀：LCC居中=也需要看清线。线和LKA同样的局限。系统退出只响一声→你不注意=车就跑偏了。"},
{id:995,cat:"smart",type:"choice",q:"自动紧急制动（AEB）系统在什么速度范围内通常有效？",opts:["任何速度都有效","不同车型不同，城市AEB通常4-80km/h，高速AEB可达车辆最高限速，但并非在所有速度下都能完全避免碰撞","只在高速有效","只在低速有效"],ans:1,exp:"AEB的有效速度范围因车型和系统版本而异。城市AEB通常4-80km/h（可识别行人、自行车），高速AEB可覆盖到车辆最高行驶速度。但AEB不是在所有速度下都能完全刹停——高速时可能只是减轻碰撞（降低碰撞速度），而非完全避免碰撞。永远不能完全依赖AEB。",tip:"口诀：AEB=不一定能刹停（高速时可能只减碰撞速度）。低速时可能刹停、高速时只减轻。它不是万能的，开车不能因为有AEB就大意。"},
{id:996,cat:"smart",type:"judgment",q:"AEB系统对行人和骑车人的识别能力与对车辆的识别能力完全一样。",opts:["正确","错误"],ans:1,exp:"AEB对不同类型的障碍物识别能力不同。大多数AEB对车辆尾部（大目标、规则形状）识别最好，对行人次之（相对规则但体积小），对骑车人（不规则轮廓+运动轨迹复杂）和动物（形状多样）识别率较低。夜间和恶劣天气下识别率进一步下降。不可盲目信任。",tip:"口诀：AEB识别=车最容易认，行人次之，骑车人/动物最难。晚上+坏天气=识别率打大折。别把命交给传感器。"},
{id:997,cat:"smart",type:"choice",q:"盲区监测系统（BSD/BSM）在以下哪种情况下可能无法正常工作？",opts:["任何情况都能工作","后方来车速度与本车速度差过大、传感器被泥雪覆盖、弯道上","只在倒车时","只在高速上"],ans:1,exp:"BSD/BSM（盲区监测）=通过毫米波雷达或超声波传感器检测侧后方盲区内是否有来车。以下情况可能失效：①传感器被泥、雪、冰覆盖→功能受限报警；②弯道上（雷达探测角度偏移）；③后方车辆速度远大于本车（可能检测延迟）；④摩托车/自行车等小目标检测灵敏度较低。",tip:"口诀：盲区监测=传感器怕脏（泥雪一盖就瞎了）+弯道不准。变道前瞄一眼后视镜最靠谱——老司机的眼睛比传感器可靠。"},
{id:998,cat:"smart",type:"judgment",q:"有了BSD盲区监测系统，变道时就不需要再扭头看盲区了。",opts:["正确","错误"],ans:1,exp:"BSD是辅助工具，不能替代驾驶人的主动观察。BSD可能漏报（传感器灵敏度限制）或因延迟而报警不及时。变道安全流程=看后视镜→看BSD指示灯→快速扭头确认盲区（Shoulder Check）→打转向灯→变道。BSD是「保险」不是「替代」。",tip:"口诀：BSD=第二道保险，不是唯一判断。变道=后视镜+BSD灯+扭头看。三道确认才变道。"},
{id:999,cat:"smart",type:"choice",q:"自动泊车系统（APA）不能在以下哪种环境中正常工作？",opts:["标准划线停车位","斜列车位、非标准尺寸车位、无地面标线的空地","宽敞的停车场","室内停车场"],ans:1,exp:"APA（Auto Parking Assist）依赖超声波传感器和摄像头识别车位边界（通过其他车辆或标线）。以下情况可能无法识别：①无标线+无相邻车辆的空旷场地（没有参照物）；②尺寸过小的车位（通常需要车长+0.8米以上）；③斜列式车位（部分车型不支持）；④车位边界为绿化带或低矮障碍物。",tip:"口诀：自动泊车=得有参照物（标线或其他车）。空地=它不知道往哪停。小位置=停不进去。泊车再智能也有极限。"},
{id:1000,cat:"smart",type:"judgment",q:"后方交通穿行警示（RCTA）在从垂直车位倒车驶出时，可以检测到左右来车并发出警告。",opts:["正确","错误"],ans:0,exp:"RCTA（Rear Cross Traffic Alert）=倒车驶出车位时，通过后侧方毫米波雷达探测左右方向来车（行人和骑车人），在来车进入碰撞风险范围前发出声光警告。特别适用于被旁边大型车辆挡住视线的倒车场景。但RCTA不能替代主动扭头观察。",tip:"口诀：RCTA=倒车时的「第三只眼」，看左右来车。大型车旁边倒车时的救命功能。但它也有盲区，还是要自己看。"},
{id:1001,cat:"smart",type:"choice",q:"驾驶员监控系统（DMS）检测到驾驶人分心或疲劳时，通常会怎么做？",opts:["直接急刹车","分阶段升级警报：视觉提示→声音警告→方向盘振动→必要时自动减速并双闪靠边停车","什么也不做","关闭发动机"],ans:1,exp:"DMS（Driver Monitoring System）=通过红外摄像头监测驾驶人眼睑开合、视线方向、头部姿态。检测到疲劳/分心后分阶段警告：①仪表盘文字+图标提示→②声音警告→③方向盘/座椅振动→④如仍无反应，系统自动减速+开启双闪+缓慢靠边停车（部分车型2026年已实现）。",tip:"口诀：DMS=车内摄像头盯着你。走神=先提醒→再警告→自动靠边停。不是直接吓你一跳，是一步步升级。"},
{id:1002,cat:"smart",type:"judgment",q:"DMS驾驶员监控系统会录制和上传驾驶人的面部视频数据。",opts:["正确","错误"],ans:1,exp:"绝大多数车辆DMS仅进行本地实时分析（边缘计算），不会录制或上传视频数据。DMS主要判断疲劳/分心状态后输出警报信号，不存储原始图像。但OTA升级和车联网功能可能涉及数据上传——具体以各品牌隐私政策为准，2026年国标对车内数据处理有严格隐私保护要求。",tip:"口诀：DMS=分析你的状态但不录视频。数据在车机本地处理不上传。车内摄像头没有偷偷录像。"},
{id:1003,cat:"smart",type:"choice",q:"交通标志识别（TSR）系统在以下哪种情况下最可能识别错误？",opts:["标志清晰干净","标志被部分遮挡、脏污、积雪覆盖、逆光强烈、或限速标志在弯道出口","标准高速公路标志","白天正常光照"],ans:1,exp:"TSR（Traffic Sign Recognition）通过摄像头识别交通标志。以下场景容易出错：①标志被树枝遮挡/脏污/积雪覆盖→部分读取或漏读；②强逆光（日出日落正对标志）→摄像头眩光；③标志设在弯道出口→识别窗口过短；④条件性标志（如「雨天限速80」）可能误读为普通限速。",tip:"口诀：TSR=怕遮、怕脏、怕逆光。标志被挡一半=可能认错。条件性限速标志（雨天/时间限制）容易误读。不能完全信它。"},
{id:1004,cat:"smart",type:"judgment",q:"抬头显示器（HUD）将车速、导航等信息投射到挡风玻璃上，驾驶人可以完全不看仪表盘。",opts:["正确","错误"],ans:0,exp:"HUD（Head-Up Display）=将关键驾驶信息（车速、导航箭头、ACC/LKA状态、警告信息等）投射在前挡风玻璃上，驾驶人无需低头看仪表盘，视线保持在前方——大大减少视线离开道路的时间。但HUD显示信息有限，详细的车辆状态仍需查看仪表盘。",tip:"口诀：HUD=信息投射在眼前挡风玻璃上。不用低头看仪表盘。但只是辅助显示，详细信息还得看仪表。"},
{id:1005,cat:"smart",type:"choice",q:"2026年国标要求新能源车低速行驶时必须发出提示音（AVAS），其主要目的是什么？",opts:["为了好听","提醒行人和非机动车注意到有车辆接近，防止无声电动车造成安全隐患","为了宣传品牌","只是装饰功能"],ans:1,exp:"AVAS（Acoustic Vehicle Alerting System）=低速行驶（通常<20km/h或倒车时）自动发出模拟发动机声音，提醒视觉障碍者和其他道路使用者注意车辆接近。电动车低速时几乎没有声音，容易造成行人毫无察觉——AVAS通过法规强制安装。声音有标准化要求，各品牌可设计独特音色。",tip:"口诀：AVAS=电车低速呜呜声。不是车坏了，是故意发声音提醒行人——电车太安静，行人听不到。"},
{id:1006,cat:"smart",type:"judgment",q:"全速域ACC（0-180km/h）可以在堵车时完全自动跟停并自动起步，驾驶人无需任何操作。",opts:["正确","错误"],ans:0,exp:"全速域ACC+Stop&Go功能确实可以在堵车时自动跟停前车并在前车起步后自动跟车起步（停车时间较短时，通常3秒内可自动起步；停车时间较长需轻踩油门或按RES键确认起步）。但驾驶人仍需保持注意力——系统不能识别所有突发情况（如行人插入、旁边车辆加塞等）。",tip:"口诀：ACC+Stop&Go=堵车神器（自动跟停+起步）。但停车久了需要你点一下油门确认。插队的车可能识别不及时，自己多看着。"},
{id:1007,cat:"smart",type:"choice",q:"恶劣天气（大雨、浓雾、暴雪）对ADAS（高级驾驶辅助系统）的影响是什么？",opts:["完全不受影响","传感器（摄像头、雷达）性能显著下降——摄像头视野受阻、雷达信号衰减、系统可能降级或自动退出","只在晚上受影响","反而更灵敏"],ans:1,exp:"恶劣天气=ADAS的「盲区」。摄像头被雨雪遮挡=失明；毫米波雷达电磁波被大雨滴/雪花衰减=探测距离缩短；超声波传感器受泥水覆盖=失效。系统检测到传感器性能下降时会降级或退出，并提示驾驶人接管。恶劣天气下应降低对辅助驾驶的依赖，更多依靠人工驾驶技能。",tip:"口诀：大雨大雪大雾=ADAS「瞎了」。摄像头被挡+雷达信号衰减。系统会自己退出来，让你来开。恶劣天气=别靠辅助驾驶。"},
{id:1008,cat:"smart",type:"judgment",q:"使用辅助驾驶系统时，如果系统突然退出，车辆会立即失去控制。",opts:["正确","错误"],ans:1,exp:"辅助驾驶系统退出时车辆不会立即失控——车辆的基础操控（转向、加速、制动）始终由驾驶人最终控制。系统退出只是取消了自动加减速和转向辅助功能，驾驶人会听到提示音并看到仪表盘图标变化，此时驾驶人应立即接管控制。系统退出不会让车辆「突然乱跑」。",tip:"口诀：系统退出=辅助功能没了，不是车失控。它会响一下提醒你，然后你接手开。你始终是车辆的主人。"},
{id:1009,cat:"smart",type:"choice",q:"关于OTA（空中升级）安全，以下说法正确的是？",opts:["升级时可以开车","应在车辆安全停放（P档）、电量充足（>20%）、网络稳定的状态下进行，升级过程中车辆无法行驶","升级不需要网络","任何地方都可以升级"],ans:1,exp:"OTA（Over-The-Air）远程升级=车辆通过移动网络下载更新包并自动安装。安全要求：①车辆挂P档停放（升级中车辆无法行驶）+②动力电池电量>20%（防止升级中途断电导致系统损坏）+③驻车在安全位置（非快速路应急车道）。升级时间通常20分钟到2小时不等，期间不要操作车辆。",tip:"口诀：OTA升级=车停好（P档）+电量足+别动车。升级中车=「变砖」暂时不能开。别在高速应急车道上OTA。"},
{id:1010,cat:"smart",type:"judgment",q:"2026年所有智能驾驶辅助系统都属于L3级别，驾驶人不再需要对驾驶负责。",opts:["正确","错误"],ans:1,exp:"截止2026年，中国量产乘用车搭载的智能驾驶系统绝大多数仍为L2级（部分车型L2+或限定场景L3），L2级=驾驶人始终是驾驶责任主体。L3级「有条件自动驾驶」仅在特定场景（如高速拥堵低速跟车）下系统承担驾驶责任，且仅有极少数车型获批。L4和L5尚未量产。驾驶人任何时候都不应将辅助驾驶当作完全自动驾驶。",tip:"口诀：2026年量产车=基本都是L2，不是L3。L2=你负责开，系统帮你。把手放在方向盘上，眼睛看路。出了事你的责任。"},
{id:1011,cat:"smart",type:"choice",q:"传感器（摄像头、毫米波雷达）需要如何维护以保证ADAS功能正常？",opts:["不需要维护","定期清洁摄像头镜头和雷达盖板表面，避免贴膜、加装装饰件或碰撞导致传感器移位","每月更换传感器","用水冲洗内部"],ans:1,exp:"ADAS传感器维护=①保持摄像头挡风玻璃区域清洁（内侧不要有雾气/灰尘，外侧不要有泥水/冰霜）；②保持前后保险杠雷达盖板和超声波传感器清洁；③不要在传感器前方贴膜/加装装饰/喷漆；④底盘磕碰后要检查雷达/传感器是否移位（毫米波雷达对角度极其敏感，偏移1度可能造成严重误判）。",tip:"口诀：摄像头/雷达=保持表面干净。别贴膜、别加装饰件遮挡。磕了底盘=去校准雷达。偏一度=测不准。"},
{id:1012,cat:"smart",type:"judgment",q:"前向碰撞预警（FCW）在检测到碰撞风险时会自动刹车。",opts:["正确","错误"],ans:1,exp:"FCW（Forward Collision Warning）=只负责「警告」不负责「刹车」。通过声音和视觉提醒驾驶人有碰撞风险，由驾驶人采取制动措施。AEB（自动紧急制动）才负责「刹车」。两者常配合使用：FCW先警告→驾驶人不反应→AEB介入制动。",tip:"口诀：FCW=叫（警告）；AEB=刹（制动）。FCW是闹钟，AEB是自动刹车。两者配合：先叫→不反应→再刹。"},
{id:1013,cat:"smart",type:"choice",q:"车路协同（V2X）技术的主要功能是什么？",opts:["只是导航","实现车与车（V2V）、车与路（V2I）、车与人（V2P）等实时信息交互，提高通行效率和安全性","只是娱乐功能","只是自动驾驶"],ans:1,exp:"V2X（Vehicle-to-Everything）=车路协同技术——车辆与交通信号灯、路侧设备、其他车辆、行人设备、云端等实时通信。功能包括：①红绿灯倒计时/绿波通行建议；②前方拥堵/事故/施工实时提醒；③盲区来车/行人预警（「鬼探头」预警）；④危险路段提醒。2026年已有部分城市和高速公路部署了V2X设备。",tip:"口诀：V2X=车和周围一切「对话」。红绿灯告诉车还有多久变灯，路告诉你前方有事故。车有超能力=万物互联。"},
{id:1014,cat:"smart",type:"judgment",q:"有了360°全景影像系统，倒车时就不需要看后视镜了。",opts:["正确","错误"],ans:1,exp:"360°全景影像=通过车身四周摄像头拼接鸟瞰画面，帮助驾驶人了解车辆四周环境。但它不能替代后视镜：①全景影像有拼接盲区和畸变；②画面存在延迟（约0.1-0.3秒）；③摄像头可能被泥水遮挡；④不能显示远处快速接近的车辆。倒车=后视镜+全景影像+扭头观察多管齐下。",tip:"口诀：360影像=辅助但不是替代。有盲区+有延迟+可能脏。倒车=后视镜+影像+眼睛一起用。只盯着屏幕倒车=离撞不远了。"},
{id:1015,cat:"smart",type:"choice",q:"以下关于「自动驾驶」与「辅助驾驶」的法律责任区别，正确的是？",opts:["没有区别","L2辅助驾驶=驾驶人负全部责任；L3有条件自动驾驶在系统激活期间由系统承担驾驶责任，但驾驶人要随时准备接管","都由车企负责","都由保险公司负责"],ans:1,exp:"L2辅助驾驶=全程由驾驶人承担安全驾驶责任，系统只是辅助工具。L3有条件自动驾驶=系统激活期间（如高速堵车低速跟车）由系统承担驾驶责任，驾驶人可以暂时不监控道路，但需在系统要求接管时及时响应。注意L3只在限定条件下生效，绝大多数量产车仍是L2。",tip:"口诀：L2=你负责；L3=系统激活时系统负责（但要准备接管）。现在路上跑的基本都是L2，出了事你担责。别让辅助驾驶四个字骗了你。"},
{id:1016,cat:"smart",type:"judgment",q:"智能汽车的传感器（摄像头、雷达）在通过自动洗车机时需要特殊保护或关闭某些功能。",opts:["正确","错误"],ans:0,exp:"通过自动洗车机前应：①关闭自动雨刷（洗车机刷子会触发雨刷，可能导致雨刷臂损坏）；②关闭自动驻车/电子手刹（部分洗车机需要车轮自由转动）；③收起后视镜（如果可折叠）；④部分车型需关闭自动紧急制动（防止洗车机滚刷被误识别为障碍物触发急刹）。以用户手册为准。",tip:"口诀：进自动洗车机=关自动雨刷+关AEB（别让车以为洗车刷子是障碍物急刹）+折后视镜。不关可能就是修车。"},
{id:1017,cat:"smart",type:"choice",q:"2026年关于「脱手检测」的要求是什么？",opts:["没有要求","L2辅助驾驶系统应配备脱手检测功能（通过方向盘扭矩传感器或电容传感器），检测到驾驶人长时间脱离方向盘时发出警告直至退出辅助驾驶模式","只需声音警告","车辆自动停车"],ans:1,exp:"2026年法规要求配备L2辅助驾驶系统的车辆必须有脱手检测功能：①检测到双手脱离方向盘15-30秒→视觉+声音警告；②警告后仍不握方向盘→警告升级（双闪、点刹提醒）；③继续不握→系统退出辅助驾驶模式并减速停车。目的=防止驾驶人将L2当作自动驾驶滥用。",tip:"口诀：脱手检测=手不在方向盘上就警告。先提醒→再升级→最后退出+减速停。方向盘得一直扶着，装睡不行。"},
{id:1018,cat:"smart",type:"judgment",q:"自动变道辅助（ALC）可以在驾驶人不确认安全的情况下由系统自行判断并自动完成变道。",opts:["正确","错误"],ans:1,exp:"自动变道辅助（ALC/Auto Lane Change）=驾驶人打转向灯后，系统自动判断目标车道是否安全并完成变道。但驾驶人是最终决策者——必须在变道前确认安全（看后视镜+盲区），ALC只是执行变道动作。系统无法判断所有复杂情况（如远处快速驶来的车辆、旁边车辆也同时变道等）。",tip:"口诀：自动变道=你打转向灯+确认安全→系统帮你转方向盘变道。确认安全是你的责任，系统只是执行者。"},
{id:1019,cat:"smart",type:"choice",q:"以下哪些行为会导致辅助驾驶系统传感器性能下降？",opts:["保持传感器清洁","在挡风玻璃上安装非原厂贴膜遮挡摄像头视野、在雷达盖板贴膜或喷涂油漆、加装前保险杠装饰件遮挡超声波传感器","定期保养","正常使用"],ans:1,exp:"影响ADAS传感器的错误操作=①挡风玻璃摄像头区域贴深色膜/金属膜→光线透过率下降→摄像头「看」不清；②毫米波雷达盖板上贴膜/喷漆→电磁波被屏蔽→雷达「盲」了；③加装前保险杠装饰杠遮挡超声波传感器→盲区探不到；④更换非原厂前挡风玻璃→摄像头校准参数不匹配。",tip:"口诀：别在传感器前面贴东西/喷漆/加装。摄像头区域=不能贴膜。原厂挡风玻璃=摄像头有校准值，换了副厂的要重新校准。"},
{id:1020,cat:"smart",type:"judgment",q:"智能汽车的自动驾驶能力可以通过OTA升级从L2直接升级到L4。",opts:["正确","错误"],ans:1,exp:"OTA升级不能改变车辆的自动驾驶等级——L3和L4需要额外的传感器硬件冗余（如激光雷达、高精度定位、双冗余制动/转向系统等）和法规认证。OTA可以优化L2辅助驾驶的性能和增加功能，但无法「软件升级」将L2变成L4。这就像不能通过软件更新把自行车变成摩托车。",tip:"口诀：OTA不能把L2升成L4。L2→L4=需要更多硬件（更多传感器+双份制动/转向系统）。软件有心无力。"},
{id:1021,cat:"newsigns",type:"choice",q:"2026年新增的「新能源车专用停车位」标志的特征是什么？",opts:["普通蓝底P","绿底P+充电插头图案，地面标线为绿色","黄底P","红底P"],ans:1,exp:"新能源车专用停车位标志=绿底或蓝底方形+白色P+充电插头图案，地面标线为绿色，车位内常标有「新能源车专用」字样。该车位仅供新能源车充电或停放，燃油车占用将被处罚并可能被拖走。",tip:"口诀：绿底P+充电插头=电车专用车位。油车停进去=违章+被电车车主鄙视。绿色标识=绿色出行专属。"},
{id:1022,cat:"newsigns",type:"judgment",q:"2026年高速公路新增的「智能可变限速」电子标志显示的限速值具有与固定限速标志同等的法律效力。",opts:["正确","错误"],ans:0,exp:"智能可变限速标志（LED电子限速屏）=根据实时交通流量、天气、事故等因素动态调整限速值，显示的速度限制与固定限速标志具有同等法律效力。当电子限速与固定限速不一致时，以电子限速（更适应当前路况）为准。",tip:"口诀：电子屏限速=和固定标志一样有效。电子和固定不一致时=听电子的（它知道当前路况）。"},
{id:1023,cat:"newsigns",type:"choice",q:"「自动驾驶测试区」标志（2026新增）的特征是什么？",opts:["普通蓝色指路标志","荧光黄绿色底+黑色自动驾驶图标+「自动驾驶测试区域」文字","红色警告标志","白色指路标志"],ans:1,exp:"自动驾驶测试区标志=荧光黄绿色底（国际新兴警告色）+自动驾驶车辆图标（带传感器波纹）+「自动驾驶测试区域」白色文字。设于自动驾驶开放测试道路路段起点，提醒过往车辆注意测试车辆可能有非常规驾驶行为，保持安全距离。",tip:"口诀：荧光黄绿底+带传感器图案的车=自动驾驶测试区。看到这个标志=旁边可能有无人驾驶测试车，它们反应和人类司机不同。"},
{id:1024,cat:"newsigns",type:"judgment",q:"2026年新增的「行人过街安全岛」标志用于指示道路中间设有行人二次过街的保护区。",opts:["正确","错误"],ans:0,exp:"「行人过街安全岛」=路中间的安全等待区域，供行人无法一次通过宽阔马路时在中间安全等待。标志为蓝底+行人图案+安全岛图案。2026年宽马路（双向6车道以上）人行横道中间普遍设置安全岛，夜间配合反光警示柱和照明。",tip:"口诀：蓝底+行人+中间岛=安全岛。马路太宽一次过不去？中间有个安全区等你。边走边等比一口气冲更安全。"},
{id:1025,cat:"newsigns",type:"choice",q:"「共享电动自行车停放区」标志（2026新增）的特征是什么？",opts:["没有专门标志","蓝底+电动自行车图案+P字样，配合地面蓝色或绿色标识区","只有地面标线","和普通停车标志一样"],ans:1,exp:"共享电单车停放区标志=蓝底方形+电动自行车轮廓+停车P符号，配合地面蓝色或绿色铺装标线框。共享电单车需停放在指定的电子围栏区域内（RFID或蓝牙道钉技术定位），否则无法还车。乱停乱放将被共享平台收取调度费。",tip:"口诀：蓝底+电动车+P=共享电单车停放区。必须停进电子围栏，乱停要多扣钱。"},
{id:1026,cat:"newsigns",type:"judgment",q:"「低排放区」标志表示该区域限制高排放车辆进入，违规驶入将被电子抓拍处罚。",opts:["正确","错误"],ans:0,exp:"「低排放区」（LEZ/Low Emission Zone）=部分大城市划定的限制高排放车辆通行区域。标志为蓝底圆形+绿色树叶/云朵图案+「低排放区」字样。国一、国二等高排放老旧汽油车和柴油车不得驶入，违法进入将被电子抓拍+罚款。2026年越来越多城市设立低排放区。",tip:"口诀：蓝底+绿叶子=低排放区。老车/高排放车=不让进。环保标志和车牌自动识别，进来就拍。"},
{id:1027,cat:"newsigns",type:"choice",q:"高速公路「电子情报板」（可变信息标志VMS）通常显示什么信息？",opts:["广告","前方路况（拥堵/事故/施工）、天气预警、限速变更、旅行时间预告等实时交通信息","天气预报","新闻"],ans:1,exp:"VMS（Variable Message Sign）=高速公路和城市快速路上的大型LED显示屏，显示内容包括：①前方路况（拥堵长度/预计通行时间）；②事故/施工警告（距离+车道封闭信息）；③天气预警（雾、冰雪、横风）；④临时限速变更；⑤替代路线建议（前方拥堵请从XX出口绕行）。",tip:"口诀：高速大电子屏=实时路况播报。堵多远+哪里有事故+该开多快+要不要绕路。不是广告牌，是行车信息板。"},
{id:1028,cat:"newsigns",type:"judgment",q:"2026年新增的「智能人行横道」配备地面LED灯带和感应器，检测到有行人等待时自动亮起警示灯提醒过往车辆。",opts:["正确","错误"],ans:0,exp:"智能人行横道（智慧斑马线）=地面嵌入式LED灯带（黄闪或红色）+红外/雷达传感器+信号灯联动。行人等待或正在横穿时→地面LED闪烁+路侧警示灯亮起→多维度提醒驾驶人。夜间和雨天效果尤为显著。2026年已在多个城市人流密集路段推广。",tip:"口诀：会发光的斑马线=智能人行横道。有人过=地面LED灯闪起来。夜里+雨天=特别显眼，老远就知道前面有人过街。"},
{id:1029,cat:"newsigns",type:"choice",q:"「错时共享停车位」标志的特征是什么？",opts:["只有P","蓝底P+时钟图案+允许停放时间段文字说明","禁止停车","收费标志"],ans:1,exp:"错时共享停车位=蓝底P+时钟图案+可用时段（如「工作日19:00-次日7:00，周末全天」）。白天可能为其他用途（如校门前禁停、公交专用），夜间开放给周边居民停车。非允许时段停放=违停。通过标志上的时间文字判断能否停放。",tip:"口诀：P+时钟+时间段=错时共享停车。看时间=能不能停。不是所有P都是24小时的，看清钟和字。"},
{id:1030,cat:"newsigns",type:"judgment",q:"2026年新标准中「收费站ETC/人工混合车道」使用黄底标志与纯ETC车道的绿底标志相区分。",opts:["正确","错误"],ans:0,exp:"收费站车道标志：纯ETC专用车道=绿底+ETC+「专用」字样；ETC/人工混合车道（MTC）=黄底+ETC/MTC+「混合」字样；纯人工车道=无特殊底色。驾驶人在接近收费站前应根据自身情况提前变道选择正确车道。",tip:"口诀：绿底=纯ETC道；黄底=混合道（ETC+人工都行）；没颜色=纯人工。有ETC走绿色，没ETC走黄色或无色。"},
{id:1031,cat:"newsigns",type:"choice",q:"「应急医疗点」交通标志（2026新增）的特征是什么？",opts:["蓝底+红十字+医院图案","白底红十字+「应急医疗」文字+方向箭头，设于高速公路服务区或出口附近","只有文字","红底白字"],ans:1,exp:"应急医疗点标志=白底+红十字+「应急医疗」文字+方向距离信息。设于高速公路设有医疗急救站的服务区、收费站出口附近。与普通「医院」指路标志的区别=强调了「应急」属性，事故伤员可在此获得初步急救处理后转运。",tip:"口诀：白底红十字+「应急医疗」=高速上的急救站。不是大医院，是应急处理点，能止血包扎稳定伤情等救护车。"},
{id:1032,cat:"newsigns",type:"judgment",q:"2026年学校区域交通标志升级为「荧光黄绿底+注意儿童+限速30+减速丘预告」的复合标志系统。",opts:["正确","错误"],ans:0,exp:"2026年学校区域形成「四件套」安全系统：①荧光黄绿色底「注意儿童」警告标志（更醒目）；②限速30标志（学校区域全时段或上下学时段）；③路面「慢」字标记+减速丘（强制减速）；④彩色防滑路面（红色或绿色）。四重措施确保学生过街安全。",tip:"口诀：学校区=荧光绿标志+限速30+减速带+彩色路面。四重保障护孩子安全。看到荧光绿就想到孩子。"},
{id:1033,cat:"newsigns",type:"choice",q:"2026年新增的「高速公路智慧服务区」预告标志增加了什么信息？",opts:["只有名称","充电桩数量及占用状态实时显示、停车位余量、餐饮品牌等实时信息","只有距离","和以前一样"],ans:1,exp:"智慧服务区预告标志=传统「P+服务区名称+距离」基础上，增加LED副屏显示：充电桩空闲数量/总数量（新能源车主可决定是否在此充电）、停车位余量、有无餐饮/加油等信息。部分通过V2X直接发送到车机屏幕。2026年越来越多高速服务区进行智慧化改造。",tip:"口诀：智慧服务区标志=多了充电桩空闲数+车位余量。充电桩满没满提前知道，不用开进去发现没位置。"},
{id:1034,cat:"newsigns",type:"judgment",q:"可变导向车道（锯齿状标线车道）的行驶方向在任何时间都是固定的。",opts:["正确","错误"],ans:1,exp:"可变导向车道=车道内侧划有锯齿状（锯齿/拉链状）短标线，上方有LED可变箭头指示灯。行驶方向随时间段变化——早高峰可能是左转，晚高峰变成直行。进入前必须看清上方LED显示的当前允许方向。走错方向=违反导向=记分+罚款。",tip:"口诀：锯齿线+LED指示灯=可变车道。早上左转晚上直行。抬头看LED箭头再进，不看=走错=扣分。"},
{id:1035,cat:"newsigns",type:"choice",q:"「HOV车道」（多乘员车道）标志的特征是什么？",opts:["蓝底+单人图案","蓝底+菱形+「2+」字样（表示乘坐2人及以上的车辆可使用），地面标线为黄色虚线","普通车道标志","红底标志"],ans:1,exp:"HOV（High-Occupancy Vehicle）车道=多乘员专用车道，路面标线为黄色虚线，标志为蓝底菱形+「2+」或「3+」。车内乘坐人数达到规定数量（通常≥2人或≥3人）的车辆方可使用。单人驾驶车辆驶入将被电子抓拍处罚。2026年更多城市引入HOV车道以鼓励合乘出行。",tip:"口诀：蓝底菱形+2+=拼车道。车上≥2个人能走。一个人的车进去=违章。鼓励拼车，减少拥堵。"},
{id:1036,cat:"newsigns",type:"judgment",q:"2026年新增「智慧路灯」路侧标志，提示该路段路灯具备环境监测、5G基站、信息发布等多功能。",opts:["正确","错误"],ans:0,exp:"智慧路灯（多功能灯杆）=集成了照明、环境监测（空气质量/温湿度）、5G微基站、信息发布屏、视频监控、WiFi热点、充电桩（灯杆底部）等多功能。2026年在智慧城市示范路段设置提示标志，告知驾驶人该路段有智慧灯杆，可利用其服务。",tip:"口诀：智慧路灯=不是普通路灯。它装着5G/WiFi/监控/甚至充电桩。路灯也能充电上网了。"},
{id:1037,cat:"newsigns",type:"choice",q:"高速公路「雾区诱导标志」（2026新标准）的特征是什么？",opts:["普通的道路标志","黄色闪烁LED诱导灯+雾区预警标志组合——路侧连续设置黄色闪光灯，大雾时自动启动引导车辆","只有文字提示","只有声音提示"],ans:1,exp:"雾区诱导系统=路侧黄色LED诱导灯（间隔20-30米）+雾区入口前2km/1km/500m分级预警标志。大雾时诱导灯自动同步闪烁（向上游方向形成「光带」），引导驾驶人看清道路轮廓，防止偏离车道。部分系统还集成了能见度监测和可变限速功能。",tip:"口诀：雾区=路边一串黄闪灯。自动感应起雾→黄灯同步闪→形成一条光带→跟着光带走。雾里看花不如跟着黄灯。"},
{id:1038,cat:"newsigns",type:"judgment",q:"「结冰预警」标志（2026新增）配备路面温度传感器和LED警示灯，路面温度接近冰点时自动闪烁提醒。",opts:["正确","错误"],ans:0,exp:"结冰预警系统=路面温度传感器+「注意结冰」标志+LED警示灯。当路面温度降至设定的临界值（通常2-3°C）时，LED警示灯自动开始闪烁，提醒驾驶人路面可能结冰。常见于桥梁、隧道口、山区背阴路段等易结冰位置。",tip:"口诀：结冰预警=传感器测路温+温度低到2度=灯闪起来。看到黄灯在闪=路面可能结冰了，慢！"},
{id:1039,cat:"newsigns",type:"choice",q:"2026年新增的「非机动车友好路口」标志提示什么？",opts:["禁止非机动车","该路口设置了非机动车专用信号灯、二次过街设施和非机动车待行区，非机动车通行更安全","没有特别含义","非机动车需要下车推行"],ans:1,exp:"非机动车友好路口=设置了非机动车专用信号灯（小自行车图案灯）、非机动车二次过街等候区（左转非机动车需二次过街而非直接左转）、非机动车待行区等设施。标志提醒机动车驾驶人该路口非机动车通行量较大，注意观察和让行。",tip:"口诀：非机动车友好路口=电动车/自行车有专用信号灯和等车区。左转电动车要拐两次（先直行再左转）。机动车要格外注意。"},
{id:1040,cat:"newsigns",type:"judgment",q:"「数字孪生道路」标志（2026新增）表示该路段有完整的数字模型，可实时监控交通状况并预警。",opts:["正确","错误"],ans:0,exp:"数字孪生道路=现实道路在数字世界中有完整的三维实时映射模型，通过路侧传感器（雷达、摄像头、激光雷达）实时采集和更新数据。可用于实时交通监控、事故自动检测、虚拟仿真测试等。标志提醒驾驶人该路段交通管理高度数字化和智能化。",tip:"口诀：数字孪生=路在电脑里有个一模一样的「分身」。路上发生什么都实时映射，事故自动发现。名副其实的智慧路。"},
{id:1041,cat:"newsigns",type:"choice",q:"2026年「道路合流预警」标志的新特征是什么？",opts:["和以前一样","增加了LED警示灯和雷达检测功能——当检测到相邻车道有来车时，黄灯闪烁提醒注意合流车辆","只有静态标志","取消了"],ans:1,exp:"智能合流预警标志=传统合流警告三角标志+LED警示灯+雷达检测模块。当检测到匝道或相邻车道有来车即将合流时，黄灯自动闪烁提醒主线车辆注意让行或变道。主动式预警比静态标志效果更显著，降低合流区域的追尾和侧撞事故。",tip:"口诀：智能合流标志=雷达发现旁边有车要并进来→黄灯闪提醒你。主动告诉你「旁边有车」，不用自己找。"},
{id:1042,cat:"newsigns",type:"judgment",q:"2026年新标准将「公交专用道」标志增加了二维码，扫码可查看专用时段和允许通行车型等详细信息。",opts:["正确","错误"],ans:0,exp:"2026年部分城市公交专用道标志增加了二维码（通常位于标志右下角），扫描后可查看该路段公交专用道详细信息：专用时段、允许通行的其他车辆类型（如新能源车、多乘员车辆等是否有通行权）、节假日规则等。为驾驶人提供更精准的通行信息。",tip:"口诀：公交专用道标志有二维码=扫一扫看时段+哪些车能走。不确定能不能走？扫一下就知道。"},
{id:1043,cat:"newsigns",type:"choice",q:"2026年「应急车道动态管控」标志的功能是什么？",opts:["没有功能","根据交通状况动态开放或关闭应急车道——拥堵时可临时开放应急车道为行车道以增加通行能力，标志显示绿色箭头可通行、红色叉号禁止通行","只有禁止标志","装饰"],ans:1,exp:"应急车道动态管控（Hard Shoulder Running）=在交通拥堵高峰时段，通过LED标志动态开放应急车道作为临时行车道（标志显示绿色↓箭头），非拥堵时段恢复为应急车道（红色×）。驾驶人需严格按标志指示——绿色可走，红色不可走。误判将被抓拍处罚。",tip:"口诀：应急车道上有LED标志=绿色箭头能走、红色叉号不能走。动态管控——拥堵时临时开放加一条道。不看标志走错=违法。"},
{id:1044,cat:"newsigns",type:"judgment",q:"2026年新增的「听觉警示区」标志提示前方路段有听觉警示装置（如定向声波），提醒驾驶人注意听声辨位。",opts:["正确","错误"],ans:0,exp:"听觉警示区=在特定危险路段（如急弯、长下坡、事故多发点）设置定向声波警示装置，车辆经过时触发定向声音警报（不干扰其他方向）。标志提前提醒驾驶人该区域通过听觉辅助判断危险——「听到警报声=减速+更加注意」。视觉和听觉双通道提高警示效果。",tip:"口诀：听觉警示区=路会「叫」——你开过去触发定向声音提醒。听到声音=有危险，减速。用眼睛也用耳朵。"},
{id:1045,cat:"newsigns",type:"choice",q:"2026年新标准中「减速标线」的创新形式包括以下哪种？",opts:["只有横向减速标线","三维立体视觉减速标线（3D标线）、彩色防滑减速带、会「震动」的发声减速标线（通过路面纹理产生震动和声音）","只有纵向减速标线","只有热熔标线"],ans:1,exp:"2026年减速标线创新形式：①3D立体视觉减速标线（利用透视和色彩造成「隆起」错觉）；②彩色防滑路面减速带（红色/绿色，同时增加摩擦系数）；③发声减速标线（路面连续微凸起，车轮压过产生震动和「嗡嗡」声，听觉+触觉双重提醒）。多种技术组合多感官提醒驾驶人减速。",tip:"口诀：新减速标线=3D假隆起（视觉）+彩色防滑（触觉）+会嗡嗡响（听觉）。全方位告诉你——该减速了。不减速就让你不舒服。"}
);
